-- Elevate LMS Migrations — batch_3_june_2026.sql
-- 140 files — run in Supabase SQL Editor
-- All guards in place: IF NOT EXISTS, ON CONFLICT DO NOTHING

-- ── 20260601000001_get_user_by_email_rpc.sql ──
-- Efficient email lookup RPC used by getUserByEmail() in lib/supabase-admin.ts.
-- Replaces the previous auth.admin.listUsers() full-scan pattern.
-- SECURITY DEFINER so it can read profiles regardless of caller RLS context.

create or replace function public.get_user_id_by_email(user_email text)
returns table (id uuid, email text)
language sql
security definer
stable
as $$
  select id, email
  from public.profiles
  where lower(email) = lower(trim(user_email))
  limit 1;
$$;

-- Restrict execution to authenticated roles only
revoke all on function public.get_user_id_by_email(text) from public, anon;
grant execute on function public.get_user_id_by_email(text) to authenticated, service_role;

-- ── 20260601000002_interactive_video_quiz_answers.sql ──
-- Dedicated table for in-video quiz answers from InteractiveVideoPlayer.
-- Replaces the lesson_progress.metadata workaround.

create table if not exists public.interactive_video_quiz_answers (
  id            uuid primary key default gen_random_uuid(),
  user_id       uuid not null references auth.users(id) on delete cascade,
  lesson_id     uuid not null,
  question      text not null,
  selected_answer integer not null,
  correct_answer  integer not null,
  is_correct    boolean not null,
  timestamp_sec numeric,
  answered_at   timestamptz not null default now()
);

-- One row per user+lesson+question — upsert on re-attempt keeps latest answer
create unique index if not exists uq_video_quiz_answer
  on public.interactive_video_quiz_answers (user_id, lesson_id, question);

-- RLS: users can only read/write their own answers
alter table public.interactive_video_quiz_answers enable row level security;

create policy "users_own_video_quiz_answers"
  on public.interactive_video_quiz_answers
  for all
  using (auth.uid() = user_id)
  with check (auth.uid() = user_id);

-- Index for fast per-lesson lookups
create index if not exists idx_video_quiz_lesson
  on public.interactive_video_quiz_answers (lesson_id, user_id);

-- ── 20260601000003_get_impact_summary_rpc.sql ──
-- Aggregates impact metrics in SQL so schema truth stays in one place.
-- Called by /api/impact/summary instead of inline route queries.
-- SECURITY DEFINER — callable by authenticated + service_role only.

create or replace function public.get_impact_summary()
returns json
language sql
security definer
stable
as $$
  select json_build_object(
    'total_learners',
      (select count(*) from public.profiles where role in ('student', 'learner')),
    'active_enrollments',
      (select count(*) from public.program_enrollments where status = 'active'),
    'program_completions',
      (select count(*) from public.program_enrollments where completed_at is not null),
    'certificates_awarded',
      (select count(*) from public.certificates),
    'total_programs',
      (select count(*) from public.programs where published = true and status != 'archived'),
    'partners',
      (select count(*) from public.profiles where role = 'partner'),
    'total_hours',
      coalesce(
        (select sum(duration_minutes) / 60.0 from public.course_lessons),
        0
      )
  );
$$;

revoke all on function public.get_impact_summary() from public, anon;
grant execute on function public.get_impact_summary() to authenticated, service_role;

-- ── 20260601000004_lti_platforms_auth_login_url.sql ──
-- Add auth_login_url to lti_platforms.
-- Required by /api/lti/login to redirect to the platform's OIDC authorization endpoint.
-- Also adds jwks_uri if not already present (needed by /api/lti/launch for JWKS verification).

alter table public.lti_platforms
  add column if not exists auth_login_url text,
  add column if not exists jwks_uri        text;

comment on column public.lti_platforms.auth_login_url is
  'Platform OIDC authorization endpoint — e.g. https://canvas.example.com/api/lti/authorize_redirect';

comment on column public.lti_platforms.jwks_uri is
  'Platform JWKS endpoint for JWT signature verification — e.g. https://canvas.example.com/api/lti/security/jwks';

