-- ── 20260601000006_step_submissions_review_columns.sql ──
-- Add instructor review columns to step_submissions.
-- Required for the instructor sign-off UI on lab/assignment step types.

ALTER TABLE public.step_submissions
  ADD COLUMN IF NOT EXISTS reviewed_by     uuid        REFERENCES public.profiles(id) ON DELETE SET NULL,
  ADD COLUMN IF NOT EXISTS reviewed_at     timestamptz,
  ADD COLUMN IF NOT EXISTS instructor_status   text CHECK (instructor_status IN ('pending', 'approved', 'rejected')),
  ADD COLUMN IF NOT EXISTS instructor_feedback text;

-- Default existing rows to pending
UPDATE public.step_submissions
SET instructor_status = 'pending'
WHERE instructor_status IS NULL;

-- Index for instructor dashboard queries (all pending submissions)
CREATE INDEX IF NOT EXISTS idx_step_submissions_instructor_status
  ON public.step_submissions (instructor_status, created_at DESC);

-- Index for per-course instructor queries
CREATE INDEX IF NOT EXISTS idx_step_submissions_course_status
  ON public.step_submissions (course_id, instructor_status);

-- ── 20260602000001_curriculum_lessons_ojt_requirements.sql ──
-- Add OJT enforcement columns to curriculum_lessons.
-- These link a lab lesson to a specific apprentice_skills row and define
-- how many supervised repetitions are required before the lesson can be
-- marked complete.

ALTER TABLE public.curriculum_lessons
  ADD COLUMN IF NOT EXISTS required_skill_id      UUID REFERENCES public.apprentice_skills(id) ON DELETE SET NULL,
  ADD COLUMN IF NOT EXISTS required_reps           INTEGER NOT NULL DEFAULT 1,
  ADD COLUMN IF NOT EXISTS requires_verification   BOOLEAN NOT NULL DEFAULT TRUE;

COMMENT ON COLUMN public.curriculum_lessons.required_skill_id    IS 'apprentice_skills row that must be logged before this lab lesson can be completed';
COMMENT ON COLUMN public.curriculum_lessons.required_reps        IS 'Minimum number of competency_log entries (supervisor_verified=true if requires_verification) before completion is allowed';
COMMENT ON COLUMN public.curriculum_lessons.requires_verification IS 'If true, each rep must have supervisor_verified=true to count toward required_reps';

CREATE INDEX IF NOT EXISTS idx_curriculum_lessons_required_skill
  ON public.curriculum_lessons (required_skill_id)
  WHERE required_skill_id IS NOT NULL;

-- ── 20260602000002_barber_lab_lesson_skill_mapping.sql ──
-- Map barber apprenticeship lab lessons to their required apprentice_skills.
-- These are the 10 highest-impact hands-on lessons in the barber program.
-- required_reps and requires_verification enforce the OJT loop.
--
-- Skill IDs reference public.apprentice_skills seeded in 20260527000002.
-- Run after 20260602000001 (adds the columns).

DO $$
DECLARE
  v_course_id UUID;
BEGIN
  SELECT id INTO v_course_id
  FROM public.courses
  WHERE slug = 'barber-apprenticeship'
  LIMIT 1;

  IF v_course_id IS NULL THEN
    RAISE NOTICE 'barber-apprenticeship course not found — skipping skill mapping';
    RETURN;
  END IF;

  -- Sanitation and Safety → Disinfection procedure (WPS Area 5)
  UPDATE public.course_lessons SET
    lesson_type          = 'lab',
    required_skill_id    = (SELECT id FROM public.apprentice_skills WHERE name ILIKE '%disinfect%' AND program_id = (SELECT id FROM public.programs WHERE slug = 'barber-apprenticeship' LIMIT 1) LIMIT 1),
    required_reps        = 3,
    requires_verification = TRUE
  WHERE course_id = v_course_id AND slug = 'sanitation-and-safety';

  -- Basic Haircut Techniques → Basic haircut (WPS Area 1)
  UPDATE public.course_lessons SET
    lesson_type          = 'lab',
    required_skill_id    = (SELECT id FROM public.apprentice_skills WHERE name ILIKE '%basic haircut%' AND program_id = (SELECT id FROM public.programs WHERE slug = 'barber-apprenticeship' LIMIT 1) LIMIT 1),
    required_reps        = 5,
    requires_verification = TRUE
  WHERE course_id = v_course_id AND slug = 'basic-haircut-techniques';

  -- Fade and Taper Techniques → Fade cut (WPS Area 1)
  UPDATE public.course_lessons SET
    lesson_type          = 'lab',
    required_skill_id    = (SELECT id FROM public.apprentice_skills WHERE name ILIKE '%fade%' AND program_id = (SELECT id FROM public.programs WHERE slug = 'barber-apprenticeship' LIMIT 1) LIMIT 1),
    required_reps        = 5,
    requires_verification = TRUE
  WHERE course_id = v_course_id AND slug = 'fade-and-taper-techniques';

  -- Beard and Mustache Grooming → Beard trim (WPS Area 2)
  UPDATE public.course_lessons SET
    lesson_type          = 'lab',
    required_skill_id    = (SELECT id FROM public.apprentice_skills WHERE name ILIKE '%beard%' AND program_id = (SELECT id FROM public.programs WHERE slug = 'barber-apprenticeship' LIMIT 1) LIMIT 1),
    required_reps        = 3,
    requires_verification = TRUE
  WHERE course_id = v_course_id AND slug = 'beard-and-mustache-grooming';

  -- Shaving Techniques → Straight razor shave (WPS Area 2)
  UPDATE public.course_lessons SET
    lesson_type          = 'lab',
    required_skill_id    = (SELECT id FROM public.apprentice_skills WHERE name ILIKE '%razor%' OR name ILIKE '%shave%' AND program_id = (SELECT id FROM public.programs WHERE slug = 'barber-apprenticeship' LIMIT 1) LIMIT 1),
    required_reps        = 3,
    requires_verification = TRUE
  WHERE course_id = v_course_id AND slug = 'shaving-techniques';

  -- Client Consultation → Client consultation (WPS Area 6)
  UPDATE public.course_lessons SET
    lesson_type          = 'lab',
    required_skill_id    = (SELECT id FROM public.apprentice_skills WHERE name ILIKE '%consultation%' AND program_id = (SELECT id FROM public.programs WHERE slug = 'barber-apprenticeship' LIMIT 1) LIMIT 1),
    required_reps        = 5,
    requires_verification = TRUE
  WHERE course_id = v_course_id AND slug = 'client-consultation';

  -- Advanced Cutting Techniques → Advanced cut (WPS Area 1)
  UPDATE public.course_lessons SET
    lesson_type          = 'lab',
    required_skill_id    = (SELECT id FROM public.apprentice_skills WHERE name ILIKE '%advanced%cut%' AND program_id = (SELECT id FROM public.programs WHERE slug = 'barber-apprenticeship' LIMIT 1) LIMIT 1),
    required_reps        = 5,
    requires_verification = TRUE
  WHERE course_id = v_course_id AND slug = 'advanced-cutting-techniques';

  -- Razor Cutting → Razor cutting (WPS Area 1)
  UPDATE public.course_lessons SET
    lesson_type          = 'lab',
    required_skill_id    = (SELECT id FROM public.apprentice_skills WHERE name ILIKE '%razor cut%' AND program_id = (SELECT id FROM public.programs WHERE slug = 'barber-apprenticeship' LIMIT 1) LIMIT 1),
    required_reps        = 3,
    requires_verification = TRUE
  WHERE course_id = v_course_id AND slug = 'razor-cutting';

  -- Hair Coloring Basics → Color application (WPS Area 3)
  UPDATE public.course_lessons SET
    lesson_type          = 'lab',
    required_skill_id    = (SELECT id FROM public.apprentice_skills WHERE name ILIKE '%color%' AND program_id = (SELECT id FROM public.programs WHERE slug = 'barber-apprenticeship' LIMIT 1) LIMIT 1),
    required_reps        = 3,
    requires_verification = TRUE
  WHERE course_id = v_course_id AND slug = 'hair-coloring-basics';

  -- Scalp Treatments → Scalp treatment (WPS Area 4)
  UPDATE public.course_lessons SET
    lesson_type          = 'lab',
    required_skill_id    = (SELECT id FROM public.apprentice_skills WHERE name ILIKE '%scalp%' AND program_id = (SELECT id FROM public.programs WHERE slug = 'barber-apprenticeship' LIMIT 1) LIMIT 1),
    required_reps        = 3,
    requires_verification = TRUE
  WHERE course_id = v_course_id AND slug = 'scalp-treatments';

  RAISE NOTICE 'Barber lab lesson skill mapping complete';
END $$;

-- ── 20260602000003_forward_schema_reconciliation.sql ──
-- Forward schema reconciliation for 3 tables where live DB is missing columns
-- that app code actively references.
--
-- Determined by: live DB introspection + grep of .ts/.tsx column references.
-- See docs/schema-drift-decisions.md for full decision rationale.
--
-- All statements use ADD COLUMN IF NOT EXISTS — safe to run against live DB
-- where columns may already exist from manual dashboard edits.

-- ============================================================
-- page_sections
-- Live has: id, page_id, component, position, props, created_at, updated_at
-- lib/data/pages.ts reads: section_type, content, is_visible (newer shape)
-- lib/data/pages.ts writes: component, position, props (older shape)
-- Adding new columns additively — both shapes coexist until a cleanup migration
-- ============================================================

ALTER TABLE public.page_sections
  ADD COLUMN IF NOT EXISTS section_type TEXT NOT NULL DEFAULT 'content',
  ADD COLUMN IF NOT EXISTS content      JSONB NOT NULL DEFAULT '{}',
  ADD COLUMN IF NOT EXISTS is_visible   BOOLEAN NOT NULL DEFAULT true;

-- ============================================================
-- direct_messages
-- Live has: id, user_id, title, content, is_read, created_at, updated_at
-- MessagesClient.tsx expects: conversation_id, sender_id
-- ============================================================

ALTER TABLE public.direct_messages
  ADD COLUMN IF NOT EXISTS conversation_id UUID,
  ADD COLUMN IF NOT EXISTS sender_id       UUID;

-- ============================================================
-- credentials
-- Live has: id, partner_id, name, type, description, created_at, expires_at,
--           issued_at, revoked_at
-- App references: abbreviation, issuing_authority (via program_credentials join)
-- ============================================================

ALTER TABLE public.credentials
  ADD COLUMN IF NOT EXISTS abbreviation      TEXT,
  ADD COLUMN IF NOT EXISTS issuing_authority TEXT;

-- ============================================================
-- pages
-- Live has: id, path, title, description, section, is_published,
--           requires_auth, roles_allowed, created_at, updated_at
-- App references: slug (6 refs), status (4 refs)
-- Missing: slug, status, meta_title, meta_desc
-- ============================================================

ALTER TABLE public.pages
  ADD COLUMN IF NOT EXISTS slug        TEXT,
  ADD COLUMN IF NOT EXISTS status      TEXT NOT NULL DEFAULT 'published',
  ADD COLUMN IF NOT EXISTS meta_title  TEXT,
  ADD COLUMN IF NOT EXISTS meta_desc   TEXT;

-- Backfill slug from path for existing rows (path is the durable identifier)
UPDATE public.pages
SET slug = regexp_replace(
  regexp_replace(lower(trim(path)), '[^a-z0-9]+', '-', 'g'),
  '^-|-$', '', 'g'
)
WHERE slug IS NULL AND path IS NOT NULL;

-- Backfill status from is_published for existing rows
UPDATE public.pages
SET status = CASE WHEN is_published THEN 'published' ELSE 'draft' END
WHERE status = 'published' AND is_published IS NOT NULL;

CREATE UNIQUE INDEX IF NOT EXISTS pages_slug_unique ON public.pages (slug)
  WHERE slug IS NOT NULL;

-- ============================================================
-- placement_records
-- Live has: id, learner_id, program_id, case_manager_id, employer_name,
--           job_title, employment_type, hourly_wage, start_date, status,
--           verified_at, verified_by, verification_method, notes,
--           created_at, updated_at
-- App references: hire_date (5), employer_id (5), enrollment_id (2),
--                 annual_salary (1), verification_source (2)
-- Missing: hire_date, employer_id, enrollment_id, annual_salary,
--          verification_source
-- ============================================================

ALTER TABLE public.placement_records
  ADD COLUMN IF NOT EXISTS hire_date            DATE,
  ADD COLUMN IF NOT EXISTS employer_id          UUID,
  ADD COLUMN IF NOT EXISTS enrollment_id        UUID,
  ADD COLUMN IF NOT EXISTS annual_salary        NUMERIC,
  ADD COLUMN IF NOT EXISTS verification_source  TEXT,
  ADD COLUMN IF NOT EXISTS employed_q2          BOOLEAN DEFAULT false,
  ADD COLUMN IF NOT EXISTS employed_q4          BOOLEAN DEFAULT false,
  ADD COLUMN IF NOT EXISTS median_earnings_q2   NUMERIC,
  ADD COLUMN IF NOT EXISTS tenant_id            UUID;

-- Backfill hire_date from start_date where not set (same semantic for most records)
UPDATE public.placement_records
SET hire_date = start_date
WHERE hire_date IS NULL AND start_date IS NOT NULL;

-- Backfill verification_source from verification_method where not set
UPDATE public.placement_records
SET verification_source = verification_method
WHERE verification_source IS NULL AND verification_method IS NOT NULL;

-- ============================================================
-- program_modules
-- Live has: id, program_id, module_number, title, description,
--           lesson_count, duration_hours, sort_order, created_at, phase_id
-- App references: order_index (3 refs), is_published (2 refs)
-- Missing: order_index, is_published
-- ============================================================

ALTER TABLE public.program_modules
  ADD COLUMN IF NOT EXISTS order_index  INTEGER,
  ADD COLUMN IF NOT EXISTS is_published BOOLEAN NOT NULL DEFAULT true;

-- Backfill order_index from sort_order (same semantic)
UPDATE public.program_modules
SET order_index = sort_order
WHERE order_index IS NULL AND sort_order IS NOT NULL;

-- ── 20260602000004_messages_additive_columns.sql ──
-- messages: add columns from later definition without dropping existing ones.
--
-- Live has: id, sender_id, recipient_id, subject, body, read, read_at,
--           created_at, conversation_id, deleted_by, read_by
-- App references: read (12), conversation_id (6), read_by (5), deleted_by (4),
--                 is_read (3) — mixed usage of both old and new column names.
--
-- Strategy: add new columns additively. Do NOT drop read/conversation_id/
-- deleted_by/read_by — 12+ app references depend on them.
-- App code using is_read (3 refs) will work once the column exists.

ALTER TABLE public.messages
  ADD COLUMN IF NOT EXISTS is_read    BOOLEAN NOT NULL DEFAULT false,
  ADD COLUMN IF NOT EXISTS thread_id  UUID,
  ADD COLUMN IF NOT EXISTS parent_id  UUID,
  ADD COLUMN IF NOT EXISTS updated_at TIMESTAMPTZ DEFAULT now();

-- Backfill is_read from read for existing rows
UPDATE public.messages
SET is_read = COALESCE(read, false)
WHERE is_read = false AND read IS NOT NULL;

-- ── 20260602000005_direct_messages_canonical.sql ──
-- direct_messages: canonicalize sender identity column.
--
-- The table had both user_id (original) and sender_id (added during
-- schema reconciliation). All app code (MessagesClient.tsx) exclusively
-- uses sender_id for reads, writes, and mark-as-read operations.
-- user_id is never referenced in any app code path.
--
-- Action: backfill sender_id from user_id, then drop user_id.

UPDATE public.direct_messages
SET sender_id = user_id
WHERE sender_id IS NULL AND user_id IS NOT NULL;

ALTER TABLE public.direct_messages
  DROP COLUMN IF EXISTS user_id;

-- ── 20260602000006_page_sections_canonical.sql ──
-- page_sections: establish canonical schema.
--
-- The table was temporarily given three extra columns (section_type, content,
-- is_visible) during schema reconciliation. No code path ever wrote those
-- columns — all reads and writes use component/position/props exclusively.
-- This migration drops the three wrong columns and documents the canonical shape.
--
-- Canonical shape:
--   id          uuid PRIMARY KEY DEFAULT gen_random_uuid()
--   page_id     uuid (FK to pages.id)
--   component   text NOT NULL
--   position    integer NOT NULL DEFAULT 0
--   props       jsonb NOT NULL DEFAULT '{}'
--   created_at  timestamptz DEFAULT now()
--   updated_at  timestamptz DEFAULT now()

ALTER TABLE public.page_sections
  DROP COLUMN IF EXISTS section_type,
  DROP COLUMN IF EXISTS content,
  DROP COLUMN IF EXISTS is_visible;

-- ── 20260602000007_fix_rls_and_conversations.sql ──
-- Three fixes identified during RLS policy alignment audit:
--
-- 1. direct_message_conversations: live table has columns 'add' and
--    'elevateforhumanity' from a malformed migration. App expects
--    participant_1_id, participant_2_id, last_message_at, last_message_preview.
--    Drop the garbage columns, add the real ones.
--
-- 2. provider_onboarding_steps: policy only allowed admin writes, but
--    provider/settings and provider/programs/create routes use createClient()
--    (user-scoped) to UPDATE steps for their own tenant. Add tenant-scoped
--    UPDATE policy for provider_admin role.
--
-- 3. provider_program_approvals: policy only allowed admin writes, but
--    provider/programs/create and provider/programs/submit routes use
--    createClient() to INSERT approval records for their own tenant. Add
--    tenant-scoped INSERT policy for provider_admin role.
--
-- 4. direct_messages: RLS was never enabled. Any authenticated user could
--    read all messages. Enable RLS and add sender/conversation-participant
--    scoped policies.

-- ─── 1. direct_message_conversations schema fix ──────────────────────────────

ALTER TABLE public.direct_message_conversations
  DROP COLUMN IF EXISTS add,
  DROP COLUMN IF EXISTS elevateforhumanity,
  ADD COLUMN IF NOT EXISTS participant_1_id uuid,
  ADD COLUMN IF NOT EXISTS participant_2_id uuid,
  ADD COLUMN IF NOT EXISTS last_message_at timestamptz,
  ADD COLUMN IF NOT EXISTS last_message_preview text;

-- ─── 2. provider_onboarding_steps: add tenant-scoped UPDATE ──────────────────
--
-- provider/settings and provider/programs/create call:
--   supabase.from('provider_onboarding_steps')
--     .update({ completed: true, ... })
--     .eq('tenant_id', tenantId)
--     .eq('step', '...')
-- using createClient() (user JWT, not service role).
-- The existing policy only allows admin INSERT/UPDATE/DELETE, so these
-- writes were silently failing (RLS blocks, no error surfaced to UI).

DROP POLICY IF EXISTS "provider_onboarding_steps_tenant_update" ON public.provider_onboarding_steps;
DO $$ BEGIN CREATE POLICY "provider_onboarding_steps_tenant_update" ON public.provider_onboarding_steps
  FOR UPDATE
  USING (tenant_id = public.my_tenant_id()); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- ─── 3. provider_program_approvals: add tenant-scoped INSERT ─────────────────
--
-- provider/programs/create inserts an approval record via createClient():
--   supabase.from('provider_program_approvals').insert({ tenant_id, ... })
-- provider/programs/submit also inserts via createClient() after auth check.
-- Both were blocked by the admin-only INSERT policy.

DROP POLICY IF EXISTS "provider_program_approvals_tenant_insert" ON public.provider_program_approvals;
DO $$ BEGIN CREATE POLICY "provider_program_approvals_tenant_insert" ON public.provider_program_approvals
  FOR INSERT
  WITH CHECK (tenant_id = public.my_tenant_id()); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- ─── 4. direct_messages: enable RLS + add policies ───────────────────────────
--
-- Access model:
--   - A user can read messages in conversations they participate in.
--     Scoped via direct_message_conversations.participant_1_id / participant_2_id.
--   - A user can insert messages into conversations they participate in,
--     and only as themselves (sender_id = auth.uid()).
--   - A user can update their own messages (e.g. mark-as-read updates
--     issued by the recipient are scoped to neq sender_id, so the UPDATE
--     policy must allow the conversation participant, not just the sender).
--   - Admin can read/write all.

ALTER TABLE public.direct_messages ENABLE ROW LEVEL SECURITY;

-- Helper: returns true if the caller is a participant in the given conversation.
CREATE OR REPLACE FUNCTION public.is_conversation_participant(p_conversation_id uuid)
RETURNS boolean
LANGUAGE sql
STABLE
SECURITY DEFINER
AS $$
  SELECT EXISTS (
    SELECT 1 FROM public.direct_message_conversations
    WHERE id = p_conversation_id
      AND (participant_1_id = auth.uid() OR participant_2_id = auth.uid())
  )
$$;

DROP POLICY IF EXISTS "direct_messages_participant_read" ON public.direct_messages;
DO $$ BEGIN CREATE POLICY "direct_messages_participant_read" ON public.direct_messages
  FOR SELECT
  USING (
    public.is_conversation_participant(conversation_id)
    OR public.is_admin_role()
  ); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- Sender inserts their own messages into conversations they belong to.
DROP POLICY IF EXISTS "direct_messages_sender_insert" ON public.direct_messages;
DO $$ BEGIN CREATE POLICY "direct_messages_sender_insert" ON public.direct_messages
  FOR INSERT
  WITH CHECK (
    sender_id = auth.uid()
    AND public.is_conversation_participant(conversation_id)
  ); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- Mark-as-read: MessagesClient updates is_read=true for messages in a
-- conversation where sender_id != current user (i.e. the recipient marks
-- the other person's messages as read). Policy must allow any participant
-- to update, not just the sender.
DROP POLICY IF EXISTS "direct_messages_participant_update" ON public.direct_messages;
DO $$ BEGIN CREATE POLICY "direct_messages_participant_update" ON public.direct_messages
  FOR UPDATE
  USING (
    public.is_conversation_participant(conversation_id)
    OR public.is_admin_role()
  ); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DROP POLICY IF EXISTS "direct_messages_admin_delete" ON public.direct_messages;
DO $$ BEGIN CREATE POLICY "direct_messages_admin_delete" ON public.direct_messages
  FOR DELETE
  USING (public.is_admin_role()); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- ─── direct_message_conversations: enable RLS ────────────────────────────────

ALTER TABLE public.direct_message_conversations ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "direct_message_conversations_participant_read" ON public.direct_message_conversations;
DO $$ BEGIN CREATE POLICY "direct_message_conversations_participant_read" ON public.direct_message_conversations
  FOR SELECT
  USING (
    participant_1_id = auth.uid()
    OR participant_2_id = auth.uid()
    OR public.is_admin_role()
  ); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- Either participant can update (last_message_at / last_message_preview
-- is written by the sender after inserting a message).
DROP POLICY IF EXISTS "direct_message_conversations_participant_update" ON public.direct_message_conversations;
DO $$ BEGIN CREATE POLICY "direct_message_conversations_participant_update" ON public.direct_message_conversations
  FOR UPDATE
  USING (
    participant_1_id = auth.uid()
    OR participant_2_id = auth.uid()
    OR public.is_admin_role()
  ); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- Only admin creates conversations (or a future "start conversation" API).
DROP POLICY IF EXISTS "direct_message_conversations_admin_insert" ON public.direct_message_conversations;
DO $$ BEGIN CREATE POLICY "direct_message_conversations_admin_insert" ON public.direct_message_conversations
  FOR INSERT
  WITH CHECK (public.is_admin_role()); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DROP POLICY IF EXISTS "direct_message_conversations_admin_delete" ON public.direct_message_conversations;
DO $$ BEGIN CREATE POLICY "direct_message_conversations_admin_delete" ON public.direct_message_conversations
  FOR DELETE
  USING (public.is_admin_role()); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- ── 20260602000008_rls_forms_webinars_provider.sql ──
-- RLS policies for forms, form_submissions, webinars, webinar_registrations,
-- and provider_* tables. These tables existed without policies, causing
-- authenticated non-service-role reads to return empty results.
--
-- Access model:
--   forms                      — public read; admin write
--   form_submissions           — anon insert (unauthenticated form posts); admin read
--   webinars                   — public read (is_public rows); admin write
--   webinar_registrations      — user owns their row; admin read all
--   provider_applications      — anon insert (public apply form); owner read own; admin manage
--   provider_compliance_artifacts — provider_admin reads/writes own tenant; admin read all
--   provider_onboarding_steps  — provider_admin reads own tenant; admin read all
--   provider_program_approvals — provider_admin reads own tenant; admin read all

-- ─── helpers ────────────────────────────────────────────────────────────────

-- Returns true when the caller's profile role is one of the admin tiers.
-- Used in USING / WITH CHECK clauses below.
CREATE OR REPLACE FUNCTION public.is_admin_role()
RETURNS boolean
LANGUAGE sql
STABLE
SECURITY DEFINER
AS $$
  SELECT EXISTS (
    SELECT 1 FROM public.profiles
    WHERE id = auth.uid()
      AND role IN ('admin', 'super_admin', 'staff')
  )
$$;

-- Returns the tenant_id from the caller's profile.
CREATE OR REPLACE FUNCTION public.my_tenant_id()
RETURNS uuid
LANGUAGE sql
STABLE
SECURITY DEFINER
AS $$
  SELECT tenant_id FROM public.profiles WHERE id = auth.uid()
$$;

-- ─── forms ──────────────────────────────────────────────────────────────────

ALTER TABLE public.forms ENABLE ROW LEVEL SECURITY;

-- Anyone (including anon) can look up a form by id — needed for the submit route
-- which verifies the form exists before inserting a submission.
DROP POLICY IF EXISTS "forms_public_read" ON public.forms;
DO $$ BEGIN CREATE POLICY "forms_public_read" ON public.forms
  FOR SELECT
  USING (true); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DROP POLICY IF EXISTS "forms_admin_insert" ON public.forms;
DO $$ BEGIN CREATE POLICY "forms_admin_insert" ON public.forms
  FOR INSERT
  WITH CHECK (public.is_admin_role()); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DROP POLICY IF EXISTS "forms_admin_update" ON public.forms;
DO $$ BEGIN CREATE POLICY "forms_admin_update" ON public.forms
  FOR UPDATE
  USING (public.is_admin_role()); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DROP POLICY IF EXISTS "forms_admin_delete" ON public.forms;
DO $$ BEGIN CREATE POLICY "forms_admin_delete" ON public.forms
  FOR DELETE
  USING (public.is_admin_role()); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- ─── form_submissions ───────────────────────────────────────────────────────

ALTER TABLE public.form_submissions ENABLE ROW LEVEL SECURITY;

-- The /api/forms/submit route uses createClient() without requiring auth,
-- so submissions must be insertable by anon callers.
DROP POLICY IF EXISTS "form_submissions_anon_insert" ON public.form_submissions;
DO $$ BEGIN CREATE POLICY "form_submissions_anon_insert" ON public.form_submissions
  FOR INSERT
  WITH CHECK (true); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- Authenticated users can read their own submissions (user_id may be null for anon).
DROP POLICY IF EXISTS "form_submissions_owner_read" ON public.form_submissions;
DO $$ BEGIN CREATE POLICY "form_submissions_owner_read" ON public.form_submissions
  FOR SELECT
  USING (
    user_id = auth.uid()
    OR public.is_admin_role()
  ); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DROP POLICY IF EXISTS "form_submissions_admin_delete" ON public.form_submissions;
DO $$ BEGIN CREATE POLICY "form_submissions_admin_delete" ON public.form_submissions
  FOR DELETE
  USING (public.is_admin_role()); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- ─── webinars ───────────────────────────────────────────────────────────────

ALTER TABLE public.webinars ENABLE ROW LEVEL SECURITY;

-- Public page reads only is_public=true rows; the policy mirrors that filter
-- so even a direct query without the filter returns only public rows for anon.
DROP POLICY IF EXISTS "webinars_public_read" ON public.webinars;
DO $$ BEGIN CREATE POLICY "webinars_public_read" ON public.webinars
  FOR SELECT
  USING (is_public = true OR public.is_admin_role()); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DROP POLICY IF EXISTS "webinars_admin_insert" ON public.webinars;
DO $$ BEGIN CREATE POLICY "webinars_admin_insert" ON public.webinars
  FOR INSERT
  WITH CHECK (public.is_admin_role()); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DROP POLICY IF EXISTS "webinars_admin_update" ON public.webinars;
DO $$ BEGIN CREATE POLICY "webinars_admin_update" ON public.webinars
  FOR UPDATE
  USING (public.is_admin_role()); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DROP POLICY IF EXISTS "webinars_admin_delete" ON public.webinars;
DO $$ BEGIN CREATE POLICY "webinars_admin_delete" ON public.webinars
  FOR DELETE
  USING (public.is_admin_role()); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- ─── webinar_registrations ──────────────────────────────────────────────────

ALTER TABLE public.webinar_registrations ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "webinar_registrations_owner_read" ON public.webinar_registrations;
DO $$ BEGIN CREATE POLICY "webinar_registrations_owner_read" ON public.webinar_registrations
  FOR SELECT
  USING (user_id = auth.uid() OR public.is_admin_role()); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DROP POLICY IF EXISTS "webinar_registrations_owner_insert" ON public.webinar_registrations;
DO $$ BEGIN CREATE POLICY "webinar_registrations_owner_insert" ON public.webinar_registrations
  FOR INSERT
  WITH CHECK (user_id = auth.uid() OR public.is_admin_role()); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DROP POLICY IF EXISTS "webinar_registrations_owner_update" ON public.webinar_registrations;
DO $$ BEGIN CREATE POLICY "webinar_registrations_owner_update" ON public.webinar_registrations
  FOR UPDATE
  USING (user_id = auth.uid() OR public.is_admin_role()); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DROP POLICY IF EXISTS "webinar_registrations_admin_delete" ON public.webinar_registrations;
DO $$ BEGIN CREATE POLICY "webinar_registrations_admin_delete" ON public.webinar_registrations
  FOR DELETE
  USING (public.is_admin_role()); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- ─── provider_applications ──────────────────────────────────────────────────

ALTER TABLE public.provider_applications ENABLE ROW LEVEL SECURITY;

-- Public apply form: anon insert allowed (no auth required to submit an application).
DROP POLICY IF EXISTS "provider_applications_anon_insert" ON public.provider_applications;
DO $$ BEGIN CREATE POLICY "provider_applications_anon_insert" ON public.provider_applications
  FOR INSERT
  WITH CHECK (true); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- Applicant can read their own application by matching contact_email.
-- Admin can read all.
DROP POLICY IF EXISTS "provider_applications_read" ON public.provider_applications;
DO $$ BEGIN CREATE POLICY "provider_applications_read" ON public.provider_applications
  FOR SELECT
  USING (
    public.is_admin_role()
    OR (
      auth.uid() IS NOT NULL
      AND contact_email = (
        SELECT email FROM auth.users WHERE id = auth.uid()
      )
    )
  ); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DROP POLICY IF EXISTS "provider_applications_admin_update" ON public.provider_applications;
DO $$ BEGIN CREATE POLICY "provider_applications_admin_update" ON public.provider_applications
  FOR UPDATE
  USING (public.is_admin_role()); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DROP POLICY IF EXISTS "provider_applications_admin_delete" ON public.provider_applications;
DO $$ BEGIN CREATE POLICY "provider_applications_admin_delete" ON public.provider_applications
  FOR DELETE
  USING (public.is_admin_role()); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- ─── provider_compliance_artifacts ──────────────────────────────────────────

ALTER TABLE public.provider_compliance_artifacts ENABLE ROW LEVEL SECURITY;

-- provider_admin reads/writes rows belonging to their own tenant.
-- Admin reads all.
DROP POLICY IF EXISTS "provider_compliance_artifacts_tenant_read" ON public.provider_compliance_artifacts;
DO $$ BEGIN CREATE POLICY "provider_compliance_artifacts_tenant_read" ON public.provider_compliance_artifacts
  FOR SELECT
  USING (
    tenant_id = public.my_tenant_id()
    OR public.is_admin_role()
  ); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

