  status          text NOT NULL DEFAULT 'pending' CHECK (status IN ('pending','in_progress','completed','cancelled')),
  notes           text,
  outcome         text,
  assigned_to     uuid REFERENCES public.profiles(id),
  due_at          timestamptz,
  completed_at    timestamptz,
