-- ── 20260611000001_harden_api_keys_rls.sql ──
-- =============================================================================
-- Harden api_keys RLS
-- Migration: 20260611000001_harden_api_keys_rls.sql
--
-- Problem: 20260124200000_admin_tables_v2.sql created:
--   DROP POLICY IF EXISTS "Admin full access to api_keys" ON api_keys;
DO $$ BEGIN CREATE POLICY "Admin full access to api_keys" ON api_keys FOR ALL USING (true); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
-- This allows ANY authenticated user to read, write, and delete all API keys.
--
-- Fix: Replace with service_role-only access + admin-role SELECT.
-- API keys must never be readable by end users or non-admin staff.
-- =============================================================================

ALTER TABLE public.api_keys ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.api_keys FORCE ROW LEVEL SECURITY;

-- Drop the permissive catch-all policy
DROP POLICY IF EXISTS "Admin full access to api_keys" ON public.api_keys;

-- Service role: full access (server-side key management)
DROP POLICY IF EXISTS "api_keys_service_role" ON public.api_keys;
DO $$ BEGIN CREATE POLICY "api_keys_service_role" ON public.api_keys
  FOR ALL
  TO service_role
  USING (true)
  WITH CHECK (true); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- Admins and super_admins: read-only (for the admin dashboard key list)
DROP POLICY IF EXISTS "api_keys_admin_select" ON public.api_keys;
DO $$ BEGIN CREATE POLICY "api_keys_admin_select" ON public.api_keys
  FOR SELECT
  TO authenticated
  USING (
    EXISTS (
      SELECT 1 FROM public.profiles
      WHERE profiles.id = auth.uid()
        AND profiles.role IN ('admin', 'super_admin')
    )
  ); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- All other roles (authenticated, anon): no access — denied by default via RLS.

-- ── 20260612000001_exam_bookings_addon_calendly.sql ──
-- Add add-on purchase tracking and Calendly scheduling link to exam_bookings.
--
-- add_on:                  whether the Certification Success Package was purchased
-- add_on_paid:             payment confirmed for the add-on
-- calendly_scheduling_url: single-use Calendly link issued after payment
--
-- Apply in Supabase Dashboard → SQL Editor.

ALTER TABLE public.exam_bookings
  ADD COLUMN IF NOT EXISTS add_on                  boolean NOT NULL DEFAULT false,
  ADD COLUMN IF NOT EXISTS add_on_paid             boolean NOT NULL DEFAULT false,
  ADD COLUMN IF NOT EXISTS calendly_scheduling_url text;

-- ── 20260613000001_nha_training_programs.sql ──
-- Add NHA training partner programs to the programs table.
--
-- These are training + certification bundle programs sold through the NHA
-- training partner agreement. Separate from the testing center (exam proctoring).
--
-- Pricing comes from lib/testing/nha-pricing.ts at runtime — the total_cost
-- column here is the retail bundle price in dollars for Stripe checkout.
-- Update it when nha-pricing.ts changes.
--
-- Apply in Supabase Dashboard → SQL Editor.

INSERT INTO public.programs (
  slug,
  title,
  description,
  category,
  duration_weeks,
  total_cost,
  published,
  is_active,
