-- ── 20260615000001_applications_transfer_hours.sql ──
-- Transfer hour structured columns on applications
--
-- Replaces the previous pattern of burying transfer hours in support_notes free text.
--
-- transfer_hours_claimed  — student-reported at intake (unverified, always present for new rows)
-- transfer_hours_verified — staff-confirmed after document review (null until verified)
-- transfer_hours_verified_by — auth.users.id of the staff member who verified
-- transfer_hours_verified_at — timestamp of verification
--
-- PRICING POLICY (do not change without updating all checkout routes):
--   Transfer hours are progress credit only. They reduce program duration, NOT tuition.
--   Tuition is fixed at $4,980 regardless of transfer_hours_claimed or transfer_hours_verified.
--   These columns exist for auditability, staff review, scheduling, and dispute evidence only.

ALTER TABLE public.applications
  ADD COLUMN IF NOT EXISTS transfer_hours_claimed   integer DEFAULT 0 CHECK (transfer_hours_claimed >= 0),
  ADD COLUMN IF NOT EXISTS transfer_hours_verified  integer DEFAULT NULL CHECK (transfer_hours_verified >= 0),
  ADD COLUMN IF NOT EXISTS transfer_hours_verified_by uuid DEFAULT NULL REFERENCES auth.users(id) ON DELETE SET NULL,
  ADD COLUMN IF NOT EXISTS transfer_hours_verified_at timestamptz DEFAULT NULL;

-- Backfill: parse "Transfer Hours (claimed): N" from support_notes for existing rows.
-- Only updates rows where the pattern is unambiguous and transfer_hours_claimed is still 0.
-- Rows without this pattern are left untouched (legacy rows remain as-is).
UPDATE public.applications
SET transfer_hours_claimed = (
  substring(support_notes FROM 'Transfer Hours \(claimed\): (\d+)')
)::integer
WHERE support_notes ~ 'Transfer Hours \(claimed\): \d+'
  AND (transfer_hours_claimed IS NULL OR transfer_hours_claimed = 0);

-- Index: staff review queue — find applications with claimed but unverified hours
CREATE INDEX IF NOT EXISTS idx_applications_transfer_hours_pending
  ON public.applications (transfer_hours_claimed, transfer_hours_verified)
  WHERE transfer_hours_claimed > 0 AND transfer_hours_verified IS NULL;

COMMENT ON COLUMN public.applications.transfer_hours_claimed
  IS 'Hours reported by student at intake — unverified. Does not affect tuition.';
COMMENT ON COLUMN public.applications.transfer_hours_verified
  IS 'Hours confirmed by staff after document review. Authoritative for scheduling only. Does not affect tuition.';
COMMENT ON COLUMN public.applications.transfer_hours_verified_by
  IS 'Staff user who verified the transfer hours claim.';
COMMENT ON COLUMN public.applications.transfer_hours_verified_at
  IS 'Timestamp when transfer hours were verified by staff.';

-- ── 20260616000001_backfill_barber_lesson_videos.sql ──
-- Backfill video_url and video_config.videoFile on barber course_lessons rows
-- that were seeded before blueprint videoFile entries were added.
--
-- Blueprint videoFile mapping (42 lessons → 14 distinct shared videos):
--   Lessons without a per-lesson MP4 (6–49) get the thematically closest shared video.
--   Lessons 1–5 already have per-lesson MP4s; this sets video_url as a belt-and-suspenders
--   fallback for any rows that were seeded without it.

DO $$
DECLARE
  barber_course_id uuid := '3fb5ce19-1cde-434c-a8c6-f138d7d7aa17';

  -- slug → videoFile mapping from blueprint
  mapping jsonb := '{
    "barber-lesson-1":  "/videos/barber-lessons/barber-apprenticeship-intro.mp4",
    "barber-lesson-2":  "/videos/course-barber-sanitation-narrated.mp4",
    "barber-lesson-3":  "/videos/course-barber-sanitation.mp4",
    "barber-lesson-4":  "/videos/course-barber-sanitation-narrated.mp4",
    "barber-lesson-5":  "/videos/course-barber-sanitation-narrated.mp4",
    "barber-lesson-6":  "/videos/course-barber-sanitation-narrated.mp4",
    "barber-lesson-8":  "/videos/course-barber-consultation-narrated.mp4",
    "barber-lesson-9":  "/videos/course-barber-consultation-narrated.mp4",
    "barber-lesson-10": "/videos/course-barber-consultation-narrated.mp4",
    "barber-lesson-11": "/videos/course-barber-shampoo-narrated.mp4",
    "barber-lesson-12": "/videos/course-barber-consultation-narrated.mp4",
    "barber-lesson-13": "/videos/course-barber-shampoo-narrated.mp4",
    "barber-lesson-15": "/videos/course-barber-clipper-techniques.mp4",
    "barber-lesson-16": "/videos/course-barber-scissors-narrated.mp4",
    "barber-lesson-17": "/videos/course-barber-razor-narrated.mp4",
    "barber-lesson-18": "/videos/course-barber-clipper-techniques.mp4",
    "barber-lesson-19": "/videos/barber-client-experience.mp4",
    "barber-lesson-20": "/videos/course-barber-consultation.mp4",
    "barber-lesson-22": "/videos/course-barber-fade-narrated.mp4",
    "barber-lesson-23": "/videos/course-barber-fade-narrated.mp4",
    "barber-lesson-24": "/videos/course-barber-clipper-techniques.mp4",
    "barber-lesson-25": "/videos/course-barber-scissors.mp4",
    "barber-lesson-26": "/videos/course-barber-lineup-narrated.mp4",
    "barber-lesson-27": "/videos/course-barber-scissors-narrated.mp4",
    "barber-lesson-29": "/videos/course-barber-razor-narrated.mp4",
    "barber-lesson-30": "/videos/course-barber-razor-narrated.mp4",
    "barber-lesson-31": "/videos/course-barber-beard-narrated.mp4",
    "barber-lesson-32": "/videos/course-barber-beard-narrated.mp4",
    "barber-lesson-33": "/videos/course-barber-beard.mp4",
    "barber-lesson-35": "/videos/course-barber-styling-narrated.mp4",
    "barber-lesson-36": "/videos/course-barber-sanitation-narrated.mp4",
    "barber-lesson-37": "/videos/course-barber-styling-narrated.mp4",
    "barber-lesson-38": "/videos/course-barber-shampoo-narrated.mp4",
    "barber-lesson-40": "/videos/course-barber-consultation.mp4",
    "barber-lesson-41": "/videos/barber-shop-culture.mp4",
    "barber-lesson-42": "/videos/barber-shop-culture.mp4",
    "barber-lesson-43": "/videos/barber-client-experience.mp4",
    "barber-lesson-44": "/videos/course-barber-styling-narrated.mp4",
    "barber-lesson-46": "/videos/barber-lessons/barber-apprenticeship-intro.mp4",
    "barber-lesson-47": "/videos/course-barber-sanitation-narrated.mp4",
    "barber-lesson-48": "/videos/course-barber-fade-narrated.mp4",
    "barber-lesson-49": "/videos/course-barber-scissors-narrated.mp4"
  }';

  rec record;
  video_file text;
BEGIN
  FOR rec IN
    SELECT id, slug, video_url, video_config
    FROM course_lessons
    WHERE course_id = barber_course_id
  LOOP
    video_file := mapping ->> rec.slug;
    CONTINUE WHEN video_file IS NULL;

    UPDATE course_lessons
    SET
      -- Only set video_url if not already populated
      video_url    = COALESCE(NULLIF(rec.video_url, ''), video_file),
      -- Always write videoFile into video_config for runtime fallback
      video_config = COALESCE(rec.video_config, '{}'::jsonb) || jsonb_build_object('videoFile', video_file),
      updated_at   = now()
    WHERE id = rec.id;
  END LOOP;
END $$;

-- ── 20260616000002_program_enrollments_voucher_timestamps.sql ──
-- Voucher payment tracking timestamps for program_enrollments.
-- These three fields are required to enforce the MOU payment clause:
-- payout triggers on voucher_paid_date, not enrollment or completion.
ALTER TABLE public.program_enrollments
  ADD COLUMN IF NOT EXISTS student_start_date   TIMESTAMPTZ,
  ADD COLUMN IF NOT EXISTS voucher_issued_date   TIMESTAMPTZ,
  ADD COLUMN IF NOT EXISTS voucher_paid_date     TIMESTAMPTZ;

COMMENT ON COLUMN public.program_enrollments.student_start_date  IS 'Date student attended and participated beyond initial enrollment — triggers voucher invoicing';
COMMENT ON COLUMN public.program_enrollments.voucher_issued_date IS 'Date WorkOne or funding agency issued the voucher';
COMMENT ON COLUMN public.program_enrollments.voucher_paid_date   IS 'Date Elevate received funds from the voucher — triggers 10-day payout clock to program holder';

-- ── 20260616000003_enrollment_payout_enforcement.sql ──
-- Payout enforcement layer for program_enrollments.
-- Implements the MOU Section 4 operational controls:
--   - payout_due_date auto-calculated as voucher_paid_date + 14 calendar days (≈10 business days)
--   - payout_status machine-managed: not_triggered → pending → due/overdue → paid
--   - voucher_paid_date blocked unless voucher_issued_date exists (DB-enforced)
--   - Full audit trail in enrollment_voucher_audit

ALTER TABLE public.program_enrollments
  ADD COLUMN IF NOT EXISTS payout_status    TEXT NOT NULL DEFAULT 'not_triggered'
    CHECK (payout_status IN ('not_triggered','pending','due','overdue','paid')),
  ADD COLUMN IF NOT EXISTS payout_due_date  TIMESTAMPTZ,
  ADD COLUMN IF NOT EXISTS payout_paid_date TIMESTAMPTZ,
  ADD COLUMN IF NOT EXISTS payout_paid_by   UUID REFERENCES auth.users(id),
  ADD COLUMN IF NOT EXISTS payout_notes     TEXT;

-- Audit log: one row per field change, who changed it, when
CREATE TABLE IF NOT EXISTS public.enrollment_voucher_audit (
  id            UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  enrollment_id UUID        NOT NULL REFERENCES public.program_enrollments(id) ON DELETE CASCADE,
  changed_by    UUID        NOT NULL REFERENCES auth.users(id),
  changed_at    TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  field_name    TEXT        NOT NULL,
  old_value     TEXT,
  new_value     TEXT,
  note          TEXT
);

CREATE INDEX IF NOT EXISTS idx_enrollment_voucher_audit_enrollment
  ON public.enrollment_voucher_audit(enrollment_id);
CREATE INDEX IF NOT EXISTS idx_enrollment_voucher_audit_changed_at
  ON public.enrollment_voucher_audit(changed_at DESC);

-- Trigger: auto-set payout_due_date and payout_status when voucher_paid_date is entered.
-- Blocks voucher_paid_date if voucher_issued_date is missing.
CREATE OR REPLACE FUNCTION public.fn_enrollment_voucher_payout()
RETURNS TRIGGER LANGUAGE plpgsql AS $$
BEGIN
  IF NEW.voucher_paid_date IS NOT NULL AND OLD.voucher_paid_date IS NULL THEN
    IF NEW.voucher_issued_date IS NULL THEN
      RAISE EXCEPTION 'voucher_issued_date must be set before voucher_paid_date';
    END IF;
    NEW.payout_due_date := NEW.voucher_paid_date + INTERVAL '14 days';
    NEW.payout_status   := 'pending';
  END IF;
  IF NEW.payout_paid_date IS NOT NULL AND OLD.payout_paid_date IS NULL THEN
    NEW.payout_status := 'paid';
  END IF;
  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS trg_enrollment_voucher_payout ON public.program_enrollments;
CREATE TRIGGER trg_enrollment_voucher_payout
  BEFORE UPDATE ON public.program_enrollments
  FOR EACH ROW EXECUTE FUNCTION public.fn_enrollment_voucher_payout();

-- ── 20260616000004_cosmetology_hours_2000.sql ──
-- Correct cosmetology apprenticeship hours from 1500 to 2000.
-- Indiana DOL Registered Apprenticeship requires 2,000 hours, same as barber.
-- Previous migrations used the cosmetology school track number (1,500) in error.

-- Update programs table
UPDATE public.programs
SET
  total_hours = 2000,
  description = REPLACE(description, '1,500 hours', '2,000 hours')
WHERE slug = 'cosmetology-apprenticeship';

-- completion_requirements does not exist in the live schema — skipped.

-- Update training_courses (column is duration_hours, not total_hours)
UPDATE public.training_courses
SET duration_hours = 2000
WHERE program_id = (SELECT id FROM public.programs WHERE slug = 'cosmetology-apprenticeship')
  AND duration_hours = 1500;

-- ── 20260616000005_program_holders_mou_columns.sql ──
-- Add missing MOU signing columns to program_holders
ALTER TABLE public.program_holders
  ADD COLUMN IF NOT EXISTS mou_holder_name        TEXT,
  ADD COLUMN IF NOT EXISTS mou_holder_signed_at   TIMESTAMPTZ,
  ADD COLUMN IF NOT EXISTS mou_holder_sig_url      TEXT;

-- ── 20260617000001_application_eligibility_reviews.sql ──
-- Application eligibility reviews table
-- Stores structured screening answers, decision codes, and support need flags
-- for every enrollment application. Tied to the applications table.
-- Status: eligible | conditional_review | ineligible
-- Reason codes are stored as text[] for auditability.

CREATE TABLE IF NOT EXISTS public.application_eligibility_reviews (
  id                          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  application_id              UUID REFERENCES public.applications(id) ON DELETE CASCADE,

  -- Funding
  funding_snap                BOOLEAN,
  funding_tanf                BOOLEAN,
  referral_partner            BOOLEAN,
  referral_source             TEXT,
  case_manager_name           TEXT,
  case_manager_email          TEXT,
  other_funding_source        TEXT,

  -- Residency / age
  age_confirmed               BOOLEAN,
  indiana_resident            BOOLEAN,

  -- Education
  education_level             TEXT,
  has_diploma_or_ged          BOOLEAN,
  enrolled_in_ged_program     BOOLEAN,

  -- Legal
  work_authorized             BOOLEAN,
  active_warrant              BOOLEAN,
  pending_charges             BOOLEAN,
  probation_or_parole         BOOLEAN,
  legal_notes                 TEXT,

  -- Readiness
  can_attend_schedule         BOOLEAN,
  has_transportation_plan     BOOLEAN,
  can_meet_physical           BOOLEAN,
  willing_to_follow_rules     BOOLEAN,
  willing_job_readiness       BOOLEAN,
  unavailable_times           TEXT,
  motivation                  TEXT,

  -- Support needs flags (set by system based on answers)
  support_needs_transport     BOOLEAN DEFAULT FALSE,
  support_needs_vehicle       BOOLEAN DEFAULT FALSE,
  support_needs_other         BOOLEAN DEFAULT FALSE,

  -- Acknowledgments
  agrees_attendance_policy    BOOLEAN DEFAULT FALSE,
  agrees_verification_policy  BOOLEAN DEFAULT FALSE,

  -- Decision (set by system, confirmed/overridden by staff)
  eligibility_status          TEXT NOT NULL DEFAULT 'incomplete',
                              CHECK (eligibility_status IN ('eligible','conditional_review','ineligible','incomplete')),
  eligibility_reason_codes    TEXT[] DEFAULT '{}',

  -- Staff review
  reviewer_name               TEXT,
  reviewer_decision           TEXT CHECK (reviewer_decision IN ('enroll','hold','do_not_enroll', NULL)),
  reviewer_notes              TEXT,
  reviewed_at                 TIMESTAMPTZ,

  -- Enrollment conditions (e.g. "Must provide SNAP verification within 7 days")
  enrollment_conditions       JSONB DEFAULT '[]',
  condition_deadline          DATE,

  created_at                  TIMESTAMPTZ DEFAULT NOW(),
  updated_at                  TIMESTAMPTZ DEFAULT NOW()
);

-- Add support need flags and eligibility status to applications table
ALTER TABLE public.applications
  ADD COLUMN IF NOT EXISTS eligibility_status       TEXT DEFAULT 'incomplete',
  ADD COLUMN IF NOT EXISTS funding_status           TEXT DEFAULT 'pending'
                           CHECK (funding_status IN ('verified','pending','none')),
  ADD COLUMN IF NOT EXISTS readiness_status         TEXT DEFAULT 'pending'
                           CHECK (readiness_status IN ('ready','conditional','not_ready','pending')),
  ADD COLUMN IF NOT EXISTS support_needs_transport  BOOLEAN DEFAULT FALSE,
  ADD COLUMN IF NOT EXISTS support_needs_vehicle    BOOLEAN DEFAULT FALSE,
  ADD COLUMN IF NOT EXISTS support_needs_other      BOOLEAN DEFAULT FALSE,
  ADD COLUMN IF NOT EXISTS case_manager_name        TEXT,
  ADD COLUMN IF NOT EXISTS case_manager_email       TEXT,
  ADD COLUMN IF NOT EXISTS referral_source          TEXT;

-- Index for admin dashboard queries
CREATE INDEX IF NOT EXISTS idx_app_eligibility_status
  ON public.applications(eligibility_status);

CREATE INDEX IF NOT EXISTS idx_app_funding_status
  ON public.applications(funding_status);

CREATE INDEX IF NOT EXISTS idx_eligibility_reviews_application
  ON public.application_eligibility_reviews(application_id);

-- Auto-update updated_at
CREATE OR REPLACE FUNCTION update_eligibility_review_timestamp()
RETURNS TRIGGER LANGUAGE plpgsql AS $$
BEGIN
  NEW.updated_at = NOW();
  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS trg_eligibility_review_updated_at ON public.application_eligibility_reviews;
CREATE TRIGGER trg_eligibility_review_updated_at
  BEFORE UPDATE ON public.application_eligibility_reviews
  FOR EACH ROW EXECUTE FUNCTION update_eligibility_review_timestamp();

-- RLS: staff and admin can read/write; applicant can read their own
ALTER TABLE public.application_eligibility_reviews ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "staff_full_access" ON public.application_eligibility_reviews;
DO $$ BEGIN CREATE POLICY "staff_full_access" ON public.application_eligibility_reviews
  FOR ALL USING (
    EXISTS (
      SELECT 1 FROM public.profiles
      WHERE id = auth.uid()
      AND role IN ('admin','super_admin','staff')
    )
  ); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DROP POLICY IF EXISTS "applicant_read_own" ON public.application_eligibility_reviews;
DO $$ BEGIN CREATE POLICY "applicant_read_own" ON public.application_eligibility_reviews
  FOR SELECT USING (
    application_id IN (
      SELECT id FROM public.applications WHERE user_id = auth.uid()
    )
  ); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- ── 20260617000002_barber_pipeline_hardening.sql ──
-- Barber pipeline hardening
--
-- 1. Backfill any remaining NULL course_id on barber program_enrollments
-- 2. Archive duplicate barber courses (any courses row that is NOT the canonical one)
-- 3. Add check constraint: barber enrollments must have course_id set
--
