  AND slug = 'barber-lesson-36';

-- ── barber-lesson-37: Relaxers & Texturizers ─────────────────────────────────
UPDATE public.course_lessons
SET quiz_questions = '[
  {
    "id": "bl37-q1",
    "question": "How do relaxers chemically alter hair?",
