-- ── 20260618000013_program_holder_onboarding_columns.sql ──
-- Add columns needed by the program holder onboarding-complete flow
-- and OCR document processing.

-- welcome_email_sent: idempotency flag — prevents duplicate welcome emails
ALTER TABLE public.program_holders
  ADD COLUMN IF NOT EXISTS welcome_email_sent BOOLEAN NOT NULL DEFAULT FALSE;

-- ocr_text: raw OCR output stored after image document uploads
ALTER TABLE public.program_holder_documents
  ADD COLUMN IF NOT EXISTS ocr_text TEXT;

-- Index for fast lookup of unsent welcome emails
CREATE INDEX IF NOT EXISTS idx_program_holders_welcome_email_sent
  ON public.program_holders (welcome_email_sent)
  WHERE welcome_email_sent = FALSE;

-- ── 20260618000014_school_application_followups.sql ──
-- Tracks follow-up emails sent to school applicants.
-- Prevents duplicate sends across cron runs (idempotency key: application_id + sequence).

CREATE TABLE IF NOT EXISTS public.school_application_followups (
  id             UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  application_id UUID NOT NULL REFERENCES public.school_applications(id) ON DELETE CASCADE,
  sequence       TEXT NOT NULL CHECK (sequence IN ('24h', '72h', '96h')),
  sent_at        TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_school_followups_application_v2 ON public.school_application_followups(application_id);
CREATE INDEX IF NOT EXISTS idx_school_followups_sent_at     ON public.school_application_followups(sent_at DESC);

ALTER TABLE public.school_application_followups ENABLE ROW LEVEL SECURITY;

DROP policy if exists "Service role full access followups" on public.school_application_followups;
CREATE policy "Service role full access followups" on public.school_application_followups FOR ALL
  TO service_role USING (true) WITH CHECK (true);

DROP policy if exists "Admin can view followups" on public.school_application_followups;
CREATE policy "Admin can view followups" on public.school_application_followups FOR SELECT
  USING (
    EXISTS (
      SELECT 1 FROM public.profiles
      WHERE id = auth.uid()
      AND role IN ('admin', 'super_admin', 'staff')
    )
  );

-- ── 20260619000001_micro_class_enrollments.sql ──
-- micro_class_enrollments
-- Records a student's purchase of a partner micro-class (HSI, NRF, CareerSafe).
-- Created by the Stripe webhook at /api/micro-classes/webhook on checkout.session.completed.

CREATE TABLE IF NOT EXISTS public.micro_class_enrollments (
  id                  UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  course_id           TEXT NOT NULL,                        -- e.g. 'careersafe-osha10-general'
  partner_id          TEXT NOT NULL,                        -- e.g. 'careersafe'
  student_email       TEXT NOT NULL,
  student_name        TEXT NOT NULL DEFAULT '',
  stripe_session_id   TEXT NOT NULL UNIQUE,
  stripe_price_id     TEXT NOT NULL,
  amount_paid_cents   INTEGER NOT NULL,
  vendor_cost_cents   INTEGER NOT NULL,                     -- for revenue tracking
  enrollment_url      TEXT NOT NULL,
  login_url           TEXT NOT NULL,
  access_email_sent   BOOLEAN NOT NULL DEFAULT FALSE,
  created_at          TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  updated_at          TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_micro_class_enrollments_email
  ON public.micro_class_enrollments (student_email);

CREATE INDEX IF NOT EXISTS idx_micro_class_enrollments_course
  ON public.micro_class_enrollments (course_id);

-- RLS: admins can read all; students can read their own by email
ALTER TABLE public.micro_class_enrollments ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "admins_all" ON public.micro_class_enrollments;
DO $$ BEGIN CREATE POLICY "admins_all" ON public.micro_class_enrollments
  FOR ALL USING (
    EXISTS (
      SELECT 1 FROM public.profiles
      WHERE id = auth.uid()
        AND role IN ('admin', 'super_admin', 'staff')
    )
  ); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DROP POLICY IF EXISTS "student_read_own" ON public.micro_class_enrollments;
DO $$ BEGIN CREATE POLICY "student_read_own" ON public.micro_class_enrollments
  FOR SELECT USING (
    student_email = (
      SELECT email FROM auth.users WHERE id = auth.uid()
    )
  ); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- ── 20260619000002_partners_cosmetology_columns.sql ──
-- Add columns required by the cosmetology salon partner application.
-- The partners table was originally built for barbershops; these columns
-- support salon-specific fields (supervisor credentials, insurance, compensation).

ALTER TABLE public.partners
  ADD COLUMN IF NOT EXISTS legal_name TEXT,
  ADD COLUMN IF NOT EXISTS contact_phone TEXT,
  ADD COLUMN IF NOT EXISTS program_type TEXT,
  ADD COLUMN IF NOT EXISTS supervisor_name TEXT,
  ADD COLUMN IF NOT EXISTS supervisor_license_number TEXT,
  ADD COLUMN IF NOT EXISTS supervisor_years_licensed INTEGER,
  ADD COLUMN IF NOT EXISTS compensation_model TEXT,
  ADD COLUMN IF NOT EXISTS number_of_employees INTEGER,
  ADD COLUMN IF NOT EXISTS workers_comp_status TEXT,
  ADD COLUMN IF NOT EXISTS has_general_liability BOOLEAN,
  ADD COLUMN IF NOT EXISTS can_supervise_and_verify BOOLEAN,
  ADD COLUMN IF NOT EXISTS mou_acknowledged BOOLEAN DEFAULT false,
  ADD COLUMN IF NOT EXISTS notes TEXT,
  ADD COLUMN IF NOT EXISTS applied_at TIMESTAMPTZ;

-- ── 20260620000001_enrollment_draft_columns.sql ──
-- Add draft state columns to program_enrollments for wizard auto-save.
-- draft_data stores the wizard form state as JSONB.
-- wizard_step tracks which step the user was on when they last saved.

ALTER TABLE public.program_enrollments
  ADD COLUMN IF NOT EXISTS draft_data    JSONB    DEFAULT '{}'::jsonb,
  ADD COLUMN IF NOT EXISTS wizard_step   INTEGER  DEFAULT 1;

-- ── 20260620000002_lms_page_schema_fixes.sql ──
-- Fix schema gaps found during LMS page audit.
--
-- 1. certificates: add issued_at as alias for issued_date so pages using
--    either column name work. Add certificate_type column.
-- 2. courses: add thumbnail_url, total_lessons, duration_hours columns
--    that LMS pages reference.
-- 3. program_enrollments → courses FK so Supabase join syntax works.
-- 4. program_enrollments → programs FK so Supabase join syntax works.
-- 5. student_progress → courses FK and → curriculum_lessons FK.

-- ── 1. certificates ──────────────────────────────────────────────────────────

ALTER TABLE public.certificates
  ADD COLUMN IF NOT EXISTS issued_at        TIMESTAMPTZ,
  ADD COLUMN IF NOT EXISTS certificate_type TEXT;

-- Backfill issued_at from issued_date where it exists (issued_date is TEXT)
UPDATE public.certificates
SET issued_at = issued_date::TIMESTAMPTZ
WHERE issued_at IS NULL AND issued_date IS NOT NULL AND issued_date ~ '^\d{4}-\d{2}-\d{2}';

-- Keep them in sync going forward via trigger
CREATE OR REPLACE FUNCTION public.sync_certificate_issued_at()
RETURNS TRIGGER LANGUAGE plpgsql AS $$
BEGIN
  IF NEW.issued_date IS DISTINCT FROM OLD.issued_date THEN
    NEW.issued_at := NEW.issued_date;
  END IF;
  IF NEW.issued_at IS DISTINCT FROM OLD.issued_at THEN
    NEW.issued_date := NEW.issued_at;
  END IF;
  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS trg_sync_certificate_issued_at ON public.certificates;
CREATE TRIGGER trg_sync_certificate_issued_at
  BEFORE INSERT OR UPDATE ON public.certificates
  FOR EACH ROW EXECUTE FUNCTION public.sync_certificate_issued_at();

-- ── 2. courses ───────────────────────────────────────────────────────────────

ALTER TABLE public.courses
  ADD COLUMN IF NOT EXISTS thumbnail_url  TEXT,
  ADD COLUMN IF NOT EXISTS total_lessons  INTEGER DEFAULT 0,
  ADD COLUMN IF NOT EXISTS duration_hours NUMERIC(6,1) DEFAULT 0;

-- ── 3 & 4. program_enrollments FKs ───────────────────────────────────────────
-- Orphaned course_id / program_id values exist in production data so we cannot
-- add hard FK constraints without first cleaning up. Instead, create indexes
-- to support the join lookups that Supabase performs via PostgREST hints.
-- PostgREST resolves joins by column name match, not FK constraint, when the
-- relationship is specified explicitly in the select string.

CREATE INDEX IF NOT EXISTS idx_program_enrollments_course_id
  ON public.program_enrollments(course_id) WHERE course_id IS NOT NULL;

CREATE INDEX IF NOT EXISTS idx_program_enrollments_program_id
  ON public.program_enrollments(program_id) WHERE program_id IS NOT NULL;

-- ── 5. student_progress indexes ───────────────────────────────────────────────

CREATE INDEX IF NOT EXISTS idx_student_progress_course_id
  ON public.student_progress(course_id) WHERE course_id IS NOT NULL;

CREATE INDEX IF NOT EXISTS idx_student_progress_lesson_id
  ON public.student_progress(lesson_id) WHERE lesson_id IS NOT NULL;

-- ── 20260620000003_parent_student_links.sql ──
-- Parent/guardian → student relationship table for the parent portal.
-- parent_id and student_id both reference auth.users (via profiles).

CREATE TABLE IF NOT EXISTS public.parent_student_links (
  id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  parent_id       UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  student_id      UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  relationship    TEXT NOT NULL DEFAULT 'guardian',
  verified        BOOLEAN NOT NULL DEFAULT false,
  created_at      TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at      TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Index for parent lookups
CREATE INDEX IF NOT EXISTS idx_parent_student_links_parent_id
  ON public.parent_student_links(parent_id);

-- Index for student lookups (e.g. "who are my guardians?")
CREATE INDEX IF NOT EXISTS idx_parent_student_links_student_id
  ON public.parent_student_links(student_id);

-- RLS: parents can only see their own links
ALTER TABLE public.parent_student_links ENABLE ROW LEVEL SECURITY;

DROP policy if exists "parent_student_links_select_own" on public.parent_student_links;
CREATE policy "parent_student_links_select_own" on public.parent_student_links FOR SELECT
  USING (auth.uid() = parent_id OR auth.uid() = student_id);

DROP policy if exists "parent_student_links_insert_own" on public.parent_student_links;
CREATE policy "parent_student_links_insert_own" on public.parent_student_links FOR INSERT
  WITH CHECK (auth.uid() = parent_id);

DROP policy if exists "parent_student_links_delete_own" on public.parent_student_links;
CREATE policy "parent_student_links_delete_own" on public.parent_student_links FOR DELETE
  USING (auth.uid() = parent_id);

-- ── 20260621000001_applications_status_and_normalization.sql ──
-- Fix applications table: status constraint, normalization columns, dedup index
--
-- Problems addressed:
--   1. applications_valid_status constraint is missing 'under_review' and
--      'ready_to_enroll', which are written by confirm-workone and transition
--      routes respectively. Any write of those values throws a constraint
--      violation → "internal server error" for the admin.
--   2. No normalized_email / normalized_phone columns → duplicates slip through.
--   3. No unique index on (normalized_email, program_id) → same person can
--      submit multiple times for the same program.

-- ── 1. Widen status constraint to include all values the code writes ──────────

ALTER TABLE public.applications
  DROP CONSTRAINT IF EXISTS applications_valid_status,
  DROP CONSTRAINT IF EXISTS applications_status_check;

ALTER TABLE public.applications
  ADD CONSTRAINT applications_valid_status CHECK (
    status IN (
      -- canonical submission statuses (written by /api/applications)
      'submitted',
      'pending_funding',
      'pending_admin_review',
      -- intake / start-form statuses (written by /api/intake/apply)
      'new',
      'queued',
      -- admin workflow statuses
      'in_review',
      'under_review',
      'ready_to_enroll',
      'approved',
      'rejected',
      'enrolled',
      'pending_workone',
      'waitlisted'
    )
  );

-- Migrate any legacy rows that used the old status values so they don't
-- violate the new constraint on the next write.
UPDATE public.applications SET status = 'submitted'           WHERE status = 'pending';
UPDATE public.applications SET status = 'in_review'           WHERE status = 'funding_review';
UPDATE public.applications SET status = 'enrolled'            WHERE status IN ('onboarding_complete', 'converted', 'active');
-- 'pending_funding' and 'pending_admin_review' are written by /api/applications and
-- are now included in the constraint above. No row migration needed — they are valid values.

-- ── 2. Add normalization columns ──────────────────────────────────────────────

ALTER TABLE public.applications
  ADD COLUMN IF NOT EXISTS normalized_email TEXT,
  ADD COLUMN IF NOT EXISTS normalized_phone TEXT;

-- Back-fill from existing rows
UPDATE public.applications
SET
  normalized_email = lower(trim(email)),
  normalized_phone = regexp_replace(phone, '\D', '', 'g')
WHERE normalized_email IS NULL OR normalized_phone IS NULL;

-- Keep normalized columns in sync on future writes
CREATE OR REPLACE FUNCTION public.normalize_application_contact()
RETURNS TRIGGER LANGUAGE plpgsql AS $$
BEGIN
  NEW.normalized_email := lower(trim(NEW.email));
  NEW.normalized_phone := regexp_replace(NEW.phone, '\D', '', 'g');
  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS trg_normalize_application_contact ON public.applications;
CREATE TRIGGER trg_normalize_application_contact
  BEFORE INSERT OR UPDATE OF email, phone ON public.applications
  FOR EACH ROW EXECUTE FUNCTION public.normalize_application_contact();

-- ── 3. Unique index: one application per (email, program) ────────────────────
-- Partial index — only enforces uniqueness on non-rejected rows so a rejected
-- applicant can re-apply for the same program.

CREATE UNIQUE INDEX IF NOT EXISTS unique_applicant_per_program
  ON public.applications (normalized_email, program_id)
  WHERE program_id IS NOT NULL
    AND status NOT IN ('rejected', 'waitlisted');

-- ── 4. Indexes for admin queue performance ────────────────────────────────────

CREATE INDEX IF NOT EXISTS idx_applications_status
  ON public.applications (status);

CREATE INDEX IF NOT EXISTS idx_applications_normalized_email
  ON public.applications (normalized_email);

-- ── 20260621000002_backfill_application_program_ids.sql ──
-- Backfill program_id on applications that were submitted before the
-- broken .or() ilike fix (commit a4eab78). Every application submitted
-- through /api/apply or /api/apply/simple before that fix has program_id = null
-- because the PostgREST .or() syntax was malformed and always returned null.
--
-- Mapping derived from live DB audit 2026-04-12:
--   23 applications with program_id = null
--   Matchable by program_interest text → programs.id
--   Unmatchable (no program): Employer Partnership, not-sure, Other,
--     Not specified, Program Holder — left as null (no program to link)

-- ── HVAC Technician (4226f7f6-fbc1-44b5-83e8-b12ea149e4c7) ──────────────────
-- Covers: "HVAC Technician", "HVAC", "hvac-technician"
UPDATE public.applications
SET program_id = '4226f7f6-fbc1-44b5-83e8-b12ea149e4c7'
WHERE program_id IS NULL
  AND lower(trim(program_interest)) IN (
    'hvac technician', 'hvac', 'hvac-technician',
    'hvac tech', 'hvac technician program'
  );

-- ── Barber Apprenticeship (5ff21fcb-1968-41fd-99d3-37d69a31bd5c) ─────────────
UPDATE public.applications
SET program_id = '5ff21fcb-1968-41fd-99d3-37d69a31bd5c'
WHERE program_id IS NULL
  AND lower(trim(program_interest)) IN (
    'barber apprenticeship', 'barber', 'barbering'
  );

-- ── Electrical Apprenticeship (421b0486-778d-4298-93df-8c645f5b4836) ─────────
UPDATE public.applications
SET program_id = '421b0486-778d-4298-93df-8c645f5b4836'
WHERE program_id IS NULL
  AND lower(trim(program_interest)) IN (
    'electrical', 'electrical apprenticeship'
  );

-- ── Home Health Aide (d8f45366-1838-4539-ae32-7bc985773772) ──────────────────
UPDATE public.applications
SET program_id = 'd8f45366-1838-4539-ae32-7bc985773772'
WHERE program_id IS NULL
  AND lower(trim(program_interest)) IN (
    'home health aide', 'home health'
  );

-- ── Entrepreneurship / Small Business (c6cf8528-bd11-4901-a785-bce3ee921988) ─
UPDATE public.applications
SET program_id = 'c6cf8528-bd11-4901-a785-bce3ee921988'
WHERE program_id IS NULL
  AND lower(trim(program_interest)) IN (
    'entrepreneurship', 'entrepreneurship small business',
    'entrepreneurship / small business'
  );

-- ── Bookkeeping / Accounting (bd503ebf-d8e1-4c79-9efe-a72c001589b4) ──────────
UPDATE public.applications
SET program_id = 'bd503ebf-d8e1-4c79-9efe-a72c001589b4'
WHERE program_id IS NULL
  AND lower(trim(program_interest)) IN (
    'accounting', 'bookkeeping'
  );

