-- ── 20260621000003_competency_audit_log.sql ──
-- Audit trail for every instructor action on a competency check.
-- Every approve / reject / revision_requested action is recorded here.
-- This is the "proof of training" output required for DOL compliance.

CREATE TABLE IF NOT EXISTS public.competency_audit_log (
  id              uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  submission_id   uuid        NOT NULL REFERENCES public.step_submissions(id) ON DELETE CASCADE,
  user_id         uuid        NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  lesson_id       uuid        REFERENCES public.course_lessons(id) ON DELETE SET NULL,
  course_id       uuid        REFERENCES public.courses(id) ON DELETE SET NULL,
  competency_key  text        DEFAULT NULL,
  action          text        NOT NULL CHECK (action IN ('approved','rejected','revision_requested','under_review')),
  actor_id        uuid        NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  note            text        DEFAULT NULL,
  created_at      timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_competency_audit_log_user
  ON public.competency_audit_log (user_id, lesson_id);

CREATE INDEX IF NOT EXISTS idx_competency_audit_log_actor
  ON public.competency_audit_log (actor_id, created_at DESC);

CREATE INDEX IF NOT EXISTS idx_competency_audit_log_submission
  ON public.competency_audit_log (submission_id);

-- RLS: instructors and admins can read all; students can read their own
ALTER TABLE public.competency_audit_log ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "instructors_read_audit_log" ON public.competency_audit_log;
DO $$ BEGIN CREATE POLICY "instructors_read_audit_log" ON public.competency_audit_log
  FOR SELECT USING (
    EXISTS (
      SELECT 1 FROM public.profiles
      WHERE id = auth.uid()
      AND role IN ('instructor','admin','super_admin','staff')
    )
  ); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DROP POLICY IF EXISTS "students_read_own_audit_log" ON public.competency_audit_log;
DO $$ BEGIN CREATE POLICY "students_read_own_audit_log" ON public.competency_audit_log
  FOR SELECT USING (user_id = auth.uid()); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DROP POLICY IF EXISTS "instructors_insert_audit_log" ON public.competency_audit_log;
DO $$ BEGIN CREATE POLICY "instructors_insert_audit_log" ON public.competency_audit_log
  FOR INSERT WITH CHECK (
    actor_id = auth.uid() AND
    EXISTS (
      SELECT 1 FROM public.profiles
      WHERE id = auth.uid()
      AND role IN ('instructor','admin','super_admin','staff')
    )
  ); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

COMMENT ON TABLE public.competency_audit_log IS
  'Immutable audit trail of every instructor action on a competency check. Required for DOL apprenticeship compliance proof.';

-- ── 20260621000004_course_lessons_competency_columns.sql ──
-- Add competency-based learning columns to course_lessons
-- Required for Milady-aligned, state-board-credible modules.
--
-- learning_objectives  — JSONB array of outcome strings (what the student will be able to do)
-- competency_checks    — JSONB array of { key, label, description, isCritical, requiresInstructorSignoff }
-- instructor_notes     — plain text guidance for the instructor during sign-off
-- practical_required   — boolean gate: lesson cannot be marked complete until all competency_checks are signed off

ALTER TABLE public.course_lessons
  ADD COLUMN IF NOT EXISTS learning_objectives   jsonb    DEFAULT NULL,
  ADD COLUMN IF NOT EXISTS competency_checks     jsonb    DEFAULT NULL,
  ADD COLUMN IF NOT EXISTS instructor_notes      text     DEFAULT NULL,
  ADD COLUMN IF NOT EXISTS practical_required    boolean  NOT NULL DEFAULT false;

-- Index for querying lessons that require practical sign-off
CREATE INDEX IF NOT EXISTS idx_course_lessons_practical_required
  ON public.course_lessons (practical_required)
  WHERE practical_required = true;

COMMENT ON COLUMN public.course_lessons.learning_objectives IS
  'Array of outcome strings — what the student will be able to do after this lesson. Drives state-board compliance reporting.';

COMMENT ON COLUMN public.course_lessons.competency_checks IS
  'Array of { key, label, description, isCritical, requiresInstructorSignoff }. Each check maps to a step_submissions row that must be instructor-approved before lesson completion.';

COMMENT ON COLUMN public.course_lessons.instructor_notes IS
  'Plain text guidance for the instructor during in-person competency sign-off. Not shown to students.';

COMMENT ON COLUMN public.course_lessons.practical_required IS
  'When true, all competency_checks with requiresInstructorSignoff=true must have an approved step_submissions row before lesson_progress can be marked complete.';

-- ── 20260621000005_step_submissions_competency_key.sql ──
-- Add competency_key to step_submissions so each submission can be tied
-- to a specific competency_check entry on the lesson.
-- This enables the completion gate to verify each required check individually.

ALTER TABLE public.step_submissions
  ADD COLUMN IF NOT EXISTS competency_key text DEFAULT NULL;

CREATE INDEX IF NOT EXISTS idx_step_submissions_competency_key
  ON public.step_submissions (user_id, lesson_id, competency_key)
  WHERE competency_key IS NOT NULL;

COMMENT ON COLUMN public.step_submissions.competency_key IS
  'Matches a key in course_lessons.competency_checks[].key. When set, this submission represents instructor sign-off for that specific competency check.';

-- ── 20260622000001_curriculum_compiler_schema.sql ──
-- Migration: curriculum compiler schema
--
-- Adds the tables and columns required by the full curriculum compiler spec.
-- Apply in Supabase Dashboard → SQL Editor.
--
-- Tables added:
--   assessment_questions  — first-class question storage (replaces jsonb blobs)
--   rubrics               — lab/assignment grading rubrics
--   field_hours_logs      — documented field/OJT time for DOL compliance
--   competency_results    — explicit per-learner competency achievement records
--
-- Columns added to course_lessons:
--   unlock_rule           — jsonb gate rule for progression engine
--   required_artifacts    — text[] artifact types learner must submit
--   rubric_id             — FK to rubrics table
--   script_text           — video/audio generation source
--   duration_minutes      — instructional time (never null after compiler runs)
--   generation_status     — lifecycle: draft → structure_seeded → ... → published
--
-- Columns added to program_completion_certificates:
--   hours_completed       — numeric hours at time of issue
--   competencies_achieved — jsonb array of achieved competency keys
--   instructor_verified   — boolean flag
--   verification_summary  — jsonb evidence payload

-- ─── assessment_questions ─────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS public.assessment_questions (
  id              uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  lesson_id       uuid        NOT NULL REFERENCES public.course_lessons(id) ON DELETE CASCADE,
  question_type   text        NOT NULL CHECK (question_type IN ('multiple_choice','true_false','short_answer','scenario')),
  prompt          text        NOT NULL,
  choices         jsonb,
  correct_answer  jsonb,
  explanation     text,
  competency_key  text,
  difficulty      text        CHECK (difficulty IN ('easy','medium','hard')),
  domain_key      text,
  sort_order      integer     NOT NULL DEFAULT 0,
  created_at      timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_assessment_questions_lesson
  ON public.assessment_questions (lesson_id, sort_order);

CREATE INDEX IF NOT EXISTS idx_assessment_questions_competency
  ON public.assessment_questions (competency_key)
  WHERE competency_key IS NOT NULL;

ALTER TABLE public.assessment_questions ENABLE ROW LEVEL SECURITY;

DROP policy if exists "instructors_read_questions" on public.assessment_questions;
CREATE policy "instructors_read_questions" on public.assessment_questions
  FOR SELECT USING (
    EXISTS (
      SELECT 1 FROM public.profiles
      WHERE id = auth.uid()
      AND role IN ('instructor','admin','super_admin','staff')
    )
  );

DROP policy if exists "admins_manage_questions" on public.assessment_questions;
CREATE policy "admins_manage_questions" on public.assessment_questions
  FOR ALL USING (
    EXISTS (
      SELECT 1 FROM public.profiles
      WHERE id = auth.uid()
      AND role IN ('admin','super_admin')
    )
  );

COMMENT ON TABLE public.assessment_questions IS
  'First-class question storage. Replaces quiz_questions jsonb blobs on course_lessons for programs using the compiler pipeline.';

-- ─── rubrics ─────────────────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS public.rubrics (
  id                uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  title             text        NOT NULL,
  program_slug      text,
  criteria          jsonb       NOT NULL DEFAULT '[]'::jsonb,
  passing_threshold integer     CHECK (passing_threshold BETWEEN 0 AND 100),
  created_at        timestamptz NOT NULL DEFAULT now(),
  updated_at        timestamptz NOT NULL DEFAULT now()
);

ALTER TABLE public.rubrics ENABLE ROW LEVEL SECURITY;

DROP policy if exists "instructors_read_rubrics" on public.rubrics;
CREATE policy "instructors_read_rubrics" on public.rubrics
  FOR SELECT USING (
    EXISTS (
      SELECT 1 FROM public.profiles
      WHERE id = auth.uid()
      AND role IN ('instructor','admin','super_admin','staff')
    )
  );

DROP policy if exists "admins_manage_rubrics" on public.rubrics;
CREATE policy "admins_manage_rubrics" on public.rubrics
  FOR ALL USING (
    EXISTS (
      SELECT 1 FROM public.profiles
      WHERE id = auth.uid()
      AND role IN ('admin','super_admin')
    )
  );

COMMENT ON TABLE public.rubrics IS
  'Grading rubrics for lab and assignment lessons. criteria is a jsonb array of { criterion, description, maxPoints }.';

-- ─── field_hours_logs ─────────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS public.field_hours_logs (
  id               uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id          uuid        NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  course_id        uuid        NOT NULL REFERENCES public.courses(id) ON DELETE CASCADE,
  module_id        uuid        REFERENCES public.course_modules(id) ON DELETE SET NULL,
  activity_date    date        NOT NULL,
  minutes          integer     NOT NULL CHECK (minutes > 0),
  description      text,
  supervisor_name  text,
  supervisor_email text,
  verified         boolean     NOT NULL DEFAULT false,
  verified_by      uuid        REFERENCES auth.users(id) ON DELETE SET NULL,
  verified_at      timestamptz,
  created_at       timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_field_hours_logs_user_course
  ON public.field_hours_logs (user_id, course_id);

CREATE INDEX IF NOT EXISTS idx_field_hours_logs_unverified
  ON public.field_hours_logs (course_id, verified)
  WHERE verified = false;

ALTER TABLE public.field_hours_logs ENABLE ROW LEVEL SECURITY;

DROP policy if exists "students_manage_own_hours" on public.field_hours_logs;
CREATE policy "students_manage_own_hours" on public.field_hours_logs
  FOR ALL USING (user_id = auth.uid());

DROP policy if exists "instructors_read_hours" on public.field_hours_logs;
CREATE policy "instructors_read_hours" on public.field_hours_logs
  FOR SELECT USING (
    EXISTS (
      SELECT 1 FROM public.profiles
      WHERE id = auth.uid()
      AND role IN ('instructor','admin','super_admin','staff')
    )
  );

DROP policy if exists "instructors_verify_hours" on public.field_hours_logs;
CREATE policy "instructors_verify_hours" on public.field_hours_logs
  FOR UPDATE USING (
    EXISTS (
      SELECT 1 FROM public.profiles
      WHERE id = auth.uid()
      AND role IN ('instructor','admin','super_admin','staff')
    )
  );

COMMENT ON TABLE public.field_hours_logs IS
  'Documented OJT/field hours for DOL apprenticeship compliance. Each row is one work session. Supervisor verification required for DOL reporting.';

-- ─── competency_results ───────────────────────────────────────────────────────
-- Named competency_results (spec) — distinct from competency_audit_log (immutable audit trail).
-- competency_audit_log = every action taken. competency_results = current achievement state.

CREATE TABLE IF NOT EXISTS public.competency_results (
  id                    uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id               uuid        NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  course_id             uuid        NOT NULL REFERENCES public.courses(id) ON DELETE CASCADE,
  competency_key        text        NOT NULL,
  status                text        NOT NULL DEFAULT 'not_started',
                                    CHECK (status IN ('not_started','in_progress','achieved','failed')),
  achieved_at           timestamptz,
  achieved_via          text        CHECK (achieved_via IN ('quiz','lab','exam','observation','assignment')),
  verified_by           uuid        REFERENCES auth.users(id) ON DELETE SET NULL,
  lesson_id             uuid        REFERENCES public.course_lessons(id) ON DELETE SET NULL,
  evidence_submission_id uuid       REFERENCES public.step_submissions(id) ON DELETE SET NULL,
  created_at            timestamptz NOT NULL DEFAULT now(),
  updated_at            timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_competency_results_user_course
  ON public.competency_results (user_id, course_id);

CREATE INDEX IF NOT EXISTS idx_competency_results_key
  ON public.competency_results (competency_key, status);

ALTER TABLE public.competency_results ENABLE ROW LEVEL SECURITY;

DROP policy if exists "students_read_own_results" on public.competency_results;
CREATE policy "students_read_own_results" on public.competency_results
  FOR SELECT USING (user_id = auth.uid());

DROP policy if exists "instructors_read_results" on public.competency_results;
CREATE policy "instructors_read_results" on public.competency_results
  FOR SELECT USING (
    EXISTS (
      SELECT 1 FROM public.profiles
      WHERE id = auth.uid()
      AND role IN ('instructor','admin','super_admin','staff')
    )
  );

DROP policy if exists "instructors_manage_results" on public.competency_results;
CREATE policy "instructors_manage_results" on public.competency_results
  FOR ALL USING (
    EXISTS (
      SELECT 1 FROM public.profiles
      WHERE id = auth.uid()
      AND role IN ('instructor','admin','super_admin','staff')
    )
  );

COMMENT ON TABLE public.competency_results IS
  'Current competency achievement state per learner. One row per (user, course, competency_key). Updated when a competency is achieved via quiz, lab, exam, or instructor observation.';

-- ─── course_lessons additions ─────────────────────────────────────────────────

ALTER TABLE public.course_lessons
  ADD COLUMN IF NOT EXISTS unlock_rule        jsonb,
  ADD COLUMN IF NOT EXISTS required_artifacts text[]      DEFAULT '{}',
  ADD COLUMN IF NOT EXISTS rubric_id          uuid        REFERENCES public.rubrics(id) ON DELETE SET NULL,
  ADD COLUMN IF NOT EXISTS script_text        text,
  ADD COLUMN IF NOT EXISTS duration_minutes   integer,
  ADD COLUMN IF NOT EXISTS generation_status  text        NOT NULL DEFAULT 'draft'
                                              CHECK (generation_status IN (
                                                'draft','structure_seeded','content_hydrated',
                                                'assessment_ready','verification_ready',
                                                'certificate_ready','published'
                                              ));

CREATE INDEX IF NOT EXISTS idx_course_lessons_generation_status
  ON public.course_lessons (generation_status)
  WHERE generation_status != 'published';

COMMENT ON COLUMN public.course_lessons.unlock_rule IS
  'JSONB gate rule consumed by lib/lms/progression-gate.ts. Shape: { type: "pass_assessment"|"approved_submission"|"complete_previous_module"|"achieve_competency", ... }';

COMMENT ON COLUMN public.course_lessons.required_artifacts IS
  'Artifact types the learner must submit: text, video, audio, checklist, document.';

COMMENT ON COLUMN public.course_lessons.rubric_id IS
  'FK to rubrics table. Required for lab and assignment lessons that use structured grading.';

COMMENT ON COLUMN public.course_lessons.script_text IS
  'Source text for video/audio generation. Written by the hydrator, consumed by the video pipeline.';

COMMENT ON COLUMN public.course_lessons.duration_minutes IS
  'Instructional time in minutes. The hours engine sets this; the compiler hard-fails if null after generation.';

COMMENT ON COLUMN public.course_lessons.generation_status IS
  'Lifecycle status: draft → structure_seeded → content_hydrated → assessment_ready → verification_ready → certificate_ready → published. The publish route requires published status.';

-- ─── program_completion_certificates additions ────────────────────────────────

ALTER TABLE public.program_completion_certificates
  ADD COLUMN IF NOT EXISTS hours_completed       numeric,
  ADD COLUMN IF NOT EXISTS competencies_achieved jsonb    DEFAULT '[]'::jsonb,
  ADD COLUMN IF NOT EXISTS instructor_verified   boolean  NOT NULL DEFAULT false,
  ADD COLUMN IF NOT EXISTS verification_summary  jsonb    DEFAULT '{}'::jsonb;

COMMENT ON COLUMN public.program_completion_certificates.hours_completed IS
  'Total instructional hours at time of certificate issue. Sourced from field_hours_logs + lesson duration_minutes.';

COMMENT ON COLUMN public.program_completion_certificates.competencies_achieved IS
  'JSONB array of { key, label, achievedAt, achievedVia } for all competencies achieved during the program.';

COMMENT ON COLUMN public.program_completion_certificates.instructor_verified IS
  'True when at least one instructor has verified a practical competency for this learner.';

COMMENT ON COLUMN public.program_completion_certificates.verification_summary IS
  'Full CertificateEvidence payload: hoursCompleted, competenciesAchieved, criticalCompetenciesAchieved, finalExamScore, completionDate.';

-- ── 20260622000003_lock_down_public_lesson_access.sql ──
-- Lock down public lesson access
--
-- Schema verified before writing:
--   course_lessons.module_id          ✓ (20260402000006_canonical_curriculum.sql:56)
--   course_modules.course_id          ✓ (20260601000005_baseline_untracked_tables.sql:1978)
--   profiles(id, role)                ✓ (20260227000003_schema_governance_baseline.sql:10)
--   courses uses status/is_active     ✓ NOT is_published (that column is on training_courses)
--
-- The proposed migration used is_published on courses — that column does not
-- exist on public.courses. This migration uses the correct columns.
--
-- What this closes:
--   20260402000006 issued GRANT SELECT ON course_lessons TO anon and created
--   a policy with no auth.role() check. Any unauthenticated browser client
--   could read full lesson content (quiz_questions, content, video_url,
--   passing_score) for every published course.
--
-- Apply: Supabase Dashboard → SQL Editor
-- Verify: run the queries at the bottom with SET ROLE anon / authenticated

-- BEGIN; (removed: exec_sql runs in implicit txn)

-- =========================================================
-- 1. course_lessons — remove anon, require authenticated
-- =========================================================

REVOKE ALL ON public.course_lessons FROM anon;
REVOKE ALL ON public.course_lessons FROM public;
GRANT  SELECT ON public.course_lessons TO authenticated;
GRANT  ALL    ON public.course_lessons TO service_role;

-- Drop all known permissive policies from prior migrations
DROP POLICY IF EXISTS "Anyone can read course lessons"                    ON public.course_lessons;
DROP POLICY IF EXISTS "Authenticated users can read course lessons"       ON public.course_lessons;
DROP POLICY IF EXISTS "Users can read published course lessons"           ON public.course_lessons;
DROP POLICY IF EXISTS "course_lessons_select"                             ON public.course_lessons;
DROP POLICY IF EXISTS "Authenticated read published lessons"              ON public.course_lessons;
DROP POLICY IF EXISTS "course_lessons_authenticated_read"                 ON public.course_lessons;
DROP POLICY IF EXISTS "Admins and instructors can read all course lessons" ON public.course_lessons;
DROP POLICY IF EXISTS "Service role lessons"                              ON public.course_lessons;
DROP POLICY IF EXISTS "course_lessons_service_role"                       ON public.course_lessons;

-- Learners: read lessons for published, active courses
-- Uses status + is_active — the actual columns on public.courses
DROP POLICY IF EXISTS "course_lessons_authenticated_read" ON public.course_lessons;
DO $$ BEGIN CREATE POLICY "course_lessons_authenticated_read" ON public.course_lessons
  FOR SELECT
  TO authenticated
  USING (
    auth.role() = 'authenticated'
    AND EXISTS (
      SELECT 1
      FROM public.course_modules cm
      JOIN public.courses c ON c.id = cm.course_id
      WHERE cm.id          = course_lessons.module_id
        AND c.status       = 'published'
        AND c.is_active    = true
    )
  ); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- Admins and instructors: read all lessons regardless of publish state
-- (needed for admin curriculum builder and instructor preview)
DROP POLICY IF EXISTS "course_lessons_admin_read" ON public.course_lessons;
DO $$ BEGIN CREATE POLICY "course_lessons_admin_read" ON public.course_lessons
  FOR SELECT
  TO authenticated
  USING (
    auth.role() = 'authenticated'
    AND EXISTS (
      SELECT 1
      FROM public.profiles p
      WHERE p.id   = auth.uid()
        AND p.role IN ('admin', 'super_admin', 'instructor', 'staff')
    )
  ); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- Service role: unrestricted (used by server-side pipeline and seed scripts)
DROP POLICY IF EXISTS "course_lessons_service_role" ON public.course_lessons;
DO $$ BEGIN CREATE POLICY "course_lessons_service_role" ON public.course_lessons
  FOR ALL
  TO service_role
  USING (true)
  WITH CHECK (true); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- =========================================================
-- 2. lms_lessons view — remove anon grant
-- =========================================================
-- View uses security_invoker=true so underlying RLS is the real gate.
-- Revoking anon removes the explicit grant as belt-and-suspenders.

REVOKE ALL   ON public.lms_lessons FROM anon;
REVOKE ALL   ON public.lms_lessons FROM public;
GRANT  SELECT ON public.lms_lessons TO authenticated, service_role;

-- =========================================================
-- 3. course_modules — ensure anon cannot read module structure
-- =========================================================

REVOKE ALL   ON public.course_modules FROM anon;
REVOKE ALL   ON public.course_modules FROM public;
GRANT  SELECT ON public.course_modules TO authenticated;
GRANT  ALL    ON public.course_modules TO service_role;

ALTER TABLE public.course_modules ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "course_modules_authenticated_read" ON public.course_modules;
DROP POLICY IF EXISTS "course_modules_admin_read"         ON public.course_modules;
DROP POLICY IF EXISTS "course_modules_service_role"       ON public.course_modules;

DROP POLICY IF EXISTS "course_modules_authenticated_read" ON public.course_modules;
DO $$ BEGIN CREATE POLICY "course_modules_authenticated_read" ON public.course_modules
  FOR SELECT
  TO authenticated
  USING (
    auth.role() = 'authenticated'
    AND EXISTS (
      SELECT 1 FROM public.courses c
      WHERE c.id       = course_modules.course_id
        AND c.status   = 'published'
        AND c.is_active = true
    )
  ); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DROP POLICY IF EXISTS "course_modules_admin_read" ON public.course_modules;
DO $$ BEGIN CREATE POLICY "course_modules_admin_read" ON public.course_modules
  FOR SELECT
  TO authenticated
  USING (
    auth.role() = 'authenticated'
    AND EXISTS (
      SELECT 1 FROM public.profiles p
      WHERE p.id   = auth.uid()
        AND p.role IN ('admin', 'super_admin', 'instructor', 'staff')
    )
  ); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DROP POLICY IF EXISTS "course_modules_service_role" ON public.course_modules;
DO $$ BEGIN CREATE POLICY "course_modules_service_role" ON public.course_modules
  FOR ALL
  TO service_role
  USING (true)
  WITH CHECK (true); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- =========================================================
-- 4. courses — keep anon catalog read, tighten policies
-- =========================================================
-- courses uses status + is_active, NOT is_published.
-- Anon can see published catalog rows (name, price, description).
-- This is intentional for the public course catalog pages.

GRANT SELECT ON public.courses TO anon;
GRANT SELECT ON public.courses TO authenticated;
GRANT ALL    ON public.courses TO service_role;

DROP POLICY IF EXISTS "Anyone can read courses"                ON public.courses;
DROP POLICY IF EXISTS "Public can read published courses"      ON public.courses;
DROP POLICY IF EXISTS "Public read published courses"          ON public.courses;
DROP POLICY IF EXISTS "courses_select"                         ON public.courses;
DROP POLICY IF EXISTS "Anon can read published catalog courses" ON public.courses;
DROP POLICY IF EXISTS "Authenticated users can read published courses" ON public.courses;
DROP POLICY IF EXISTS "Admins can read all courses"            ON public.courses;
DROP POLICY IF EXISTS "Service role courses"                   ON public.courses;

-- Anon: published catalog only
DROP POLICY IF EXISTS "courses_anon_catalog" ON public.courses;
DO $$ BEGIN CREATE POLICY "courses_anon_catalog" ON public.courses
  FOR SELECT
  TO anon
  USING (status = 'published' AND is_active = true); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- Authenticated learners: published courses
DROP POLICY IF EXISTS "courses_authenticated_read" ON public.courses;
DO $$ BEGIN CREATE POLICY "courses_authenticated_read" ON public.courses
  FOR SELECT
  TO authenticated
  USING (
    auth.role() = 'authenticated'
    AND status  = 'published'
    AND is_active = true
  ); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- Admins/instructors: all courses (draft + published)
DROP POLICY IF EXISTS "courses_admin_read" ON public.courses;
DO $$ BEGIN CREATE POLICY "courses_admin_read" ON public.courses
  FOR SELECT
  TO authenticated
  USING (
    auth.role() = 'authenticated'
    AND EXISTS (
      SELECT 1 FROM public.profiles p
      WHERE p.id   = auth.uid()
        AND p.role IN ('admin', 'super_admin', 'instructor', 'staff')
    )
  ); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- Service role: unrestricted
DROP POLICY IF EXISTS "courses_service_role" ON public.courses;
DO $$ BEGIN CREATE POLICY "courses_service_role" ON public.courses
  FOR ALL
  TO service_role
  USING (true)
  WITH CHECK (true); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- COMMIT; (removed: exec_sql runs in implicit txn)

