-- ── 20260622000004_instructor_scoped_lesson_rls.sql ──
-- Scope instructor read access on course_lessons to assigned programs only.
--
-- Before this migration, instructors had a global read policy on course_lessons
-- (same as admins), meaning any instructor could read quiz_questions and
-- passing_score for every course in the system.
--
-- After this migration:
--   - Admins / super_admin / staff / org_admin: unchanged — read all lessons
--   - Instructors: read only lessons belonging to courses in programs they are
--     assigned to via program_instructors
--   - Learners: unchanged — read published lessons for enrolled courses only
--
-- Join chain: course_lessons.course_id → courses.program_id → program_instructors
--
-- Apply in Supabase Dashboard → SQL Editor.

-- Drop the existing combined admin+instructor policy
DROP POLICY IF EXISTS "course_lessons_admin_read" ON public.course_lessons;

-- Admins/staff: unrestricted read (no instructor role here)
DROP POLICY IF EXISTS "course_lessons_admin_read" ON public.course_lessons;
DO $$ BEGIN CREATE POLICY "course_lessons_admin_read" ON public.course_lessons
  FOR SELECT
  TO authenticated
  USING (
    EXISTS (
      SELECT 1 FROM public.profiles p
      WHERE p.id = auth.uid()
        AND p.role IN ('admin', 'super_admin', 'staff', 'org_admin')
    )
  ); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- Instructors: read only lessons for their assigned programs
DROP POLICY IF EXISTS "course_lessons_instructor_read" ON public.course_lessons;
DO $$ BEGIN CREATE POLICY "course_lessons_instructor_read" ON public.course_lessons
  FOR SELECT
  TO authenticated
  USING (
    EXISTS (
      SELECT 1
      FROM public.profiles p
      JOIN public.program_instructors pi ON pi.instructor_id = p.id
      JOIN public.courses c ON c.program_id = pi.program_id
      WHERE p.id = auth.uid()
        AND p.role = 'instructor'
        AND c.id = course_lessons.course_id
    )
  ); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- Repeat for course_modules — same scoping logic
DROP POLICY IF EXISTS "course_modules_admin_read" ON public.course_modules;

DROP POLICY IF EXISTS "course_modules_admin_read" ON public.course_modules;
DO $$ BEGIN CREATE POLICY "course_modules_admin_read" ON public.course_modules
  FOR SELECT
  TO authenticated
  USING (
    EXISTS (
      SELECT 1 FROM public.profiles p
      WHERE p.id = auth.uid()
        AND p.role IN ('admin', 'super_admin', 'staff', 'org_admin')
    )
  ); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DROP POLICY IF EXISTS "course_modules_instructor_read" ON public.course_modules;
DO $$ BEGIN CREATE POLICY "course_modules_instructor_read" ON public.course_modules
  FOR SELECT
  TO authenticated
  USING (
    EXISTS (
      SELECT 1
      FROM public.profiles p
      JOIN public.program_instructors pi ON pi.instructor_id = p.id
      JOIN public.courses c ON c.program_id = pi.program_id
      WHERE p.id = auth.uid()
        AND p.role = 'instructor'
        AND c.id = course_modules.course_id
    )
  ); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- ── 20260622000005_lms_lessons_competency_checks.sql ──
-- Expose competency_checks in lms_lessons view.
--
-- The lesson page reads competency_checks to pass competencyKey to StepSubmissionForm.
-- Without this column in the view, the prop is always undefined → submissions stored
-- with competency_key=null → gate query never matches → lab lessons permanently blocked.
--
-- Both branches of the UNION are updated:
--   curriculum_lessons branch: cl.competency_checks (column added in 20260621000001)
--   course_lessons branch:     cl.competency_checks (same column on course_lessons)

DROP VIEW IF EXISTS public.lms_lessons CASCADE;

CREATE VIEW public.lms_lessons AS

-- curriculum_lessons (priority) — published only
SELECT
  cl.id,
  cl.course_id,
  (cl.module_order * 1000 + cl.lesson_order)  AS order_index,
  cl.lesson_order                              AS lesson_number,
  cl.lesson_title                              AS title,
  cl.script_text                               AS content,
  NULL::TEXT                                   AS rendered_html,
  cl.step_type::TEXT                           AS step_type,
  cl.step_type::TEXT                           AS content_type,
  cl.lesson_slug                               AS slug,
  cl.lesson_slug                               AS lesson_slug,
  cl.passing_score,
  cl.quiz_questions,
  NULL::JSONB                                  AS activities,
  NULL::JSONB                                  AS video_config,
  cm.id                                        AS module_id,
  cm.title                                     AS module_title,
  cl.module_order,
  cl.lesson_order,
  cl.duration_minutes,
  (cl.status = 'published')                    AS is_published,
  cl.status,
  'curriculum'::TEXT                           AS lesson_source,
  cl.created_at,
  cl.updated_at,
  NULL::TEXT                                   AS partner_exam_code,
  cl.video_file                                AS video_url,
  NULL::UUID                                   AS quiz_id,
  NULL::TEXT                                   AS description,
  NULL::JSONB                                  AS resources,
  NULL::TEXT                                   AS scorm_package_id,
  NULL::TEXT                                   AS scorm_launch_path,
  cl.competency_checks                                                -- ← added
FROM public.curriculum_lessons cl
LEFT JOIN public.course_modules cm
  ON cm.course_id = cl.course_id
  AND cm.order_index = cl.module_order
WHERE cl.status = 'published'

UNION ALL

-- course_lessons fallback (courses not in curriculum_lessons) — published only
SELECT
  cl.id,
  cl.course_id,
  cl.order_index,
  cl.order_index                               AS lesson_number,
  cl.title,
  (cl.content#>>'{}')                          AS content,
  cl.rendered_html,
  cl.lesson_type::TEXT                         AS step_type,
  cl.lesson_type::TEXT                         AS content_type,
  cl.slug,
  cl.slug                                      AS lesson_slug,
  cl.passing_score,
  cl.quiz_questions,
  cl.activities,
  cl.video_config,
  cl.module_id,
  cm.title                                     AS module_title,
  COALESCE(cm.order_index, 0)                  AS module_order,
  NULL::INTEGER                                AS lesson_order,
  NULL::INTEGER                                AS duration_minutes,
  cl.is_published,
  cl.status,
  'canonical'::TEXT                            AS lesson_source,
  cl.created_at,
  cl.updated_at,
  cl.partner_exam_code,
  cl.video_url,
  NULL::UUID                                   AS quiz_id,
  NULL::TEXT                                   AS description,
  NULL::JSONB                                  AS resources,
  NULL::TEXT                                   AS scorm_package_id,
  NULL::TEXT                                   AS scorm_launch_path,
  cl.competency_checks                                                -- ← added
FROM public.course_lessons cl
LEFT JOIN public.course_modules cm ON cm.id = cl.module_id
WHERE cl.status = 'published'
  AND NOT EXISTS (
    SELECT 1 FROM public.curriculum_lessons cur
    WHERE cur.course_id = cl.course_id
  );

-- Restore grants (CASCADE drop removed them)
REVOKE ALL ON public.lms_lessons FROM anon, public;
GRANT SELECT ON public.lms_lessons TO authenticated, service_role;

-- Verify:
-- SELECT id, title, competency_checks FROM public.lms_lessons WHERE competency_checks IS NOT NULL LIMIT 5;

-- ── 20260622000006_documents_ocr_columns.sql ──
-- Ensure OCR result columns exist on documents table.
-- These may already exist from earlier migrations — all statements are idempotent.

ALTER TABLE public.documents
  ADD COLUMN IF NOT EXISTS ocr_text         TEXT,
  ADD COLUMN IF NOT EXISTS ocr_confidence   DECIMAL(5,4),
  ADD COLUMN IF NOT EXISTS extracted_data   JSONB DEFAULT '{}',
  ADD COLUMN IF NOT EXISTS processed_at     TIMESTAMPTZ,
  ADD COLUMN IF NOT EXISTS processed_by     UUID REFERENCES auth.users(id) ON DELETE SET NULL;

-- Index for finding unprocessed documents efficiently
CREATE INDEX IF NOT EXISTS idx_documents_status
  ON public.documents (status)
  WHERE status IN ('pending', 'pending_review', 'processing', 'error');

-- Index for looking up a user's documents
CREATE INDEX IF NOT EXISTS idx_documents_user_id
  ON public.documents (user_id)
  WHERE user_id IS NOT NULL;

COMMENT ON COLUMN public.documents.ocr_text IS 'Raw text extracted by Tesseract (images) or pdf-parse (PDFs)';
COMMENT ON COLUMN public.documents.ocr_confidence IS 'OCR confidence 0.0–1.0; NULL means not yet processed or source was pdf-parse (exact)';
COMMENT ON COLUMN public.documents.extracted_data IS 'Structured fields parsed from ocr_text: {fields, source, word_count, char_count}';
COMMENT ON COLUMN public.documents.processed_at IS 'Timestamp when OCR processing completed';
COMMENT ON COLUMN public.documents.processed_by IS 'Admin user who triggered processing';

-- ── 20260622000007_platform_settings_history.sql ──
-- platform_settings_history
-- Stores previous values of platform_settings rows so admins can roll back.
-- Written by /api/admin/env-vars on every upsert.

create table if not exists platform_settings_history (
  id          bigserial primary key,
  key         text        not null,
  old_value   text,
  new_value   text        not null,
  changed_by  uuid        references auth.users(id) on delete set null,
  changed_at  timestamptz not null default now()
);

create index if not exists platform_settings_history_key_idx
  on platform_settings_history (key, changed_at desc);

-- RLS: super_admin / admin / staff can read; only service role can write
alter table platform_settings_history enable row level security;

drop policy if exists "admins can read settings history" on platform_settings_history;
create policy "admins can read settings history" on platform_settings_history for select
  using (
    exists (
      select 1 from profiles
      where profiles.id = auth.uid()
        and profiles.role in ('super_admin', 'admin', 'staff')
    )
  );

-- ── 20260623000001_publish_all_active_programs.sql ──
-- Ensure all programs that have dedicated pages are published and active.
--
-- Programs were inserted with various status values ('active', 'draft', etc.)
-- but the public catalog queries require published = true AND is_active = true.
-- This migration sets those flags for every program that has a live page.
--
-- Safe to re-run: uses INSERT ... ON CONFLICT DO UPDATE.
-- Apply in Supabase Dashboard → SQL Editor.

-- ── 1. Publish all existing programs that are not archived ────────────────────
-- Any program already in the table with status != 'archived' should be visible.

UPDATE public.programs
SET
  published  = true,
  is_active  = true,
  updated_at = now()
WHERE
  (published = false OR published IS NULL OR is_active = false OR is_active IS NULL)
  AND (status IS NULL OR status != 'archived');

