-- ── 20260624000003_step_submissions_assignment_id.sql ──
-- Allow step_submissions to be linked to an assignment directly,
-- without requiring a curriculum_lessons row.
--
-- Before: lesson_id NOT NULL FK → curriculum_lessons (blocks standalone assignments)
-- After:  lesson_id nullable, assignment_id nullable FK → assignments,
--         CHECK (lesson_id IS NOT NULL OR assignment_id IS NOT NULL)

-- 1. Drop the NOT NULL constraint on lesson_id
ALTER TABLE public.step_submissions
  ALTER COLUMN lesson_id DROP NOT NULL;

-- 2. Add assignment_id column
ALTER TABLE public.step_submissions
  ADD COLUMN IF NOT EXISTS assignment_id uuid REFERENCES public.assignments(id) ON DELETE CASCADE;

-- 3. Ensure at least one of lesson_id / assignment_id is always set
ALTER TABLE public.step_submissions
  DROP CONSTRAINT IF EXISTS step_submissions_requires_lesson_or_assignment;

ALTER TABLE public.step_submissions
  ADD CONSTRAINT step_submissions_requires_lesson_or_assignment
  CHECK (lesson_id IS NOT NULL OR assignment_id IS NOT NULL);

-- 4. Index for assignment-based lookups
CREATE INDEX IF NOT EXISTS idx_step_submissions_assignment_id
  ON public.step_submissions (assignment_id)
  WHERE assignment_id IS NOT NULL;

-- ── 20260624000004_sfc_leads.sql ──
ALTER TABLE public.sfc_leads ADD COLUMN IF NOT EXISTS service_type text;
ALTER TABLE public.sfc_leads ADD COLUMN IF NOT EXISTS referral_source text;
ALTER TABLE public.sfc_leads ADD COLUMN IF NOT EXISTS assigned_to uuid REFERENCES auth.users(id) ON DELETE SET NULL;
ALTER TABLE public.sfc_leads ADD COLUMN IF NOT EXISTS converted_at timestamptz;
ALTER TABLE public.sfc_leads ADD COLUMN IF NOT EXISTS metadata jsonb DEFAULT '{}';

-- Supersonic Fast Cash — canonical intake spine
-- Phase 2.2: every form on the SFC site writes one sfc_leads row.
-- Phase 3.3: documents attach to lead_id via sfc_documents.
-- Phase 3.4: appointments link back via sfc_leads.appointment_id.
-- Apply in Supabase Dashboard → SQL Editor

-- ── Leads ────────────────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS public.sfc_leads (
  id                      uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  created_at              timestamptz NOT NULL DEFAULT now(),
  updated_at              timestamptz NOT NULL DEFAULT now(),

  -- Identity
  first_name              text        NOT NULL,
  last_name               text        NOT NULL,
  email                   text        NOT NULL,
  phone                   text,
  preferred_contact_method text       CHECK (preferred_contact_method IN ('phone','email','text')) DEFAULT 'phone',

  -- Attribution
  source                  text        NOT NULL DEFAULT 'website',
                            CHECK (source IN ('calculator','service_page','contact','state_page','book_appointment','start','upload','referral','website')),
  source_detail           text,       -- e.g. 'tax-preparation-indiana', 'refund-advance'
  utm_campaign            text,
  utm_medium              text,

  -- Qualification
  service_type            text        CHECK (service_type IN ('tax_prep','refund_advance','bookkeeping','payroll','diy','audit_protection','cash_advance')),
  state                   text,
  filing_status           text        CHECK (filing_status IN ('single','married_joint','married_separate','head_of_household')),
  income_range            text        CHECK (income_range IN ('under_25k','25k_50k','50k_75k','75k_100k','over_100k')),
  refund_estimate         numeric(10,2),
  has_1099                boolean,
  has_dependents          boolean,
  dependents_count        int,
  needs_refund_advance    boolean,

  -- Pipeline status
  status                  text        NOT NULL DEFAULT 'new',
                            CHECK (status IN ('new','contacted','docs_pending','docs_received','in_preparation','filed','completed','lost')),

  -- Links
  appointment_id          uuid,       -- FK set after appointment is created
  notes                   text           -- one canonical lead per email; use upsert for duplicates
);

CREATE INDEX IF NOT EXISTS idx_sfc_leads_status      ON public.sfc_leads(status);
CREATE INDEX IF NOT EXISTS idx_sfc_leads_source      ON public.sfc_leads(source);
CREATE INDEX IF NOT EXISTS idx_sfc_leads_created_at  ON public.sfc_leads(created_at DESC);
CREATE INDEX IF NOT EXISTS idx_sfc_leads_service     ON public.sfc_leads(service_type);

-- ── Documents ─────────────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS public.sfc_documents (
  id            uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  created_at    timestamptz NOT NULL DEFAULT now(),

  lead_id       uuid        NOT NULL REFERENCES public.sfc_leads(id) ON DELETE CASCADE,
  file_url      text        NOT NULL,
  file_name     text,
  file_type     text,       -- 'pdf','jpg','png','heic'
  file_size     bigint,
  doc_category  text        CHECK (doc_category IN ('w2','1099','id','ssn_card','prior_return','other')),
  uploaded_at   timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_sfc_documents_lead_id ON public.sfc_documents(lead_id);

-- ── Row-level security ─────────────────────────────────────────────────────
-- Service-role writes (via admin client) are unrestricted.
-- Authenticated admin/staff can read all rows.
-- Public: no direct access — all mutations go through the API.

ALTER TABLE public.sfc_leads     ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.sfc_documents ENABLE ROW LEVEL SECURITY;

-- Admin read policy
DROP POLICY IF EXISTS sfc_leads_admin_read     ON public.sfc_leads;
DROP POLICY IF EXISTS sfc_documents_admin_read ON public.sfc_documents;

DO $$ BEGIN CREATE POLICY sfc_leads_admin_read ON public.sfc_leads
  FOR SELECT
  USING (
    EXISTS (
      SELECT 1 FROM public.profiles p
      WHERE p.id = auth.uid()
        AND p.role IN ('admin','super_admin','staff')
    )
  ); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DO $$ BEGIN CREATE POLICY sfc_documents_admin_read ON public.sfc_documents
  FOR SELECT
  USING (
    EXISTS (
      SELECT 1 FROM public.profiles p
      WHERE p.id = auth.uid()
        AND p.role IN ('admin','super_admin','staff')
    )
  ); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- Admin write policy (status updates, notes)
DROP POLICY IF EXISTS sfc_leads_admin_write     ON public.sfc_leads;

DO $$ BEGIN CREATE POLICY sfc_leads_admin_write ON public.sfc_leads
  FOR UPDATE
  USING (
    EXISTS (
      SELECT 1 FROM public.profiles p
      WHERE p.id = auth.uid()
        AND p.role IN ('admin','super_admin','staff')
    )
  ); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- ── Timestamp trigger ─────────────────────────────────────────────────────

CREATE OR REPLACE FUNCTION public.sfc_leads_set_updated_at()
  RETURNS TRIGGER LANGUAGE plpgsql AS $$
BEGIN
  NEW.updated_at = now();
  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS sfc_leads_updated_at ON public.sfc_leads;
CREATE TRIGGER sfc_leads_updated_at
  BEFORE UPDATE ON public.sfc_leads
  FOR EACH ROW EXECUTE FUNCTION public.sfc_leads_set_updated_at();

-- ── 20260624000005_sync_partners_mou_from_bpa.sql ──
-- Sync partners.mou_signed from barbershop_partner_applications.mou_signed_at
--
-- The new barbershop onboarding flow writes mou_signed_at to
-- barbershop_partner_applications but does not update partners.mou_signed.
-- This causes partner/dashboard to loop approved partners back to the MOU
-- signing step even after they've completed it.
--
-- Fix 1: Backfill partners.mou_signed for existing approved partners who
--         signed via the new flow.
-- Fix 2: Add a trigger to keep them in sync going forward.

-- Step 1: Add mou_signed column to partners if it doesn't exist
ALTER TABLE public.partners
  ADD COLUMN IF NOT EXISTS mou_signed BOOLEAN NOT NULL DEFAULT false;

ALTER TABLE public.partners
  ADD COLUMN IF NOT EXISTS mou_signed_at TIMESTAMPTZ;

-- Step 2: Backfill — mark mou_signed = true for any partner whose email
--         appears in barbershop_partner_applications with a mou_signed_at value
UPDATE public.partners p
SET
  mou_signed     = true,
  mou_signed_at  = bpa.mou_signed_at,
  updated_at     = now()
FROM public.barbershop_partner_applications bpa
WHERE bpa.contact_email = p.contact_email
  AND bpa.mou_signed_at IS NOT NULL
  AND bpa.status = 'approved'
  AND p.mou_signed = false;

-- Step 3: Trigger function — when barbershop_partner_applications.mou_signed_at
--         is set, sync to partners.mou_signed
CREATE OR REPLACE FUNCTION public.sync_bpa_mou_to_partners()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  -- Only fire when mou_signed_at transitions from NULL to a value
  IF NEW.mou_signed_at IS NOT NULL AND (OLD.mou_signed_at IS NULL) THEN
    UPDATE public.partners
    SET
      mou_signed    = true,
      mou_signed_at = NEW.mou_signed_at,
      updated_at    = now()
    WHERE contact_email = NEW.contact_email;
  END IF;
  RETURN NEW;
END;
$$;

-- Step 4: Attach trigger to barbershop_partner_applications
DROP TRIGGER IF EXISTS trg_sync_bpa_mou_to_partners
  ON public.barbershop_partner_applications;

CREATE TRIGGER trg_sync_bpa_mou_to_partners
  AFTER UPDATE ON public.barbershop_partner_applications
  FOR EACH ROW
  EXECUTE FUNCTION public.sync_bpa_mou_to_partners();

-- Step 5: Also sync onboarding_completed when the new flow finishes.
--         The new flow doesn't set partners.onboarding_completed — add a
--         trigger that sets it when all required fields are present.
CREATE OR REPLACE FUNCTION public.sync_bpa_onboarding_to_partners()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  -- Consider onboarding complete when MOU is signed and employer acceptance is acknowledged
  IF NEW.mou_signed_at IS NOT NULL
     AND NEW.employer_acceptance_acknowledged = true
     AND (OLD.mou_signed_at IS NULL OR OLD.employer_acceptance_acknowledged IS DISTINCT FROM true)
  THEN
    UPDATE public.partners
    SET
      onboarding_completed = true,
      updated_at           = now()
    WHERE contact_email = NEW.contact_email;
  END IF;
  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS trg_sync_bpa_onboarding_to_partners
  ON public.barbershop_partner_applications;

CREATE TRIGGER trg_sync_bpa_onboarding_to_partners
  AFTER UPDATE ON public.barbershop_partner_applications
  FOR EACH ROW
  EXECUTE FUNCTION public.sync_bpa_onboarding_to_partners();

-- ── 20260624000006_lesson_responses.sql ──
-- lesson_responses
-- Stores student free-text responses typed inline during lessons
-- (LessonInlineInput component). One row per user × lesson × field_key.
-- field_key is a stable slug set by the lesson author (e.g. 'reading-reflection').

create table if not exists public.lesson_responses (
  id          uuid primary key default gen_random_uuid(),
  user_id     uuid not null references auth.users(id) on delete cascade,
  lesson_id   uuid not null,
  course_id   uuid not null,
  field_key   text not null,
  response_text text not null default '',
  created_at  timestamptz not null default now(),
  updated_at  timestamptz not null default now()

  -- upsert conflict target used by LessonInlineInput
  , constraint lesson_responses_user_lesson_field_key unique (user_id, lesson_id, field_key)
);

-- Learners can only read/write their own responses
alter table public.lesson_responses enable row level security;

drop policy if exists "lesson_responses: learner read own" on public.lesson_responses;
create policy "lesson_responses: learner read own" on public.lesson_responses for select
  using (auth.uid() = user_id);

drop policy if exists "lesson_responses: learner upsert own" on public.lesson_responses;
create policy "lesson_responses: learner upsert own" on public.lesson_responses for insert
  with check (auth.uid() = user_id);

drop policy if exists "lesson_responses: learner update own" on public.lesson_responses;
create policy "lesson_responses: learner update own" on public.lesson_responses for update
  using (auth.uid() = user_id);

-- Admins and instructors can read all responses (for grading / review)
drop policy if exists "lesson_responses: staff read all" on public.lesson_responses;
create policy "lesson_responses: staff read all" on public.lesson_responses for select
  using (
    exists (
      select 1 from public.profiles
      where id = auth.uid()
        and role in ('admin', 'super_admin', 'staff', 'instructor')
    )
  );

-- Index for the common lookup pattern: all responses for a lesson
create index if not exists lesson_responses_lesson_id_idx
  on public.lesson_responses (lesson_id);

-- Index for fetching all responses by a user across a course
create index if not exists lesson_responses_user_course_idx
  on public.lesson_responses (user_id, course_id);

-- ── 20260625000001_lesson_resources_column.sql ──
-- Add resources column to both lesson tables and fix lms_lessons view.
-- Previously both UNION branches returned NULL::JSONB AS resources,
-- making lesson resource attachments invisible to learners.

ALTER TABLE public.course_lessons
  ADD COLUMN IF NOT EXISTS resources JSONB NOT NULL DEFAULT '[]'::jsonb;

ALTER TABLE public.curriculum_lessons
  ADD COLUMN IF NOT EXISTS resources JSONB NOT NULL DEFAULT '[]'::jsonb;

-- Rebuild lms_lessons view with real resources from both branches.
-- Preserves all existing columns and grants.
DROP VIEW IF EXISTS public.lms_lessons;

CREATE VIEW public.lms_lessons AS

-- curriculum_lessons (priority) — published only
SELECT
  cl.id,
  cl.course_id,
  (cl.module_order * 1000 + cl.lesson_order)  AS order_index,
  cl.lesson_order                              AS lesson_number,
  cl.lesson_title                              AS title,
  cl.script_text                               AS content,
  NULL::TEXT                                   AS rendered_html,
  cl.step_type::TEXT                           AS step_type,
  cl.step_type::TEXT                           AS content_type,
  cl.lesson_slug                               AS slug,
  cl.lesson_slug                               AS lesson_slug,
  cl.passing_score,
  cl.quiz_questions,
  NULL::JSONB                                  AS activities,
  NULL::JSONB                                  AS video_config,
  cm.id                                        AS module_id,
  cm.title                                     AS module_title,
  cl.module_order,
  cl.lesson_order,
  cl.duration_minutes,
  (cl.status = 'published')                    AS is_published,
  cl.status,
  'curriculum'::TEXT                           AS lesson_source,
  cl.created_at,
  cl.updated_at,
  NULL::TEXT                                   AS partner_exam_code,
  cl.video_file                                AS video_url,
  NULL::UUID                                   AS quiz_id,
  NULL::TEXT                                   AS description,
  COALESCE(cl.resources, '[]'::jsonb)          AS resources,
  NULL::TEXT                                   AS scorm_package_id,
  NULL::TEXT                                   AS scorm_launch_path,
  cl.competency_checks
FROM public.curriculum_lessons cl
LEFT JOIN public.course_modules cm
  ON cm.course_id = cl.course_id
  AND cm.order_index = cl.module_order
WHERE cl.status = 'published'
  AND NOT EXISTS (
    SELECT 1 FROM public.course_lessons ecl
    WHERE ecl.course_id = cl.course_id
      AND ecl.slug = cl.lesson_slug
  )

UNION ALL

-- course_lessons (canonical path for non-HVAC programs)
SELECT
  cl.id,
  cl.course_id,
  cl.order_index,
  cl.order_index                               AS lesson_number,
  cl.title,
  (cl.content#>>'{}')                          AS content,
  cl.rendered_html,
  cl.lesson_type::TEXT                         AS step_type,
  cl.lesson_type::TEXT                         AS content_type,
  cl.slug,
  cl.slug                                      AS lesson_slug,
  cl.passing_score,
  cl.quiz_questions,
  cl.activities,
  cl.video_config,
  cl.module_id,
  cm.title                                     AS module_title,
  COALESCE(cm.order_index, 0)                  AS module_order,
  NULL::INTEGER                                AS lesson_order,
  NULL::INTEGER                                AS duration_minutes,
  cl.is_published,
  cl.status,
  'canonical'::TEXT                            AS lesson_source,
  cl.created_at,
  cl.updated_at,
  cl.partner_exam_code,
  cl.video_url,
  NULL::UUID                                   AS quiz_id,
  NULL::TEXT                                   AS description,
  COALESCE(cl.resources, '[]'::jsonb)          AS resources,
  NULL::TEXT                                   AS scorm_package_id,
  NULL::TEXT                                   AS scorm_launch_path,
  cl.competency_checks
FROM public.course_lessons cl
LEFT JOIN public.course_modules cm ON cm.id = cl.module_id
WHERE cl.is_published = true;

-- Restore grants
GRANT SELECT ON public.lms_lessons TO authenticated;
GRANT SELECT ON public.lms_lessons TO anon;

-- ── 20260625000002_automation_triggers.sql ──
-- Automation trigger system.
-- Defines rules that fire when conditions are met, enqueue actions into
-- automation_action_queue, and track execution history.
--
-- Trigger types:
--   stale_lead          → email reminder to assigned staff / reassign
--   compliance_alert    → escalate to super_admin after threshold
--   job_failure         → retry job or notify on-call
--   enrollment_overdue  → nudge applicant + notify admin
--   inactive_learner    → outreach email to learner
--
-- Execution: /api/admin/automations/run (called by job_queue or cron)

-- ── automation_rules ─────────────────────────────────────────────────────────
-- Defines what triggers what action under what condition.
CREATE TABLE IF NOT EXISTS public.automation_rules (
  id              uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  name            text        NOT NULL,
  description     text,
  trigger_type    text        NOT NULL,
    -- 'stale_lead' | 'compliance_alert' | 'job_failure'
    -- | 'enrollment_overdue' | 'inactive_learner'
  condition_json  jsonb       NOT NULL DEFAULT '{}',
    -- e.g. {"days_threshold": 5, "severity": "critical"}
  action_type     text        NOT NULL,
    -- 'send_email' | 'create_task' | 'reassign' | 'retry_job' | 'escalate'
  action_config   jsonb       NOT NULL DEFAULT '{}',
    -- e.g. {"template": "stale_lead_reminder", "to_role": "staff"}
  enabled         boolean     NOT NULL DEFAULT true,
  cooldown_hours  integer     NOT NULL DEFAULT 24,
    -- Minimum hours between firings for the same reference_id
  created_at      timestamptz NOT NULL DEFAULT now(),
  updated_at      timestamptz NOT NULL DEFAULT now()
);

-- NOTE: automation_rules already existed in the DB with a different schema.
-- The table uses trigger_config (not condition_json) and status (not enabled).
-- Migration applied the following ALTER to add missing columns:
--   ALTER TABLE public.automation_rules
--     ADD COLUMN IF NOT EXISTS condition_json jsonb NOT NULL DEFAULT '{}',
--     ADD COLUMN IF NOT EXISTS enabled boolean NOT NULL DEFAULT true,
--     ADD COLUMN IF NOT EXISTS cooldown_hours integer NOT NULL DEFAULT 24;

-- Seed default rules (uses both trigger_config and condition_json for compatibility)
INSERT INTO public.automation_rules
  (name, description, trigger_type, trigger_config, condition_json, action_type, action_config, cooldown_hours, enabled)
VALUES
  ('Stale lead reminder', 'Email assigned staff when a lead has no activity for 5+ days.',
   'stale_lead', '{"days_threshold": 5}', '{"days_threshold": 5}',
   'send_email', '{"template": "stale_lead_reminder", "to_role": "staff"}', 24, true),
  ('Critical compliance escalation', 'Escalate unresolved critical compliance alerts to super_admin after 24 hours.',
   'compliance_alert', '{"severity": "critical", "hours_threshold": 24}', '{"severity": "critical", "hours_threshold": 24}',
   'escalate', '{"to_role": "super_admin", "template": "compliance_escalation"}', 24, true),
  ('High compliance escalation', 'Escalate unresolved high-severity compliance alerts to admin after 72 hours.',
   'compliance_alert', '{"severity": "high", "hours_threshold": 72}', '{"severity": "high", "hours_threshold": 72}',
   'escalate', '{"to_role": "admin", "template": "compliance_escalation"}', 48, true),
  ('Failed job retry', 'Retry failed jobs up to 3 times with exponential backoff.',
   'job_failure', '{"max_attempts": 3}', '{"max_attempts": 3}',
   'retry_job', '{"backoff_minutes": [5, 15, 60]}', 1, true),
  ('Enrollment overdue nudge', 'Email applicant when their enrollment review has been pending 72+ hours.',
   'enrollment_overdue', '{"hours_threshold": 72}', '{"hours_threshold": 72}',
   'send_email', '{"template": "enrollment_pending_nudge", "to": "applicant"}', 48, true),
  ('Inactive learner outreach', 'Email learner when they have been inactive for 7+ days.',
   'inactive_learner', '{"days_threshold": 7}', '{"days_threshold": 7}',
   'send_email', '{"template": "learner_reengagement", "to": "learner"}', 72, true)
ON CONFLICT DO NOTHING;

-- ── automation_action_queue ───────────────────────────────────────────────────
-- Pending and completed automation actions.
CREATE TABLE IF NOT EXISTS public.automation_action_queue (
  id              uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  rule_id         uuid        NOT NULL REFERENCES public.automation_rules(id),
  reference_id    uuid        NOT NULL,   -- source row that triggered the rule
  reference_table text        NOT NULL,
  action_type     text        NOT NULL,
  action_config   jsonb       NOT NULL DEFAULT '{}',
  status          text        NOT NULL DEFAULT 'pending'
                              CHECK (status IN ('pending','processing','completed','failed','skipped')),
  attempts        integer     NOT NULL DEFAULT 0,
  last_error      text,
  scheduled_at    timestamptz NOT NULL DEFAULT now(),
  started_at      timestamptz,
  completed_at    timestamptz,
  created_at      timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_aaq_status_scheduled
  ON public.automation_action_queue (status, scheduled_at)
  WHERE status = 'pending';

CREATE INDEX IF NOT EXISTS idx_aaq_rule_reference
  ON public.automation_action_queue (rule_id, reference_id);

-- ── automation_execution_log ──────────────────────────────────────────────────
-- Immutable audit trail of every automation action taken.
CREATE TABLE IF NOT EXISTS public.automation_execution_log (
  id              uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  action_id       uuid        NOT NULL REFERENCES public.automation_action_queue(id),
  rule_id         uuid        NOT NULL REFERENCES public.automation_rules(id),
  reference_id    uuid        NOT NULL,
  reference_table text        NOT NULL,
  action_type     text        NOT NULL,
  outcome         text        NOT NULL CHECK (outcome IN ('success','failure','skipped')),
  detail          jsonb,
  executed_at     timestamptz NOT NULL DEFAULT now()
);

-- ── Cooldown check ────────────────────────────────────────────────────────────
-- Returns true if the rule has already fired for this reference_id within cooldown.
CREATE OR REPLACE FUNCTION public.automation_in_cooldown(
  p_rule_id      uuid,
  p_reference_id uuid
) RETURNS boolean LANGUAGE sql STABLE AS $$
  SELECT EXISTS (
    SELECT 1
    FROM public.automation_action_queue q
    JOIN public.automation_rules r ON r.id = q.rule_id
    WHERE q.rule_id      = p_rule_id
      AND q.reference_id = p_reference_id
      AND q.status IN ('pending','processing','completed')
      AND q.created_at > now() - (r.cooldown_hours || ' hours')::interval
  );
$$;

-- ── Enqueue automation actions from priority queue ────────────────────────────
-- Called by /api/admin/automations/run or a scheduled job.
CREATE OR REPLACE FUNCTION public.enqueue_automation_actions()
RETURNS integer LANGUAGE plpgsql AS $$
DECLARE
  enqueued integer := 0;
  rec      record;
BEGIN
  FOR rec IN
    SELECT
      r.id          AS rule_id,
      r.action_type,
      r.action_config,
      r.trigger_type,
      r.condition_json,
      q.reference_id,
      q.reference_table,
      q.days_overdue,
      q.severity,
      q.priority_score
    FROM public.admin_priority_queue q
    JOIN public.automation_rules r ON r.trigger_type = q.item_type
    WHERE q.resolved = false
      AND r.enabled  = true
      -- Apply condition thresholds
      AND (
        (r.trigger_type = 'stale_lead'
          AND q.days_overdue >= (r.condition_json->>'days_threshold')::integer)
        OR
        (r.trigger_type = 'compliance_alert'
          AND (r.condition_json->>'severity' IS NULL OR q.severity = r.condition_json->>'severity')
          AND q.days_overdue * 24 >= (r.condition_json->>'hours_threshold')::integer)
        OR
        (r.trigger_type = 'job_failure')
        OR
        (r.trigger_type = 'enrollment_overdue'
          AND q.days_overdue * 24 >= (r.condition_json->>'hours_threshold')::integer)
        OR
        (r.trigger_type = 'inactive_learner'
          AND q.days_overdue >= (r.condition_json->>'days_threshold')::integer)
      )
  LOOP
    -- Skip if in cooldown
    IF public.automation_in_cooldown(rec.rule_id, rec.reference_id) THEN
      CONTINUE;
    END IF;

    INSERT INTO public.automation_action_queue
      (rule_id, reference_id, reference_table, action_type, action_config)
    VALUES
      (rec.rule_id, rec.reference_id, rec.reference_table, rec.action_type, rec.action_config);

    enqueued := enqueued + 1;
  END LOOP;

  RETURN enqueued;
END;
$$;

-- ── RLS ───────────────────────────────────────────────────────────────────────
ALTER TABLE public.automation_rules          ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.automation_action_queue   ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.automation_execution_log  ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "admin_manage_automation_rules" ON public.automation_rules;
DO $$ BEGIN CREATE POLICY "admin_manage_automation_rules" ON public.automation_rules FOR ALL
  USING (EXISTS (SELECT 1 FROM public.profiles WHERE profiles.id = auth.uid() AND profiles.role IN ('admin','super_admin'))); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DROP POLICY IF EXISTS "admin_read_action_queue" ON public.automation_action_queue;
DO $$ BEGIN CREATE POLICY "admin_read_action_queue" ON public.automation_action_queue FOR SELECT
  USING (EXISTS (SELECT 1 FROM public.profiles WHERE profiles.id = auth.uid() AND profiles.role IN ('admin','super_admin','staff'))); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DROP POLICY IF EXISTS "admin_write_action_queue" ON public.automation_action_queue;
DO $$ BEGIN CREATE POLICY "admin_write_action_queue" ON public.automation_action_queue FOR ALL
  USING (EXISTS (SELECT 1 FROM public.profiles WHERE profiles.id = auth.uid() AND profiles.role IN ('admin','super_admin'))); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DROP POLICY IF EXISTS "admin_read_execution_log" ON public.automation_execution_log;
DO $$ BEGIN CREATE POLICY "admin_read_execution_log" ON public.automation_execution_log FOR SELECT
  USING (EXISTS (SELECT 1 FROM public.profiles WHERE profiles.id = auth.uid() AND profiles.role IN ('admin','super_admin','staff'))); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- ── 20260625000003_accreditation_system.sql ──
-- Accreditation tracking system.
-- Replaces the hardcoded 23-item checklist with a DB-driven evidence system.
--
-- Architecture:
--   accreditation_standards   — the checklist items (seeded with real categories)
--   accreditation_evidence    — documents/timestamps proving each standard is met
--   accreditation_reviews     — periodic review records with reviewer + score
--
-- Readiness score = completed standards / total required standards × 100
-- A standard is "complete" when it has at least one accepted evidence row.

-- ── accreditation_standards ───────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS public.accreditation_standards (
  id              uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  category        text        NOT NULL,
    -- 'Documentation' | 'Systems' | 'Compliance' | 'Student Experience'
  name            text        NOT NULL,
  description     text,
  required        boolean     NOT NULL DEFAULT true,
  evidence_types  text[]      NOT NULL DEFAULT '{}',
    -- accepted evidence types: 'document' | 'url' | 'timestamp' | 'attestation'
  admin_link      text,       -- direct admin link to manage this standard
  sort_order      integer     NOT NULL DEFAULT 0,
  created_at      timestamptz NOT NULL DEFAULT now()
);

