   '1–2 hours', 'Hardware costs + maintenance',
   ARRAY['Complete data ownership','On-premise deployment','Air-gapped environments','Custom security policies'],
   false, 3)
ON CONFLICT (slug) DO NOTHING;

-- Subscription pricing view used by /store/subscriptions
-- Joins store_products + store_prices into a flat shape the page expects
CREATE TABLE IF NOT EXISTS public.store_prices (
  id               uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  product_id       uuid NOT NULL REFERENCES public.store_products(id) ON DELETE CASCADE,
  stripe_price_id  text UNIQUE,
  interval         text NOT NULL CHECK (interval IN ('month','year','one_time')),
  amount_cents     int NOT NULL CHECK (amount_cents >= 0),
  currency         text NOT NULL DEFAULT 'usd',
  trial_period_days int,
  active           boolean NOT NULL DEFAULT true,
  created_at       timestamptz NOT NULL DEFAULT now()
);

-- RLS: deployment_options is public read
ALTER TABLE public.deployment_options ENABLE ROW LEVEL SECURITY;
DROP policy if exists "deployment_options_public_read" on public.deployment_options;
CREATE policy "deployment_options_public_read" on public.deployment_options FOR SELECT USING (true);

-- RLS: store_prices readable by authenticated users
ALTER TABLE public.store_prices ENABLE ROW LEVEL SECURITY;
DROP policy if exists "store_prices_authenticated_read" on public.store_prices;
CREATE policy "store_prices_authenticated_read" on public.store_prices FOR SELECT TO authenticated USING (true);

-- View: joins store_products + store_prices
CREATE OR REPLACE VIEW public.store_subscription_pricing AS
SELECT
  sp.id                                                        AS product_id,
  sp.name                                                      AS product_name,
  sp.description,
  '{}'::jsonb                                                   AS features,
  spr.id                                                       AS price_id,
  spr.stripe_price_id,
  spr.interval,
  spr.amount_cents,
  ROUND((spr.amount_cents / 100.0)::numeric, 2)                AS amount_dollars,
  CASE spr.interval
    WHEN 'month' THEN 'Monthly'
    WHEN 'year'  THEN 'Annual'
    ELSE initcap(spr.interval)
  END                                                          AS billing_period,
  CASE spr.interval
    WHEN 'year'  THEN ROUND((spr.amount_cents / 100.0 / 12)::numeric, 2)
    ELSE ROUND((spr.amount_cents / 100.0)::numeric, 2)
  END                                                          AS effective_monthly_price,
  spr.trial_period_days
FROM public.store_products sp
JOIN public.store_prices spr ON spr.product_id = sp.id
WHERE sp.status = 'active'
  AND spr.active = true
  AND sp.status = 'active'
ORDER BY spr.amount_cents ASC;

-- ── 20260625000008_student_hour_summary.sql ──
-- student_hour_summary view
-- Per-student breakdown of theory (RTI), lab (OJL), and field (host_shop) hours.
-- Sources: hour_entries (source_type) + progress_entries (verified OJL hours).

CREATE OR REPLACE VIEW public.student_hour_summary AS
SELECT
  he.user_id                                                          AS student_id,
  SUM(CASE WHEN he.source_type = 'rti'       THEN COALESCE(he.hours_claimed, 0) ELSE 0 END) AS theory_hours,
  SUM(CASE WHEN he.source_type = 'ojl'       THEN COALESCE(he.hours_claimed, 0) ELSE 0 END) AS lab_hours,
  SUM(CASE WHEN he.source_type = 'host_shop' THEN COALESCE(he.hours_claimed, 0) ELSE 0 END) AS field_hours,
  SUM(CASE WHEN he.source_type = 'timeclock' THEN COALESCE(he.hours_claimed, 0) ELSE 0 END) AS timeclock_hours,
  SUM(COALESCE(he.hours_claimed, 0))                                  AS total_claimed_hours,
  SUM(CASE WHEN he.status = 'approved'       THEN COALESCE(he.hours_claimed, 0) ELSE 0 END) AS total_approved_hours,
  SUM(CASE WHEN he.status IN ('pending', 'submitted') THEN COALESCE(he.hours_claimed, 0) ELSE 0 END) AS total_pending_hours,
  COUNT(*)                                                            AS entry_count
FROM public.hour_entries he
WHERE he.user_id IS NOT NULL
GROUP BY he.user_id;

GRANT SELECT ON public.student_hour_summary TO authenticated;

-- Also expose verified OJL hours from progress_entries for barber apprentices
CREATE OR REPLACE VIEW public.apprentice_hour_summary AS
SELECT
  pe.apprentice_id                                                    AS student_id,
  SUM(CASE WHEN pe.status = 'verified' THEN COALESCE(pe.hours_worked, 0) ELSE 0 END) AS verified_hours,
  SUM(CASE WHEN pe.status = 'submitted' THEN COALESCE(pe.hours_worked, 0) ELSE 0 END) AS pending_hours,
  SUM(COALESCE(pe.hours_worked, 0))                                   AS total_hours,
  COUNT(*)                                                            AS entry_count
FROM public.progress_entries pe
WHERE pe.apprentice_id IS NOT NULL
GROUP BY pe.apprentice_id;

GRANT SELECT ON public.apprentice_hour_summary TO authenticated;

-- ── 20260625000009_video_jobs.sql ──
-- Video generation job queue.
--
-- video_jobs tracks async render jobs submitted from the admin course builder.
-- The LMS Railway service owns rendering; admin calls POST /api/videos/generate
-- and polls GET /api/videos/status/:job_id until status = 'complete'.
--
-- course_lessons gets lightweight video tracking columns (video_job_id,
-- video_error, video_generated_at) to complement video_url and video_status
-- added in migration 20260625000005.

-- ── video_jobs table ──────────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS public.video_jobs (
  id                UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  lesson_id         UUID        NOT NULL REFERENCES public.course_lessons(id) ON DELETE CASCADE,
  course_id         UUID        NOT NULL REFERENCES public.courses(id)        ON DELETE CASCADE,
  status            TEXT        NOT NULL DEFAULT 'queued'
    CHECK (status IN ('draft', 'queued', 'rendering', 'complete', 'failed')),
  video_url         TEXT,
  audio_url         TEXT,
  error_message     TEXT,
  scene_count       INTEGER,
  duration_seconds  INTEGER,
  -- Metadata stored at job creation for reproducibility
  lesson_title      TEXT        NOT NULL,
  script            TEXT,
  bullet_points     JSONB       DEFAULT '[]'::jsonb,
  scene_data        JSONB,
  -- Timing
  queued_at         TIMESTAMPTZ NOT NULL DEFAULT now(),
  started_at        TIMESTAMPTZ,
  completed_at      TIMESTAMPTZ,
  created_at        TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at        TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_video_jobs_lesson_id_v2 ON public.video_jobs(lesson_id);
CREATE INDEX IF NOT EXISTS idx_video_jobs_status_v2    ON public.video_jobs(status);
CREATE INDEX IF NOT EXISTS idx_video_jobs_course_id_v2 ON public.video_jobs(course_id);

COMMENT ON TABLE public.video_jobs IS
  'Async video render jobs. LMS Railway service processes these; admin polls for status.';

