-- ── RLS ───────────────────────────────────────────────────────────────────────

ALTER TABLE public.video_jobs ENABLE ROW LEVEL SECURITY;

-- Admins and staff can read/write all jobs
DROP policy if exists "admin_full_access" on public.video_jobs;
DROP policy if exists "admin_full_access" on public.video_jobs;
