-- ── 20260626000001_workforce_referrals_full_schema.sql ──
-- Replaces the 5-column stub in baseline_untracked_tables with the full schema
-- that the workforce-referral API route actually writes.
-- Safe to run against a DB that already has the stub (ALTER ADD COLUMN IF NOT EXISTS).

-- 1. Add all missing columns to the existing table
ALTER TABLE public.workforce_referrals
  ADD COLUMN IF NOT EXISTS user_id           uuid REFERENCES auth.users(id) ON DELETE SET NULL,
  ADD COLUMN IF NOT EXISTS application_id    uuid REFERENCES public.applications(id) ON DELETE SET NULL,
  ADD COLUMN IF NOT EXISTS enrollment_id     uuid REFERENCES public.training_enrollments(id) ON DELETE SET NULL,

  -- Agency / case manager
  ADD COLUMN IF NOT EXISTS agency_name       text NOT NULL DEFAULT '',
  ADD COLUMN IF NOT EXISTS agency_type       text NOT NULL DEFAULT 'other'
    CHECK (agency_type IN (
      'american_job_center','workforce_board','vocational_rehabilitation',
      'wioa','jri','snap_et','fssa','other'
    )),
  ADD COLUMN IF NOT EXISTS case_manager_name  text,
  ADD COLUMN IF NOT EXISTS case_manager_email text,
  ADD COLUMN IF NOT EXISTS case_manager_phone text,

  -- Participant (denormalised for audit trail — survives user deletion)
  ADD COLUMN IF NOT EXISTS participant_name  text,
  ADD COLUMN IF NOT EXISTS participant_email text,

  -- Funding
  ADD COLUMN IF NOT EXISTS funding_type      text,
  ADD COLUMN IF NOT EXISTS voucher_number    text,
  ADD COLUMN IF NOT EXISTS funding_amount    numeric(10,2),
  ADD COLUMN IF NOT EXISTS funding_approved  boolean NOT NULL DEFAULT false,
  ADD COLUMN IF NOT EXISTS funding_approved_at timestamptz,
  ADD COLUMN IF NOT EXISTS funding_approved_by uuid REFERENCES auth.users(id) ON DELETE SET NULL,

  -- Referral lifecycle
  ADD COLUMN IF NOT EXISTS referral_date     timestamptz NOT NULL DEFAULT now(),
  ADD COLUMN IF NOT EXISTS contact_sent      boolean NOT NULL DEFAULT false,
  ADD COLUMN IF NOT EXISTS contact_sent_at   timestamptz,
  ADD COLUMN IF NOT EXISTS partner_acknowledged boolean NOT NULL DEFAULT false,
  ADD COLUMN IF NOT EXISTS partner_acknowledged_at timestamptz,

  -- Status (extends the existing status text column)
  ADD COLUMN IF NOT EXISTS status_update_email_enabled boolean NOT NULL DEFAULT true,
  ADD COLUMN IF NOT EXISTS last_status_update_sent_at  timestamptz,

  -- Case notes (required for FSSA/WIOA audits)
  ADD COLUMN IF NOT EXISTS case_notes        text,

  -- Soft-delete
  ADD COLUMN IF NOT EXISTS archived          boolean NOT NULL DEFAULT false;

-- 2. Tighten the status column to the values the API actually uses
--    (existing rows default to 'referred' if status is null)
UPDATE public.workforce_referrals
  SET status = 'referred'
  WHERE status IS NULL OR status NOT IN (
    'referred','intake_started','enrolled','active','completed','withdrawn','cancelled'
  );

ALTER TABLE public.workforce_referrals
  DROP CONSTRAINT IF EXISTS workforce_referrals_status_check;

ALTER TABLE public.workforce_referrals
  ADD CONSTRAINT workforce_referrals_status_check
  CHECK (status IN (
    'referred','intake_started','enrolled','active','completed','withdrawn','cancelled'
  ));

ALTER TABLE public.workforce_referrals
  ALTER COLUMN status SET NOT NULL,
  ALTER COLUMN status SET DEFAULT 'referred';

-- 3. Primary key (baseline stub may not have one)
DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_constraint
    WHERE conrelid = 'public.workforce_referrals'::regclass
      AND contype = 'p'
  ) THEN
    ALTER TABLE public.workforce_referrals ADD PRIMARY KEY (id);
  END IF;
END $$;

-- 4. Indexes for the query patterns in the API route
CREATE INDEX IF NOT EXISTS idx_workforce_referrals_user_id
  ON public.workforce_referrals(user_id);

CREATE INDEX IF NOT EXISTS idx_workforce_referrals_application_id
  ON public.workforce_referrals(application_id);

CREATE INDEX IF NOT EXISTS idx_workforce_referrals_agency_type
  ON public.workforce_referrals(agency_type);

CREATE INDEX IF NOT EXISTS idx_workforce_referrals_status
  ON public.workforce_referrals(status);

CREATE INDEX IF NOT EXISTS idx_workforce_referrals_referral_date
  ON public.workforce_referrals(referral_date DESC);

-- 5. updated_at trigger (reuse existing helper if present, else create)
CREATE OR REPLACE FUNCTION public.set_updated_at()
RETURNS trigger LANGUAGE plpgsql AS $$
BEGIN
  NEW.updated_at = now();
  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS trg_workforce_referrals_updated_at ON public.workforce_referrals;
CREATE TRIGGER trg_workforce_referrals_updated_at
  BEFORE UPDATE ON public.workforce_referrals
  FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();

-- 6. RLS
ALTER TABLE public.workforce_referrals ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "workforce_referrals_admin_all" ON public.workforce_referrals;
DO $$ BEGIN CREATE POLICY "workforce_referrals_admin_all" ON public.workforce_referrals
  FOR ALL
  TO authenticated
  USING (
    EXISTS (
      SELECT 1 FROM public.profiles
      WHERE id = auth.uid()
        AND role IN ('admin','super_admin','advisor','staff')
    )
  ); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DROP POLICY IF EXISTS "workforce_referrals_own_read" ON public.workforce_referrals;
DO $$ BEGIN CREATE POLICY "workforce_referrals_own_read" ON public.workforce_referrals
  FOR SELECT
  TO authenticated
  USING (user_id = auth.uid()); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- ── 20260626000002_agency_referral_confirmations.sql ──
-- Partner acknowledgment log for workforce referrals.
-- Every time a partner confirms receipt of a referral (or fails to),
-- a row is written here. This is the audit trail agencies ask for.
--
-- Answers: "Did the partner confirm they received this referral?"
-- Required for FSSA/WIOA audits — a referral without confirmation is not valid.

CREATE TABLE IF NOT EXISTS public.agency_referral_confirmations (
  id                  uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  referral_id         uuid NOT NULL REFERENCES public.workforce_referrals(id) ON DELETE CASCADE,

  -- Who confirmed (partner contact or staff recording the confirmation)
  confirmed_by_name   text,
  confirmed_by_email  text,
  confirmed_by_phone  text,
  recorded_by         uuid REFERENCES auth.users(id) ON DELETE SET NULL,

  -- What was confirmed
  confirmation_method text NOT NULL DEFAULT 'email'
    CHECK (confirmation_method IN ('email','phone','portal','in_person','fax','other')),
  confirmation_type   text NOT NULL DEFAULT 'receipt'
    CHECK (confirmation_type IN (
      'receipt',          -- partner confirmed they received the referral
      'enrollment',       -- partner confirmed participant enrolled
      'attendance',       -- partner confirmed attendance/participation
      'completion',       -- partner confirmed program completion
      'placement',        -- partner confirmed job placement
      'no_show',          -- partner reported participant did not show
      'declined',         -- partner declined the referral
      'unable_to_reach'   -- partner could not be reached (logged for follow-up)
    )),

  -- Outcome data (populated for enrollment/completion/placement types)
  enrollment_date     date,
  completion_date     date,
  placement_date      date,
  employer_name       text,
  job_title           text,
  hourly_wage         numeric(8,2),

  -- Notes (required for audit — case managers must document every contact)
  notes               text,

  -- Follow-up tracking
  follow_up_required  boolean NOT NULL DEFAULT false,
  follow_up_due_date  date,
  follow_up_completed boolean NOT NULL DEFAULT false,

  confirmed_at        timestamptz NOT NULL DEFAULT now(),
  created_at          timestamptz NOT NULL DEFAULT now(),
  updated_at          timestamptz NOT NULL DEFAULT now()
);

-- When a confirmation of type 'receipt' is inserted, mark the referral as acknowledged
CREATE OR REPLACE FUNCTION public.sync_referral_acknowledgment()
RETURNS trigger LANGUAGE plpgsql AS $$
BEGIN
  IF NEW.confirmation_type = 'receipt' THEN
    UPDATE public.workforce_referrals
    SET
      partner_acknowledged     = true,
      partner_acknowledged_at  = NEW.confirmed_at,
      updated_at               = now()
    WHERE id = NEW.referral_id;
  END IF;

  -- Advance referral status based on confirmation type
  UPDATE public.workforce_referrals
  SET
    status = CASE NEW.confirmation_type
      WHEN 'enrollment'  THEN 'enrolled'
      WHEN 'completion'  THEN 'completed'
      WHEN 'no_show'     THEN 'withdrawn'
      WHEN 'declined'    THEN 'cancelled'
      ELSE status  -- receipt / attendance / placement / unable_to_reach don't change status
    END,
    updated_at = now()
  WHERE id = NEW.referral_id
    AND (
      -- only advance, never regress
      CASE NEW.confirmation_type
        WHEN 'enrollment' THEN status IN ('referred','intake_started')
        WHEN 'completion' THEN status IN ('referred','intake_started','enrolled','active')
        WHEN 'no_show'    THEN status NOT IN ('completed','withdrawn','cancelled')
        WHEN 'declined'   THEN status NOT IN ('completed','withdrawn','cancelled')
        ELSE false
      END
    );

  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS trg_sync_referral_acknowledgment ON public.agency_referral_confirmations;
CREATE TRIGGER trg_sync_referral_acknowledgment
  AFTER INSERT ON public.agency_referral_confirmations
  FOR EACH ROW EXECUTE FUNCTION public.sync_referral_acknowledgment();

-- updated_at
DROP TRIGGER IF EXISTS trg_agency_referral_confirmations_updated_at ON public.agency_referral_confirmations;
CREATE TRIGGER trg_agency_referral_confirmations_updated_at
  BEFORE UPDATE ON public.agency_referral_confirmations
  FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();

-- Indexes
CREATE INDEX IF NOT EXISTS idx_arc_referral_id
  ON public.agency_referral_confirmations(referral_id);

CREATE INDEX IF NOT EXISTS idx_arc_confirmation_type
  ON public.agency_referral_confirmations(confirmation_type);

CREATE INDEX IF NOT EXISTS idx_arc_follow_up
  ON public.agency_referral_confirmations(follow_up_required, follow_up_completed, follow_up_due_date)
  WHERE follow_up_required = true AND follow_up_completed = false;

-- RLS
ALTER TABLE public.agency_referral_confirmations ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "arc_admin_all" ON public.agency_referral_confirmations;
DO $$ BEGIN CREATE POLICY "arc_admin_all" ON public.agency_referral_confirmations
  FOR ALL
  TO authenticated
  USING (
    EXISTS (
      SELECT 1 FROM public.profiles
      WHERE id = auth.uid()
        AND role IN ('admin','super_admin','advisor','staff')
    )
  ); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- View: referral pipeline summary used by the admin dashboard
DROP VIEW IF EXISTS public.referral_pipeline_summary;
CREATE VIEW public.referral_pipeline_summary AS
SELECT
  wr.id,
  wr.application_id,
  wr.enrollment_id,
  wr.participant_name,
  wr.participant_email,
  wr.agency_name,
  wr.agency_type,
  wr.case_manager_name,
  wr.case_manager_email,
  wr.funding_type,
  wr.voucher_number,
  wr.status,
  wr.referral_date,
  wr.partner_acknowledged,
  wr.partner_acknowledged_at,
  wr.funding_approved,
  wr.funding_approved_at,
  wr.contact_sent,
  wr.case_notes,
  -- Days since referral (SLA tracking)
  EXTRACT(DAY FROM now() - wr.referral_date)::int AS days_since_referral,
  -- Latest confirmation
  latest.confirmation_type  AS latest_confirmation_type,
  latest.confirmed_at       AS latest_confirmation_at,
  latest.notes              AS latest_confirmation_notes,
  -- Outcome data from latest placement confirmation
  placement.employer_name,
  placement.job_title,
  placement.hourly_wage,
  placement.placement_date,
  -- Linked application status
  a.status                  AS application_status,
  a.eligibility_status,
  a.has_workone_approval,
  a.workone_approval_ref,
  -- Linked enrollment
  te.status                 AS enrollment_status,
  te.program_id
FROM public.workforce_referrals wr
LEFT JOIN LATERAL (
  SELECT confirmation_type, confirmed_at, notes
  FROM public.agency_referral_confirmations
  WHERE referral_id = wr.id
  ORDER BY confirmed_at DESC
  LIMIT 1
) latest ON true
LEFT JOIN LATERAL (
  SELECT employer_name, job_title, hourly_wage, placement_date
  FROM public.agency_referral_confirmations
  WHERE referral_id = wr.id
    AND confirmation_type = 'placement'
  ORDER BY confirmed_at DESC
  LIMIT 1
) placement ON true
LEFT JOIN public.applications a ON a.id = wr.application_id
LEFT JOIN public.training_enrollments te ON te.id = wr.enrollment_id
WHERE wr.archived = false;

COMMENT ON VIEW public.referral_pipeline_summary IS
  'Denormalised referral pipeline for admin dashboard. One row per referral with latest confirmation and linked application/enrollment status.';

-- ── 20260626000003_wioa_pirl_exports_full_schema.sql ──
-- Adds missing columns to the live wioa_pirl_exports table so the
-- admin PIRL export UI can track job status, validation results, and downloads.
-- The live table has: id, schema_id, quarter, fiscal_year, status, record_count,
-- file_url, errors, exported_by, exported_at, created_at
-- We add: error_count, warning_count, checksum_sha256, file_path, report_json,
--         created_by, started_at, completed_at

ALTER TABLE public.wioa_pirl_exports
  ADD COLUMN IF NOT EXISTS error_count      integer NOT NULL DEFAULT 0,
  ADD COLUMN IF NOT EXISTS warning_count    integer NOT NULL DEFAULT 0,
  ADD COLUMN IF NOT EXISTS checksum_sha256  text,
  ADD COLUMN IF NOT EXISTS file_path        text,
  ADD COLUMN IF NOT EXISTS report_json      jsonb,
  ADD COLUMN IF NOT EXISTS created_by       uuid REFERENCES auth.users(id) ON DELETE SET NULL,
  ADD COLUMN IF NOT EXISTS started_at       timestamptz,
  ADD COLUMN IF NOT EXISTS completed_at     timestamptz;

-- Normalise status values (live DB may have nulls)
UPDATE public.wioa_pirl_exports
  SET status = 'completed'
  WHERE status IS NULL AND file_url IS NOT NULL;

UPDATE public.wioa_pirl_exports
  SET status = 'pending'
  WHERE status IS NULL;

-- Tighten status constraint
ALTER TABLE public.wioa_pirl_exports
  DROP CONSTRAINT IF EXISTS wioa_pirl_exports_status_check;

ALTER TABLE public.wioa_pirl_exports
  ADD CONSTRAINT wioa_pirl_exports_status_check
  CHECK (status IN ('pending','running','completed','failed'));

-- wioa_pirl_export_issues: add field_name if missing (live may have issue_type)
ALTER TABLE public.wioa_pirl_export_issues
  ADD COLUMN IF NOT EXISTS field_name text;

-- Backfill field_name from issue_type if that column exists
DO $$
BEGIN
  IF EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema = 'public'
      AND table_name   = 'wioa_pirl_export_issues'
      AND column_name  = 'issue_type'
  ) THEN
    UPDATE public.wioa_pirl_export_issues
      SET field_name = issue_type
      WHERE field_name IS NULL;
  END IF;
END $$;

-- Index for fast issue lookup by export
CREATE INDEX IF NOT EXISTS idx_wioa_pirl_export_issues_export_id
  ON public.wioa_pirl_export_issues(export_id);

-- RLS: admin-only
ALTER TABLE public.wioa_pirl_exports ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.wioa_pirl_export_issues ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "pirl_exports_admin_all" ON public.wioa_pirl_exports;
DO $$ BEGIN CREATE POLICY "pirl_exports_admin_all" ON public.wioa_pirl_exports FOR ALL TO authenticated
  USING (
    EXISTS (
      SELECT 1 FROM public.profiles
      WHERE id = auth.uid() AND role IN ('admin','super_admin','staff')
    )
  ); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DROP POLICY IF EXISTS "pirl_export_issues_admin_all" ON public.wioa_pirl_export_issues;
DO $$ BEGIN CREATE POLICY "pirl_export_issues_admin_all" ON public.wioa_pirl_export_issues FOR ALL TO authenticated
  USING (
    EXISTS (
      SELECT 1 FROM public.profiles
      WHERE id = auth.uid() AND role IN ('admin','super_admin','staff')
    )
