-- ── 20260626000004_individual_employment_plans_full_schema.sql ──
-- Adds columns the /api/wioa/iep route writes that are absent from the
-- baseline stub. The live table uses text[] arrays; we add the JSONB/text
-- columns the API expects alongside the existing ones.

ALTER TABLE public.individual_employment_plans
  -- API writes user_id (not participant_id) — add as alias FK
  ADD COLUMN IF NOT EXISTS user_id              uuid REFERENCES auth.users(id) ON DELETE SET NULL,

  -- API column names that differ from baseline stub
  ADD COLUMN IF NOT EXISTS career_goal          text,
  ADD COLUMN IF NOT EXISTS employment_goal      text,
  ADD COLUMN IF NOT EXISTS education_level      text,
  ADD COLUMN IF NOT EXISTS work_experience      jsonb NOT NULL DEFAULT '[]',
  ADD COLUMN IF NOT EXISTS skills               jsonb NOT NULL DEFAULT '[]',
  ADD COLUMN IF NOT EXISTS barriers             jsonb NOT NULL DEFAULT '[]',
  ADD COLUMN IF NOT EXISTS strengths            jsonb NOT NULL DEFAULT '[]',
  ADD COLUMN IF NOT EXISTS training_needs       jsonb NOT NULL DEFAULT '[]',
  ADD COLUMN IF NOT EXISTS support_services_needed jsonb NOT NULL DEFAULT '[]',
  ADD COLUMN IF NOT EXISTS target_occupation    text,
  ADD COLUMN IF NOT EXISTS target_industry      text,
  ADD COLUMN IF NOT EXISTS target_wage          numeric(8,2),
  ADD COLUMN IF NOT EXISTS target_completion_date date,
  ADD COLUMN IF NOT EXISTS milestones           jsonb NOT NULL DEFAULT '[]',
  ADD COLUMN IF NOT EXISTS status               text NOT NULL DEFAULT 'draft'
    CHECK (status IN ('draft','active','completed','cancelled')),
  ADD COLUMN IF NOT EXISTS notes                text,

  -- Case manager / reviewer
  ADD COLUMN IF NOT EXISTS case_manager_id      uuid REFERENCES auth.users(id) ON DELETE SET NULL,
  ADD COLUMN IF NOT EXISTS reviewed_at          timestamptz,
  ADD COLUMN IF NOT EXISTS review_notes         text,

  -- Linked WIOA participant record
  ADD COLUMN IF NOT EXISTS wioa_participant_id  uuid REFERENCES public.wioa_participants(id) ON DELETE SET NULL;

-- Backfill user_id from participant_id where possible
UPDATE public.individual_employment_plans iep
  SET user_id = wp.user_id
  FROM public.wioa_participants wp
  WHERE iep.participant_id = wp.id
    AND iep.user_id IS NULL;

-- Primary key guard
DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_constraint
    WHERE conrelid = 'public.individual_employment_plans'::regclass
      AND contype = 'p'
  ) THEN
    ALTER TABLE public.individual_employment_plans ADD PRIMARY KEY (id);
  END IF;
END $$;

-- Indexes
CREATE INDEX IF NOT EXISTS idx_iep_user_id
  ON public.individual_employment_plans(user_id);

CREATE INDEX IF NOT EXISTS idx_iep_participant_id
  ON public.individual_employment_plans(participant_id);

CREATE INDEX IF NOT EXISTS idx_iep_status
  ON public.individual_employment_plans(status);

CREATE INDEX IF NOT EXISTS idx_iep_case_manager_id
  ON public.individual_employment_plans(case_manager_id);

-- updated_at trigger
DROP TRIGGER IF EXISTS trg_iep_updated_at ON public.individual_employment_plans;
CREATE TRIGGER trg_iep_updated_at
  BEFORE UPDATE ON public.individual_employment_plans
  FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();

-- RLS
ALTER TABLE public.individual_employment_plans ENABLE ROW LEVEL SECURITY;

-- Admin / staff: full access
DROP POLICY IF EXISTS "iep_admin_all" ON public.individual_employment_plans;
DO $$ BEGIN CREATE POLICY "iep_admin_all" ON public.individual_employment_plans FOR ALL TO authenticated
  USING (
    EXISTS (
      SELECT 1 FROM public.profiles
      WHERE id = auth.uid()
        AND role IN ('admin','super_admin','staff','advisor')
    )
  ); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- Participant: read own IEPs only
DROP POLICY IF EXISTS "iep_own_read" ON public.individual_employment_plans;
DO $$ BEGIN CREATE POLICY "iep_own_read" ON public.individual_employment_plans FOR SELECT TO authenticated
  USING (user_id = auth.uid()); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- ── 20260626000005_fssa_participants_exit_columns.sql ──
-- Adds exit interview and follow-up tracking columns to fssa_participants.
-- Required for FSSA TPP reporting: credential attainment, Q2/Q4 follow-up
-- employment status, wages, and exit case notes.

ALTER TABLE public.fssa_participants
  -- Credential / training outcome
  ADD COLUMN IF NOT EXISTS credential_attained        boolean,
  ADD COLUMN IF NOT EXISTS credential_name            text,
  ADD COLUMN IF NOT EXISTS credential_issued_date     date,

  -- Exit documentation
  ADD COLUMN IF NOT EXISTS exit_notes                 text,
  ADD COLUMN IF NOT EXISTS exit_recorded_by           uuid REFERENCES auth.users(id) ON DELETE SET NULL,

  -- ABAWD tracking
  ADD COLUMN IF NOT EXISTS abawd_exempt               boolean NOT NULL DEFAULT false,
  ADD COLUMN IF NOT EXISTS abawd_exemption_reason     text,

  -- Q2 follow-up (approx 6 months post-exit)
  ADD COLUMN IF NOT EXISTS q2_follow_up_date          date,
  ADD COLUMN IF NOT EXISTS q2_follow_up_completed     boolean NOT NULL DEFAULT false,
  ADD COLUMN IF NOT EXISTS q2_employed                boolean,
  ADD COLUMN IF NOT EXISTS q2_employer_name           text,
  ADD COLUMN IF NOT EXISTS q2_hourly_wage             numeric(8,2),
  ADD COLUMN IF NOT EXISTS q2_hours_per_week          int,
  ADD COLUMN IF NOT EXISTS q2_notes                   text,

  -- Q4 follow-up (approx 12 months post-exit)
  ADD COLUMN IF NOT EXISTS q4_follow_up_date          date,
  ADD COLUMN IF NOT EXISTS q4_follow_up_completed     boolean NOT NULL DEFAULT false,
  ADD COLUMN IF NOT EXISTS q4_employed                boolean,
  ADD COLUMN IF NOT EXISTS q4_employer_name           text,
  ADD COLUMN IF NOT EXISTS q4_hourly_wage             numeric(8,2),
  ADD COLUMN IF NOT EXISTS q4_hours_per_week          int,
  ADD COLUMN IF NOT EXISTS q4_notes                   text;

-- Auto-schedule Q2/Q4 follow-up dates when a participant exits
CREATE OR REPLACE FUNCTION public.schedule_fssa_followups()
RETURNS trigger LANGUAGE plpgsql AS $$
BEGIN
  -- Only fire when enrollment_status transitions to 'exited' or 'completed'
  IF NEW.enrollment_status IN ('exited', 'completed')
     AND (OLD.enrollment_status IS DISTINCT FROM NEW.enrollment_status)
     AND NEW.snap_et_exited_at IS NOT NULL
  THEN
    NEW.q2_follow_up_date := (NEW.snap_et_exited_at::date + INTERVAL '6 months')::date;
    NEW.q4_follow_up_date := (NEW.snap_et_exited_at::date + INTERVAL '12 months')::date;
  END IF;
  RETURN NEW;
END;
$$;

DROP TRIGGER IF EXISTS trg_fssa_schedule_followups ON public.fssa_participants;
CREATE TRIGGER trg_fssa_schedule_followups
  BEFORE UPDATE ON public.fssa_participants
  FOR EACH ROW EXECUTE FUNCTION public.schedule_fssa_followups();

-- Index for follow-up queue (staff need to see who is due)
CREATE INDEX IF NOT EXISTS idx_fssa_participants_q2_followup
  ON public.fssa_participants(q2_follow_up_date)
  WHERE q2_follow_up_completed = false AND q2_follow_up_date IS NOT NULL;

CREATE INDEX IF NOT EXISTS idx_fssa_participants_q4_followup
  ON public.fssa_participants(q4_follow_up_date)
  WHERE q4_follow_up_completed = false AND q4_follow_up_date IS NOT NULL;

-- ── 20260626000006_applications_status_fix.sql ──
-- Restore pending_funding and pending_admin_review to applications.status CHECK constraint.
--
-- These values were added in 20260425000001 but dropped by 20260430000010 and
-- 20260503000008. The /api/applications route inserts both values for funded
-- applicants (WIOA/WRG/FSSA), causing a CHECK violation and the user-visible
-- "Failed to save application" error on the HVAC apply page.
--
-- Full canonical status set after this migration:
--   submitted            → initial submission (self-pay / employer / unsure)
--   pending_funding      → funded applicant who has not yet been to ICC
--   pending_admin_review → funded applicant with ICC in process — awaiting staff review
--   pending_workone      → awaiting WorkOne eligibility confirmation
--   scheduled            → consultation booked
--   in_review            → staff reviewing
--   under_review         → alias used by some admin routes
--   attended_orientation → orientation complete
--   ready_to_enroll      → cleared for enrollment
--   approved             → approved for enrollment
--   rejected             → application rejected
--   enrolled             → actively enrolled
--   active_apprentice    → in apprenticeship program
--   assigned             → placed with employer/shop
--   completed            → program complete
--   placed               → employed post-completion
--   retained             → retained at 2nd quarter (WIOA metric)
--   waitlisted           → on waitlist
--   withdrawn            → voluntarily left
--   exited               → formally exited (WIOA exit)
--   funding_review       → funding verification in progress (legacy)

ALTER TABLE public.applications
  DROP CONSTRAINT IF EXISTS applications_valid_status,
  DROP CONSTRAINT IF EXISTS applications_status_check;

ALTER TABLE public.applications
  ADD CONSTRAINT applications_status_check CHECK (status = ANY (ARRAY[
    'submitted',
    'pending_funding',
    'pending_admin_review',
    'pending_workone',
    'funding_review',
    'scheduled',
    'in_review',
    'under_review',
    'attended_orientation',
    'ready_to_enroll',
    'approved',
    'rejected',
    'enrolled',
    'active_apprentice',
    'assigned',
    'completed',
    'placed',
    'retained',
    'waitlisted',
    'withdrawn',
    'exited'
  ]::text[]));

-- ── 20260626000007_job_postings_rls.sql ──
-- Fix RLS on job_postings and job_applications.
--
-- Previous policies allowed any authenticated user to read all rows
-- (auth_read_job_postings / auth_read_job_applications with qual=true).
-- Replaced with employer-scoped policies so each employer only sees their own data.

-- job_postings: employers own their postings; public sees active only
DROP POLICY IF EXISTS auth_read_job_postings  ON public.job_postings;
DROP POLICY IF EXISTS job_public_policy       ON public.job_postings;

DO $$ BEGIN CREATE POLICY employer_own_postings ON public.job_postings
  FOR ALL
  USING  (employer_id = auth.uid())
  WITH CHECK (employer_id = auth.uid()); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DO $$ BEGIN CREATE POLICY public_active_jobs ON public.job_postings
  FOR SELECT
  USING (status = 'active'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- job_applications: applicants own their rows; employers see apps for their jobs only
DROP POLICY IF EXISTS auth_read_job_applications          ON public.job_applications;
DROP POLICY IF EXISTS "Users can manage own applications" ON public.job_applications;
DROP POLICY IF EXISTS application_user_policy             ON public.job_applications;

DO $$ BEGIN CREATE POLICY applicant_own ON public.job_applications
  FOR ALL
  USING  (student_id = auth.uid())
  WITH CHECK (student_id = auth.uid()); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

DO $$ BEGIN CREATE POLICY employer_see_own_job_apps ON public.job_applications
  FOR SELECT
  USING (
    job_posting_id IN (
      SELECT id FROM public.job_postings WHERE employer_id = auth.uid()
    )
  ); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

