  'practical_requirements','priority_scores','product_clones',
  'product_page_views','program_banner_views','program_discussion_replies',
  'program_discussions','program_holder_banking','provisioning_jobs',
  'public_ai_tutor_logs','refund_advance_applications','reporting_completions',
  'reporting_enrollments','reporting_funding','reporting_progress',
  'reporting_verdicts','resumes','rise_participants','sam_alerts',
  'scorm_attempts','scorm_cmi_data','script_acknowledgments','script_deviations',
  'search_analytics','security_logs','seller_applications','shop_checkin_codes',
  'shop_profiles','shop_weekly_reports','skills_checklist','social_media_campaigns',
  'social_posts','staff','staff_notifications','store_entitlements',
  'store_subscriptions','studio_deployments','study_sessions',
  'sub_office_agreements','support_sessions','tax_filing_applications',
  'tax_return_events','tenant_compliance_records','testing_slots',
  'transmission_statuses','web_vitals','webhook_logs'
]; BEGIN FOREACH t IN ARRAY tables LOOP
  IF EXISTS (SELECT 1 FROM information_schema.tables WHERE table_schema='public' AND table_name=t) THEN
    EXECUTE format('ALTER TABLE public.%I ENABLE ROW LEVEL SECURITY', t);
    EXECUTE format('DROP POLICY IF EXISTS admin_all ON public.%I', t);
    EXECUTE format('CREATE POLICY admin_all ON public.%I FOR ALL USING (EXISTS (SELECT 1 FROM public.profiles WHERE id=auth.uid() AND role IN (''admin'',''super_admin'',''staff'')))', t);
  END IF;
END LOOP; END $$;

-- ── 20260626000012_bookkeeping_course_dedup.sql ──
-- Merge duplicate bookkeeping courses into single canonical course.
--
-- Two courses existed for program bd503ebf (Bookkeeping):
--   db7aac84 - "Bookkeeping & QuickBooks Certified User" (Jan 2026, exam lessons mistyped as lesson)
--   566e2ef7 - "Intuit QuickBooks Online Certified User + Intuit Certified Bookkeeping Professional" (Apr 2026, correct types)
--
-- Both had identical 5-module / 43-lesson structure. Zero lesson_progress rows on either.
-- Kept 566e2ef7 (more complete, correct lesson_type on exams).
-- Migrated 9 curriculum_lessons from old course to keeper, then deleted old course.

-- Migrate curriculum_lessons to keeper course
UPDATE public.curriculum_lessons
SET course_id = '566e2ef7-6861-4736-9807-b4ff868fc908'
WHERE program_id = 'bd503ebf-d8e1-4c79-9efe-a72c001589b4'
  AND course_id  = 'db7aac84-e261-4cee-aa6b-57a465e07a9c';

-- Delete old course content
DELETE FROM public.course_lessons
WHERE module_id IN (
  SELECT id FROM public.course_modules
  WHERE course_id = 'db7aac84-e261-4cee-aa6b-57a465e07a9c'
);

DELETE FROM public.course_modules
WHERE course_id = 'db7aac84-e261-4cee-aa6b-57a465e07a9c';

DELETE FROM public.courses
WHERE id = 'db7aac84-e261-4cee-aa6b-57a465e07a9c';

-- ── 20260626000013_missing_views.sql ──
-- Create missing views referenced by admin pages
-- All views are SECURITY DEFINER so RLS on underlying tables still applies

-- 1. admin_applications_queue
-- Used by: app/admin/applications/[type]/[id]/page.tsx
DROP VIEW IF EXISTS public.admin_applications_queue CASCADE;
CREATE VIEW public.admin_applications_queue AS
SELECT
  a.id,
  a.id AS application_id,
  a.application_type,
  a.first_name,
  a.last_name,
  COALESCE(a.full_name, a.first_name || ' ' || a.last_name) AS full_name,
  a.email,
  a.phone,
  a.program_id,
  a.program_slug,
  a.status,
  a.eligibility_status,
  a.funding_status,
  a.funding_source,
  a.intake_stage,
  a.created_at,
  a.updated_at,
  a.submitted_at,
  a.reviewer_id,
  a.review_notes,
  a.reviewed_at,
  a.next_step,
  a.next_step_due_date,
  p.title AS program_title
FROM public.applications a
LEFT JOIN public.programs p ON p.id = a.program_id;

-- 2. enrollments (alias for program_enrollments)
-- Used by: app/admin/reports/charts/page.tsx
DROP VIEW IF EXISTS public.enrollments CASCADE;
CREATE VIEW public.enrollments AS
SELECT
  pe.id,
  pe.user_id,
  pe.student_id,
  pe.program_id,
  pe.enrollment_state AS status,
  pe.enrollment_state,
  pe.created_at,
  pe.updated_at,
  p.title AS program_name,
  p.slug AS program_slug
FROM public.program_enrollments pe
LEFT JOIN public.programs p ON p.id = pe.program_id;

-- 3. exam_authorization_queue
-- Used by: app/admin/exam-authorizations/page.tsx
DROP VIEW IF EXISTS public.exam_authorization_queue CASCADE;
CREATE VIEW public.exam_authorization_queue AS
SELECT
  efa.id,
  efa.learner_id,
  efa.program_id,
  efa.credential_id,
  efa.funding_source,
  efa.funding_status,
  efa.funded_amount_cents,
  efa.funding_notes,
  efa.funding_approved_by,
  efa.funding_approved_at,
  efa.created_at,
  efa.updated_at,
  pr.first_name,
  pr.last_name,
  pr.email,
  pg.title AS program_title,
  pg.slug AS program_slug
FROM public.exam_funding_authorizations efa
LEFT JOIN public.profiles pr ON pr.id = efa.learner_id
LEFT JOIN public.programs pg ON pg.id = efa.program_id;

-- 4. participant_report
-- Used by: app/admin/reports/wioa/page.tsx
DROP VIEW IF EXISTS public.participant_report CASCADE;
CREATE VIEW public.participant_report AS
SELECT
  pe.id,
  pe.user_id,
  pe.student_id,
  pe.program_id,
  pe.enrollment_state AS enrollment_status,
  pe.enrollment_state,
  pe.created_at AS applied_at,
  pe.created_at,
  pe.updated_at,
  pr.first_name,
  pr.last_name,
  pr.email,
  pr.phone,
  pg.title AS program_title,
  pg.slug AS program_slug,
  pg.title AS program_category
FROM public.program_enrollments pe
LEFT JOIN public.profiles pr ON pr.id = COALESCE(pe.user_id, pe.student_id)
LEFT JOIN public.programs pg ON pg.id = pe.program_id;

-- 5. referral_pipeline_summary
-- Used by: app/admin/referrals/page.tsx
DROP VIEW IF EXISTS public.referral_pipeline_summary CASCADE;
CREATE VIEW public.referral_pipeline_summary AS
SELECT
  wr.id,
  wr.user_id,
  wr.application_id,
  wr.enrollment_id,
  wr.agency_name,
  wr.agency_type,
  wr.case_manager_name,
  wr.case_manager_email,
  wr.case_manager_phone,
  COALESCE(wr.participant_name, wr.applicant_name) AS participant_name,
  COALESCE(wr.participant_email, wr.applicant_email) AS participant_email,
  wr.funding_type,
  wr.voucher_number,
  wr.funding_amount,
  wr.funding_approved,
  wr.funding_approved_at,
  wr.status,
  wr.referral_date,
  wr.archived,
  wr.notes,
  wr.created_at,
  wr.updated_at,
  a.program_id,
  a.program_slug,
  p.title AS program_title
FROM public.workforce_referrals wr
LEFT JOIN public.applications a ON a.id = wr.application_id
LEFT JOIN public.programs p ON p.id = a.program_id;

-- 6. shop_required_docs_status
-- Used by: app/admin/shops/page.tsx
DROP VIEW IF EXISTS public.shop_required_docs_status CASCADE;
CREATE VIEW public.shop_required_docs_status AS
SELECT
  sa.id,
  sa.shop_name,
  sa.status,
  sa.created_at,
  -- Derive required/approved from agreement fields
  3 AS required,
  (CASE WHEN sa.agree_supervision THEN 1 ELSE 0 END +
   CASE WHEN sa.agree_reporting THEN 1 ELSE 0 END +
   CASE WHEN sa.agree_wages THEN 1 ELSE 0 END) AS approved,
  sa.agree_supervision,
  sa.agree_reporting,
  sa.agree_wages,
  -- shop_id for joining
  NULL::uuid AS shop_id
FROM public.shop_applications sa
UNION ALL
SELECT
  s.id,
  s.name AS shop_name,
  CASE WHEN s.active THEN 'active' ELSE 'inactive' END AS status,
  s.created_at,
  3 AS required,
  3 AS approved,
  true AS agree_supervision,
  true AS agree_reporting,
  true AS agree_wages,
  s.id AS shop_id
FROM public.shops s;

-- 7. v_admin_financial_assurance_summary
-- Used by: app/admin/compliance/financial-assurance/page.tsx
DROP VIEW IF EXISTS public.v_admin_financial_assurance_summary CASCADE;
CREATE VIEW public.v_admin_financial_assurance_summary AS
SELECT
  COUNT(*) AS total_records,
  COUNT(*) FILTER (WHERE status = 'active') AS active_count,
  COUNT(*) FILTER (WHERE status = 'expired') AS expired_count,
  COUNT(*) FILTER (WHERE status = 'expiring_soon' OR (
    expiration_date IS NOT NULL AND
    expiration_date <= (CURRENT_DATE + INTERVAL '90 days') AND
    expiration_date > CURRENT_DATE
  )) AS expiring_soon_count,
  COALESCE(SUM(coverage_amount) FILTER (WHERE status = 'active'), 0) AS total_active_coverage,
  MAX(updated_at) AS last_updated
FROM public.financial_assurance_records;

-- 8. v_funding_verification_queue
-- Used by: app/admin/funding-verification/page.tsx
DROP VIEW IF EXISTS public.v_funding_verification_queue CASCADE;
CREATE VIEW public.v_funding_verification_queue AS
SELECT
  pe.id,
  pe.user_id,
  pe.student_id,
  pe.program_id,
  pe.enrollment_state,
  pe.funding_source,
  pe.created_at,
  pe.updated_at,
  pr.first_name,
  pr.last_name,
  pr.email,
  pg.title AS program_title,
  pg.slug AS program_slug,
  pif.id AS flag_id,
  pif.flag_type,
  pif.flag_reason,
  pif.flagged_at,
  pif.sla_days,
  pif.sla_escalated_at,
  -- SLA priority: escalated first, then by age
  CASE
    WHEN pif.sla_escalated_at IS NOT NULL THEN 1
    WHEN pe.created_at < NOW() - INTERVAL '7 days' THEN 2
    ELSE 3
  END AS sla_priority
FROM public.program_enrollments pe
LEFT JOIN public.profiles pr ON pr.id = COALESCE(pe.user_id, pe.student_id)
LEFT JOIN public.programs pg ON pg.id = pe.program_id
LEFT JOIN public.payment_integrity_flags pif
  ON pif.entity_id = pe.id
  AND pif.entity_type = 'enrollment'
  AND pif.resolved_at IS NULL
WHERE pe.enrollment_state IN ('pending_funding_verification', 'pending_payment', 'funding_review')
   OR pif.id IS NOT NULL
ORDER BY sla_priority, pe.created_at ASC;

-- ── 20260627000001_program_state_engine.sql ──
-- Program State Engine
-- Adds enrollment_state, capacity, and provider ref columns to programs.
-- enrollment_state drives CTA behavior and API gating across the platform.

ALTER TABLE public.programs
  ADD COLUMN IF NOT EXISTS enrollment_state       text NOT NULL DEFAULT 'open'
    CHECK (enrollment_state IN ('open', 'waitlist', 'closed')),
  ADD COLUMN IF NOT EXISTS total_seats            int,
  ADD COLUMN IF NOT EXISTS seats_available        int,
  ADD COLUMN IF NOT EXISTS next_cohort_date       date,
  ADD COLUMN IF NOT EXISTS waitlist_enabled       boolean NOT NULL DEFAULT false,
  ADD COLUMN IF NOT EXISTS internal_provider_ref  text;  -- admin-only, never exposed in UI

-- CNA is intentionally waitlisted
UPDATE public.programs
  SET enrollment_state = 'waitlist',
      waitlist_enabled = true
  WHERE slug = 'cna';

-- CDL provider reference (internal only — never surfaced in UI or public API)
UPDATE public.programs
  SET internal_provider_ref = 'cdl-provider-001'
  WHERE slug = 'cdl-training';

CREATE INDEX IF NOT EXISTS idx_programs_enrollment_state
  ON public.programs(enrollment_state);

-- RLS: internal_provider_ref is readable only by service_role (admin)
-- Public/authenticated reads via REST API will not expose this column
-- because the column is not in any public view or anon-accessible query.
COMMENT ON COLUMN public.programs.internal_provider_ref IS
  'Internal provider reference — admin-only. Never expose in public UI or API responses.';

-- ── 20260627000002_waitlist_priority.sql ──
-- Waitlist Priority Queue
-- Adds priority_tag, cohort_id, and rank to the waitlist table.
-- priority_tag drives ordering: wioa > employer > self_pay > unknown

ALTER TABLE public.waitlist
  ADD COLUMN IF NOT EXISTS priority_tag  text
    CHECK (priority_tag IN ('wioa', 'employer', 'self_pay', 'unknown')),
  ADD COLUMN IF NOT EXISTS cohort_id     uuid REFERENCES public.cohorts(id) ON DELETE SET NULL,
  ADD COLUMN IF NOT EXISTS rank          int;

-- Backfill priority_tag from existing funding_interest values
UPDATE public.waitlist
  SET priority_tag = funding_interest
  WHERE funding_interest IN ('wioa', 'employer', 'self_pay');

UPDATE public.waitlist
  SET priority_tag = 'unknown'
  WHERE priority_tag IS NULL;

CREATE INDEX IF NOT EXISTS idx_waitlist_program_priority
  ON public.waitlist(program_slug, priority_tag, created_at);

-- ── 20260627000003_cdl_enrollment_tracking.sql ──
-- CDL enrollment tracking columns
-- Adds training dates and provider notification audit trail.
-- provider_notified_at proves Elevate recorded the student before provider contact.

ALTER TABLE public.program_enrollments
  ADD COLUMN IF NOT EXISTS training_start_date   date,
  ADD COLUMN IF NOT EXISTS training_end_date     date,
  ADD COLUMN IF NOT EXISTS provider_notified_at  timestamptz,
  ADD COLUMN IF NOT EXISTS provider_notified_by  uuid REFERENCES auth.users(id) ON DELETE SET NULL;

COMMENT ON COLUMN public.program_enrollments.provider_notified_at IS
  'Timestamp when Elevate notified the training provider. Always set AFTER enrollment is recorded here — proves Elevate owns the student record.';

COMMENT ON COLUMN public.program_enrollments.provider_notified_by IS
  'Admin user who triggered provider notification.';

-- ── 20260627000004_cdl_payout_view.sql ──
-- CDL enrollment control view (admin-only)
-- Joins enrollment + payout + provider ref + student info.
-- Accessible only to service_role — never exposed via public API.

DROP VIEW IF EXISTS public.v_cdl_enrollment_control CASCADE;

CREATE VIEW public.v_cdl_enrollment_control AS
SELECT
  pe.id                       AS enrollment_id,
  pe.user_id,
  pe.program_slug,
  pe.status                   AS enrollment_status,
  pe.funding_source,
  pe.payout_status,
  pe.payout_amount,
  pe.payout_due_date,
  pe.payout_paid_date,
  pe.training_start_date,
  pe.training_end_date,
  pe.provider_notified_at,
  pe.provider_notified_by,
  p.internal_provider_ref,
  pr.full_name                AS student_name,
  pr.email                    AS student_email,
  pr.phone                    AS student_phone,
  -- Placement data from applications (source of truth for outcomes)
  a.placement_employer,
  a.placement_job_title,
  a.placement_hourly_wage,
  a.placed_at
FROM public.program_enrollments pe
JOIN public.programs p ON p.slug = pe.program_slug
LEFT JOIN public.profiles pr ON pr.id = pe.user_id
LEFT JOIN public.applications a ON a.user_id = pe.user_id
  AND a.program_interest = 'cdl-training'
WHERE pe.program_slug = 'cdl-training';

-- Restrict to service_role only — internal_provider_ref must never reach public clients
REVOKE ALL ON public.v_cdl_enrollment_control FROM anon, authenticated;
GRANT SELECT ON public.v_cdl_enrollment_control TO service_role;

-- ── 20260627000005_leads_qualification_path.sql ──
-- Add qualification_path to leads so funnel path (A/B/C) is queryable,
-- not just buried in a notes text field.
ALTER TABLE public.leads
  ADD COLUMN IF NOT EXISTS qualification_path TEXT CHECK (qualification_path IN ('A', 'B', 'C')),
  ADD COLUMN IF NOT EXISTS qualifier_unemployed TEXT,
  ADD COLUMN IF NOT EXISTS qualifier_indiana TEXT,
  ADD COLUMN IF NOT EXISTS qualifier_wants_cert TEXT;

CREATE INDEX IF NOT EXISTS idx_leads_qualification_path ON public.leads (qualification_path);
CREATE INDEX IF NOT EXISTS idx_leads_source ON public.leads (source);

-- ── 20260627000006_audit_fixes.sql ──
-- Audit fixes: 4 missing tables + partners RLS tightening
-- Generated from supabase-deep-audit.mjs results 2026-06-27

-- ─── 1. compliance_flags ─────────────────────────────────────────────────────
-- Referenced by admin compliance pages. Stores per-record compliance flag events.
CREATE TABLE IF NOT EXISTS public.compliance_flags (
  id            uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  entity_type   text NOT NULL,           -- 'enrollment' | 'application' | 'partner' etc.
  entity_id     uuid NOT NULL,
  flag_type     text NOT NULL,           -- 'missing_docs' | 'overdue' | 'policy_violation' etc.
  severity      text NOT NULL DEFAULT 'medium', -- 'low' | 'medium' | 'high' | 'critical'
  description   text,
  resolved      boolean NOT NULL DEFAULT false,
  resolved_at   timestamptz,
  resolved_by   uuid REFERENCES public.profiles(id),
  created_by    uuid REFERENCES public.profiles(id),
  created_at    timestamptz NOT NULL DEFAULT now(),
  updated_at    timestamptz NOT NULL DEFAULT now()
);

ALTER TABLE public.compliance_flags ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "compliance_flags_admin" ON public.compliance_flags;
CREATE POLICY "compliance_flags_admin" ON public.compliance_flags
  FOR ALL USING (
    EXISTS (
      SELECT 1 FROM public.profiles
      WHERE id = auth.uid()
      AND role IN ('admin', 'super_admin', 'staff', 'org_admin')
    )
  );

CREATE INDEX IF NOT EXISTS compliance_flags_entity_idx ON public.compliance_flags(entity_type, entity_id);
CREATE INDEX IF NOT EXISTS compliance_flags_resolved_idx ON public.compliance_flags(resolved);

-- ─── 2. wioa_exports ─────────────────────────────────────────────────────────
-- The admin WIOA PIRL export route queries 'wioa-exports' (hyphenated).
-- Create the canonical snake_case table and a view alias for the hyphenated name.
CREATE TABLE IF NOT EXISTS public.wioa_exports (
  id              uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  export_type     text NOT NULL DEFAULT 'pirl',
  status          text NOT NULL DEFAULT 'pending', -- 'pending' | 'processing' | 'complete' | 'failed'
  file_url        text,
  record_count    integer DEFAULT 0,
  period_start    date,
  period_end      date,
  exported_by     uuid REFERENCES public.profiles(id),
  error_message   text,
  metadata        jsonb DEFAULT '{}',
  created_at      timestamptz NOT NULL DEFAULT now(),
  updated_at      timestamptz NOT NULL DEFAULT now()
);

ALTER TABLE public.wioa_exports ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "wioa_exports_admin" ON public.wioa_exports;
CREATE POLICY "wioa_exports_admin" ON public.wioa_exports
  FOR ALL USING (
    EXISTS (
      SELECT 1 FROM public.profiles
      WHERE id = auth.uid()
      AND role IN ('admin', 'super_admin', 'staff', 'org_admin')
    )
  );

CREATE INDEX IF NOT EXISTS wioa_exports_status_idx ON public.wioa_exports(status);
CREATE INDEX IF NOT EXISTS wioa_exports_created_idx ON public.wioa_exports(created_at DESC);

-- ─── 3. payroll_records ──────────────────────────────────────────────────────
-- Referenced by admin payroll pages. Stores individual payroll record lines.
CREATE TABLE IF NOT EXISTS public.payroll_records (
  id              uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  payroll_run_id  uuid REFERENCES public.payroll_runs(id) ON DELETE CASCADE,
  employee_id     uuid REFERENCES public.profiles(id),
  employee_name   text,
  pay_period_start date,
  pay_period_end   date,
  -- 'amount' is the canonical pay amount — queried by get-kpis.ts (.select('status, amount'))
  amount          numeric(10,2) DEFAULT 0,
  net_pay         numeric(10,2) DEFAULT 0,
  deductions      numeric(10,2) DEFAULT 0,
  hours_worked    numeric(8,2) DEFAULT 0,
  pay_type        text DEFAULT 'hourly', -- 'hourly' | 'salary' | 'stipend'
  status          text DEFAULT 'draft',  -- 'draft' | 'approved' | 'paid'
  notes           text,
  metadata        jsonb DEFAULT '{}',
  created_at      timestamptz NOT NULL DEFAULT now(),
  updated_at      timestamptz NOT NULL DEFAULT now()
);

ALTER TABLE public.payroll_records ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "payroll_records_admin" ON public.payroll_records;
CREATE POLICY "payroll_records_admin" ON public.payroll_records
  FOR ALL USING (
    EXISTS (
      SELECT 1 FROM public.profiles
      WHERE id = auth.uid()
      AND role IN ('admin', 'super_admin', 'staff', 'org_admin')
    )
  );

CREATE INDEX IF NOT EXISTS payroll_records_run_idx ON public.payroll_records(payroll_run_id);
CREATE INDEX IF NOT EXISTS payroll_records_employee_idx ON public.payroll_records(employee_id);

-- ─── 4. Fix partners RLS — tighten open SELECT policy ────────────────────────
-- Current state: "partners_select" uses USING (true) — fully public.
-- Public pages only need active partners. Internal fields (contact info,
-- banking, notes) should not be readable by anonymous users.
-- Fix: restrict anon reads to is_active = true rows only.

DROP POLICY IF EXISTS "partners_select" ON public.partners;

-- Public can only see active partners (for /courses/partners, program pages etc.)
DROP POLICY IF EXISTS "partners_public_select" ON public.partners;
CREATE POLICY "partners_public_select" ON public.partners
  FOR SELECT
  USING (is_active = true);

-- Authenticated admin/staff can see all partners
DROP POLICY IF EXISTS "partners_admin_select" ON public.partners;
CREATE POLICY "partners_admin_select" ON public.partners
  FOR SELECT
  USING (
    auth.uid() IS NOT NULL AND
    EXISTS (
      SELECT 1 FROM public.profiles
      WHERE id = auth.uid()
      AND role IN ('admin', 'super_admin', 'staff', 'org_admin', 'instructor')
    )
  );

