-- ── 20260627000008_fix_stuck_onboarding.sql ──
-- Fix stuck onboarding for enrolled students
-- These users have active program_enrollments but onboarding_completed=false
-- because they never hit /api/onboarding/complete after enrollment was created.
--
-- Jordan White (Jbwhite888@icloud.com) — active enrollment, payment succeeded, 17d stuck
-- Bryan Long (fabisbabs1988@gmail.com) — active enrollment, 17d stuck
--
-- The other 4 (natataroa, rodybanegas, fletcheraustin98, sallenjohn) have
-- enrollment_status='pending' — they need admin to send onboarding email first,
-- not a direct flag flip. Only flip the ones with enrollment_status='active'.

UPDATE public.profiles
SET
  onboarding_completed = true,
  onboarding_completed_at = now(),
  updated_at = now()
WHERE email IN (
  'Jbwhite888@icloud.com',
  'fabisbabs1988@gmail.com'
)
AND onboarding_completed = false
AND enrollment_status = 'active';

-- Also ensure their program_enrollments reflect active state
UPDATE public.program_enrollments
SET
  enrollment_state = 'active',
  status = 'active',
  updated_at = now()
WHERE user_id IN (
  SELECT id FROM public.profiles
  WHERE email IN ('Jbwhite888@icloud.com', 'fabisbabs1988@gmail.com')
)
AND enrollment_state != 'active';

-- For the 4 with enrollment_status='pending' — update their enrollment to onboarding
-- so the admin dashboard shows them correctly and can send the onboarding email
UPDATE public.program_enrollments
SET
  status = 'onboarding',
  enrollment_state = 'onboarding',
  updated_at = now()
WHERE user_id IN (
  SELECT id FROM public.profiles
  WHERE email IN (
    'natataroa@gmail.com',
    'rodybanegas@yahoo.com',
    'fletcheraustin98@gmail.com',
    'sallenjohn@outlook.com'
  )
)
AND status NOT IN ('active', 'completed', 'revoked');

-- ── 20260627000009_flag_stuck_funding.sql ──
-- Flag 11 enrollments stuck in pending_funding_verification for >14 days
-- These need admin to either verify funding or contact the student.
-- Sets next_required_action and funding_verification_due_at so the
-- admin dashboard funding queue surfaces them.

UPDATE public.program_enrollments
SET
  next_required_action = 'funding_verification_overdue',
  funding_verification_due_at = now(),
  updated_at = now()
WHERE
  status = 'pending_funding_verification'
  AND created_at < now() - interval '14 days'
  AND (next_required_action IS NULL OR next_required_action != 'funding_verification_overdue');

-- Also update the applications table so the admin queue shows them
UPDATE public.applications
SET
  next_step = 'Funding verification overdue — contact student or WorkOne',
  next_step_due_date = now()::date,
  updated_at = now()
WHERE
  user_id IN (
    SELECT user_id FROM public.program_enrollments
    WHERE status = 'pending_funding_verification'
    AND created_at < now() - interval '14 days'
  )
  AND (next_step IS NULL OR next_step NOT LIKE '%overdue%');

-- ── 20260627000010_fix_natalia_enrollment_state.sql ──
-- Fix Natalia Roa's enrollment state
-- She was approved and an enrollment row was created, but her Stripe checkout
-- session expired without payment. Reset to payment_required so she is routed
-- to the payment flow on next login. 'pending' is not a valid enrollment_state
-- per the CHECK constraint — payment_required is the correct value.

UPDATE public.program_enrollments
SET
  enrollment_state      = 'payment_required',
  next_required_action  = 'PAYMENT',
  payment_status        = 'pending',
  stripe_checkout_session_id = NULL,  -- clear expired session
  updated_at            = now()
WHERE id = '6ad966f1-f8fd-457f-9f5e-5391072f9f29'
  AND user_id = '2d761d18-6ff9-4355-b9dd-5ff55903906b';

-- Also clear the expired session from the application row
UPDATE public.applications
SET
  stripe_session_id     = NULL,
  payment_status        = 'pending',
  updated_at            = now()
WHERE id = 'c4b48167-7780-4ea5-9c3c-53afa5c2cf1b'
  AND user_id = '2d761d18-6ff9-4355-b9dd-5ff55903906b';

