-- ── 20260628000003_fix_applications_rls.sql ──
-- Fix applications table RLS policy conflict that causes mirror failures.
--
-- Root cause: multiple overlapping RESTRICTIVE policies on `public.applications`
-- (applications_admin_all, applications_own_read, users_own, "Users can view own
-- applications") apply to the `authenticated` and `public` roles. When the
-- service_role client calls .insert().select('id'), Supabase executes the INSERT
-- then a SELECT to return the new row. If the service_role JWT is evaluated
-- against any RESTRICTIVE SELECT policy that requires user_id = auth.uid() (which
-- is NULL for service_role), the SELECT returns 0 rows — the insert succeeds but
-- .maybeSingle() returns null, producing the intake-${Date.now()} fallback ID.
--
-- Fix: drop all conflicting policies and replace with a clean, non-overlapping set:
--   1. service_role → unrestricted ALL (bypasses RLS entirely in practice, but
--      explicit policy ensures no RESTRICTIVE policy can interfere)
--   2. admin/staff  → ALL via is_admin() check
--   3. authenticated user → SELECT own rows only
--   4. public/anon  → INSERT only (intake form submissions)

-- ── Drop every existing policy on public.applications ────────────────────────
DO $$ DECLARE r RECORD; BEGIN
  FOR r IN SELECT policyname FROM pg_policies WHERE schemaname='public' AND tablename='applications'
  LOOP
    EXECUTE format('DROP POLICY IF EXISTS %I ON public.applications', r.policyname);
  END LOOP;
END $$;

-- ── Re-enable RLS (idempotent) ───────────────────────────────────────────────
ALTER TABLE public.applications ENABLE ROW LEVEL SECURITY;

-- ── 1. Service role: full access, no restrictions ────────────────────────────
-- Explicit policy so RESTRICTIVE policies on other roles cannot bleed through.
CREATE POLICY "service_role_all"
  ON public.applications
  AS PERMISSIVE
  FOR ALL
  TO service_role
  USING (true)
  WITH CHECK (true);

-- ── 2. Admins and staff: full access ─────────────────────────────────────────
CREATE POLICY "admin_all"
  ON public.applications
  AS PERMISSIVE
  FOR ALL
  TO authenticated
  USING (
    EXISTS (
      SELECT 1 FROM public.profiles
      WHERE id = auth.uid()
        AND role IN ('admin', 'super_admin', 'staff', 'org_admin')
    )
  )
  WITH CHECK (
    EXISTS (
      SELECT 1 FROM public.profiles
      WHERE id = auth.uid()
        AND role IN ('admin', 'super_admin', 'staff', 'org_admin')
    )
  );

-- ── 3. Authenticated users: read own applications ────────────────────────────
CREATE POLICY "user_read_own"
  ON public.applications
  AS PERMISSIVE
  FOR SELECT
  TO authenticated
  USING (
    user_id = auth.uid()
    OR email = (SELECT email FROM public.profiles WHERE id = auth.uid())
  );

-- ── 4. Public / anon: insert only (intake form, apply form) ──────────────────
-- Email format check prevents junk submissions.
CREATE POLICY "public_insert"
  ON public.applications
  AS PERMISSIVE
  FOR INSERT
  TO anon, authenticated
  WITH CHECK (
    email IS NOT NULL
    AND length(email) <= 255
    AND email ~* '^[A-Za-z0-9._%+\-]+@[A-Za-z0-9.\-]+\.[A-Za-z]{2,}$'
  );

-- ── 20260629000001_performance_indexes.sql ──
-- 20260629000001_performance_indexes.sql
-- 9 indexes for admin dashboard query paths that were doing full-table scans.
-- NOTE: CONCURRENTLY removed (exec_sql runs in implicit transaction).
--       Re-apply manually with CONCURRENTLY via Supabase Dashboard if write-lock duration is a concern.
-- All are so they build without locking writes.

-- program_enrollments: revenue queries filter by payment_status
CREATE INDEX IF NOT EXISTS idx_pe_payment_status
  ON public.program_enrollments (payment_status);

CREATE INDEX IF NOT EXISTS idx_pe_payment_status_created
  ON public.program_enrollments (payment_status, created_at);

-- program_enrollments: enrollment trend and active-count queries filter by created_at
CREATE INDEX IF NOT EXISTS idx_pe_created_at
  ON public.program_enrollments (created_at);

-- program_enrollments: active-state + created_at (used by last-month delta)
CREATE INDEX IF NOT EXISTS idx_pe_state_created
  ON public.program_enrollments (enrollment_state, created_at);

-- program_enrollments: partial index for active-only lookups (inactive learner scan)
CREATE INDEX IF NOT EXISTS idx_pe_state_user
  ON public.program_enrollments (enrollment_state, user_id)
  WHERE enrollment_state = 'active';

-- leads: stale-leads filter on updated_at had no index
CREATE INDEX IF NOT EXISTS idx_leads_updated_at
  ON public.leads (updated_at);

-- enrollment_funding_records: participant_report LATERAL join
CREATE INDEX IF NOT EXISTS idx_efr_enrollment_created
  ON public.enrollment_funding_records (enrollment_id, created_at);

-- placement_records: participant_report LATERAL join
CREATE INDEX IF NOT EXISTS idx_placement_learner_start
  ON public.placement_records (learner_id, start_date);

-- program_completion_certificates: participant_report LATERAL join
CREATE INDEX IF NOT EXISTS idx_pcc_user_program
  ON public.program_completion_certificates (user_id, program_id);

-- applications: stalled-applications query (partial — only non-terminal statuses)
CREATE INDEX IF NOT EXISTS idx_applications_status_created
  ON public.applications (status, created_at)
  WHERE status NOT IN ('approved', 'rejected', 'enrolled', 'withdrawn');

-- ── 20260629000002_revenue_rpc.sql ──
-- 20260629000002_revenue_rpc.sql
-- admin_revenue_summary(month_start, last_month_start, last_month_end)
--
-- Replaces 3 separate SELECT amount_paid_cents queries that transferred all
-- paid enrollment rows to the JS process for summing. This does the
-- aggregation in Postgres and returns a single row with three totals.
--
-- Returns exactly one row. If no paid enrollments exist, all values are 0.

CREATE OR REPLACE FUNCTION public.admin_revenue_summary(
  month_start      timestamptz,
  last_month_start timestamptz,
  last_month_end   timestamptz
)
RETURNS TABLE (
  all_time_cents      bigint,
  this_month_cents    bigint,
  last_month_cents    bigint
)
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT
    COALESCE(SUM(amount_paid_cents), 0)::bigint                                                        AS all_time_cents,
    COALESCE(SUM(amount_paid_cents) FILTER (WHERE created_at >= month_start), 0)::bigint               AS this_month_cents,
    COALESCE(SUM(amount_paid_cents) FILTER (WHERE created_at >= last_month_start
                                              AND created_at <  last_month_end), 0)::bigint            AS last_month_cents
  FROM public.program_enrollments
  WHERE payment_status IN ('paid', 'completed', 'setup_fee_paid');
$$;

-- Grant execute to the service role used by the admin dashboard
GRANT EXECUTE ON FUNCTION public.admin_revenue_summary(timestamptz, timestamptz, timestamptz)
  TO service_role;

-- ── 20260629000003_inactive_learners_rpc.sql ──
-- 20260629000003_inactive_learners_rpc.sql
-- admin_inactive_learners(inactive_days, limit)
--
-- Replaces a 4-query chain:
--   1. fetch active enrollments (up to 100 rows)
--   2. fetch recent lesson_progress per user
--   3. fetch profiles for inactive user_ids
--   4. fetch program names for inactive program_ids
--
-- This single JOIN does all four steps server-side and returns only the
-- rows the dashboard needs, fully enriched.
--
-- inactive_days: learners with no lesson_progress.updated_at in this many days
-- limit_n:       max rows to return (dashboard uses 20)

CREATE OR REPLACE FUNCTION public.admin_inactive_learners(
  inactive_days int     DEFAULT 3,
  limit_n       int     DEFAULT 20
)
RETURNS TABLE (
  enrollment_id  uuid,
  user_id        uuid,
  program_id     uuid,
  enrolled_at    timestamptz,
  full_name      text,
  email          text,
  program_title  text,
  last_activity  timestamptz
)
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT
    pe.id                                          AS enrollment_id,
    pe.user_id,
    pe.program_id,
    pe.enrolled_at,
    COALESCE(p.full_name, p.first_name || ' ' || p.last_name, p.email) AS full_name,
    p.email,
    COALESCE(prog.title, prog.name, pe.program_id::text)               AS program_title,
    MAX(lp.updated_at)                             AS last_activity
  FROM public.program_enrollments pe
  LEFT JOIN public.profiles        p    ON p.id    = pe.user_id
  LEFT JOIN public.programs        prog ON prog.id = pe.program_id
  LEFT JOIN public.lesson_progress lp   ON lp.user_id = pe.user_id
  WHERE pe.enrollment_state = 'active'
    AND pe.user_id IS NOT NULL
  GROUP BY pe.id, pe.user_id, pe.program_id, pe.enrolled_at,
           p.full_name, p.first_name, p.last_name, p.email,
           prog.title, prog.name
  HAVING MAX(lp.updated_at) IS NULL
      OR MAX(lp.updated_at) < NOW() - (inactive_days || ' days')::interval
  ORDER BY last_activity ASC NULLS FIRST
  LIMIT limit_n;
$$;

GRANT EXECUTE ON FUNCTION public.admin_inactive_learners(int, int)
  TO service_role;

-- ── 20260629000004_cleanup_intake_timestamp_ids.sql ──
-- 20260629000004_cleanup_intake_timestamp_ids.sql
--
-- Convert legacy applications rows whose id starts with 'intake-' to proper UUIDs.
-- These were created by an old version of /api/intake/route.ts that used
-- `intake-${Date.now()}` as a fallback ID. The bug is fixed — new rows always
-- get UUID ids. But existing rows need their id column updated so the admin
-- review page can load them.
--
-- Strategy: assign gen_random_uuid() to each legacy row, preserving all data.
-- The old intake-{timestamp} id is stored in metadata->>'legacy_id' for tracing.

-- Step 1: preview what will be converted
-- SELECT id, email, program_interest, created_at
-- FROM public.applications
-- WHERE id LIKE 'intake-%'
-- ORDER BY created_at DESC;

-- Step 2: convert ids to real UUIDs, stash old id in metadata.
-- Safety: canonical schema uses UUID ids, which cannot contain intake-* values.
-- Only execute this update when applications.id is text/varchar in a drifted env.
DO $$
DECLARE
  id_data_type text;
BEGIN
  SELECT c.data_type
    INTO id_data_type
  FROM information_schema.columns c
  WHERE c.table_schema = 'public'
    AND c.table_name = 'applications'
    AND c.column_name = 'id';

  IF id_data_type IN ('text', 'character varying') THEN
    EXECUTE $sql$
      UPDATE public.applications
      SET
        id = gen_random_uuid()::text,
        metadata = COALESCE(metadata, '{}'::jsonb) || jsonb_build_object('legacy_id', id)
      WHERE id LIKE 'intake-%'
    $sql$;
    RAISE NOTICE 'Converted legacy intake-* IDs in text/varchar applications.id';
  ELSE
    RAISE NOTICE 'Skipped intake-* cleanup: applications.id is %, not text/varchar', COALESCE(id_data_type, 'unknown');
  END IF;
END $$;

-- Verify (for text/varchar id environments): should return 0 rows after running
-- SELECT id FROM public.applications WHERE id LIKE 'intake-%';

-- ── 20260629000005_applications_zip_default.sql ──
-- Safety net: prevent application inserts from failing when zip is omitted
-- (some legacy/public intake paths may not provide zip consistently)

UPDATE public.applications
SET zip = '00000'
WHERE zip IS NULL OR btrim(zip) = '';

ALTER TABLE public.applications
ALTER COLUMN zip SET DEFAULT '00000';

-- ── 20260629000006_compliance_items_columns.sql ──
-- Add missing columns to compliance_items so the admin compliance dashboard
-- can group by category, display titles, and show last-reviewed dates.
-- The API orders by category + title and the ComplianceItemsPanel groups by category.

ALTER TABLE public.compliance_items
  ADD COLUMN IF NOT EXISTS title           text,
  ADD COLUMN IF NOT EXISTS category        text DEFAULT 'General',
  ADD COLUMN IF NOT EXISTS last_reviewed_at timestamptz,
  ADD COLUMN IF NOT EXISTS assigned_to     uuid REFERENCES public.profiles(id) ON DELETE SET NULL,
  ADD COLUMN IF NOT EXISTS due_date        date;

-- Back-fill title from name for any existing rows
UPDATE public.compliance_items
SET title = name
WHERE title IS NULL AND name IS NOT NULL;

